  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company has two Virtual Cloud Networks (VCNs) in the same OCI region and wants resources in each VCN to communicate with each other using private IP addresses without traffic traversing the public internet. Which OCI feature enables this connectivity?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Oracle Cloud Infrastructure Compute service allows you to run applications without provisioning or managing underlying virtual machines by automatically scaling resources based on demand?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"OCI Container Instances"},{"id":"b","text":"OCI Functions"},{"id":"c","text":"OCI Dedicated VM Host"},{"id":"d","text":"OCI Bare Metal Compute"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$OCI Functions is a serverless platform that lets developers run code without provisioning or managing any underlying infrastructure. It automatically scales based on demand, and you only pay for the resources consumed during execution. OCI Container Instances run containers but still require you to define resource shapes. Dedicated VM Host provides single-tenant physical servers for VMs. Bare Metal Compute provisions physical servers that require management.$patch$, $patch$Compute$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Functions/Concepts/functionsoverview.htm","label":"OCI Functions Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
