INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When creating a Virtual Machine (VM) instance in Oracle Cloud Infrastructure, which component defines the number of OCPUs, amount of memory, and other hardware characteristics of the instance?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Compartment"},{"id":"b","text":"Availability Domain"},{"id":"c","text":"Shape"},{"id":"d","text":"Image"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A Shape in OCI defines the number of OCPUs, the amount of memory, network bandwidth, and other resources allocated to a Compute instance. A Compartment is a logical grouping for organizing and isolating cloud resources. An Availability Domain is a physical data center location within a region. An Image is the template that contains the operating system and software used to boot the instance.$patch$, $patch$Compute$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/References/computeshapes.htm","label":"OCI Compute Shapes"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
