INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Oracle Cloud Infrastructure, what is the purpose of a Custom Image?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It is used to define the network topology for a Compute instance."},{"id":"b","text":"It allows you to capture the boot disk of an existing instance so you can launch new instances with the same configuration and software."},{"id":"c","text":"It is a pre-built Oracle database template that includes the OCI SDK."},{"id":"d","text":"It provides a snapshot of all block volumes attached to a running instance."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Custom Image in OCI lets you capture the boot disk of an existing Compute instance, preserving the installed OS, configurations, and software. This custom image can then be used to launch new instances that replicate that environment. It does not define network topology (that is handled by VCNs and subnets), is not specific to database templates, and does not snapshot attached block volumes separately.$patch$, $patch$Compute$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Tasks/managingcustomimages.htm","label":"Managing Custom Images"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Oracle Cloud Infrastructure, what is the purpose of a Custom Image?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which OCI Compute option provides single-tenant, physical servers dedicated exclusively to a single customer, offering greater control over hardware and meeting strict compliance requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Virtual Machine Standard Shapes"},{"id":"b","text":"Preemptible Instances"},{"id":"c","text":"Bare Metal Instances"},{"id":"d","text":"Burstable Instances"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Bare Metal Instances in OCI give you direct access to a physical server without a hypervisor layer, providing single-tenant isolation, high performance, and the ability to meet strict regulatory or compliance requirements. Virtual Machine Standard Shapes run on shared physical hardware managed by Oracle. Preemptible Instances are low-cost VMs that can be reclaimed at any time. Burstable Instances are VMs that can temporarily exceed their baseline OCPU utilization.$patch$, $patch$Compute$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Concepts/computeoverview.htm","label":"OCI Bare Metal Compute Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which OCI Compute option provides single-tenant, physical servers dedicated exclusively to a single customer, offering greater control over hardware and meeting strict compliance requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator needs to run a script automatically every time a new OCI Compute instance is launched to install software and apply configurations. Which feature should the administrator use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Instance Metadata Service (IMDS)"},{"id":"b","text":"Cloud-Init / Cloud Guard"},{"id":"c","text":"Cloud-Init User Data (Startup Script)"},{"id":"d","text":"OCI Bastion Service"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Cloud-Init User Data (also referred to as a startup script or cloud-init script) allows administrators to provide a script that runs automatically when a Compute instance first boots. This is the standard mechanism for bootstrapping instance configuration. The Instance Metadata Service (IMDS) provides instance metadata to applications running on the instance but does not execute setup scripts. Cloud Guard is a security monitoring service, not a bootstrapping tool. OCI Bastion provides secure, audited access to private resources and is unrelated to instance startup automation.$patch$, $patch$Compute$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Tasks/gettingdatafrominstance.htm","label":"Providing User Data to Instances (Cloud-Init)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator needs to run a script automatically every time a new OCI Compute instance is launched to install software and apply configurations. Which feature should the administrator use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer needs to store unstructured data such as images, videos, and log files in Oracle Cloud Infrastructure. The data must be accessible via REST APIs and must support virtually unlimited storage capacity. Which OCI storage service is the BEST fit for this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Block Volume"},{"id":"b","text":"Object Storage"},{"id":"c","text":"File Storage Service"},{"id":"d","text":"Local NVMe SSD"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$OCI Object Storage is designed specifically for storing unstructured data (images, videos, backups, logs) at virtually unlimited scale. It exposes a REST-based API (S3-compatible and native OCI API) and is accessible from anywhere over the internet or within OCI. Block Volume is a block-level storage device that must be attached to a compute instance and is not accessible via REST APIs directly. File Storage Service provides a hierarchical NFS-based file system, not REST object access. Local NVMe SSD is ephemeral storage physically attached to certain bare-metal and VM shapes and cannot be used as a standalone, REST-accessible store.$patch$, $patch$Storage$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Object/Concepts/objectstorageoverview.htm","label":"OCI Object Storage Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer needs to store unstructured data such as images, videos, and log files in Oracle Cloud Infrastructure. The data must be accessible via REST APIs and must support virtually unlimited storage capacity. Which OCI storage service is the BEST fit for this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Oracle Cloud Infrastructure Object Storage, which storage tier is optimized for data that is accessed frequently and requires low latency retrieval?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Archive tier"},{"id":"b","text":"Infrequent Access tier"},{"id":"c","text":"Standard tier"},{"id":"d","text":"Cold tier"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The Standard tier (also called Hot tier) in OCI Object Storage is designed for data that requires fast, frequent access with no retrieval delays or minimum storage duration requirements. The Archive tier is optimized for rarely accessed data that can tolerate long retrieval times (typically hours) and has a minimum storage period of 90 days. The Infrequent Access tier is for data that is accessed less frequently but still requires millisecond access; it has a minimum storage duration of 31 days and per-retrieval charges. 'Cold tier' is not a valid OCI Object Storage tier name.$patch$, $patch$Storage$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Object/Concepts/understandingstoragetiers.htm","label":"OCI Object Storage Tiers"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Oracle Cloud Infrastructure Object Storage, which storage tier is optimized for data that is accessed frequently and requires low latency retrieval?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator attaches an OCI Block Volume to a Linux compute instance. Before the operating system can use the volume to store data, what step must be performed on the instance?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable the volume's Paravirtualized attachment in the OCI Console"},{"id":"b","text":"Partition, format, and mount the volume within the operating system"},{"id":"c","text":"Create an Object Storage bucket and link it to the Block Volume"},{"id":"d","text":"Reboot the compute instance so OCI automatically formats the volume"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$After attaching a Block Volume to a Linux compute instance, the volume appears as a raw block device inside the OS. An administrator must partition the device (e.g., using fdisk or parted), create a filesystem (e.g., mkfs.ext4), and mount it to a directory before it can be used to store data. Enabling Paravirtualized attachment is done before or during attachment in the Console and relates to the attachment type, not OS-level readiness. Block Volumes and Object Storage buckets are separate, independent services and are not linked in this way. OCI does not automatically format a volume on reboot.$patch$, $patch$Storage$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Block/Tasks/connectingtoavolume.htm","label":"Connecting to a Block Volume — OCI Documentation"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator attaches an OCI Block Volume to a Linux compute instance. Before the operating system can use the volume to store data, what step must be performed on the instance?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which OCI storage service provides a fully managed, scalable NFS (Network File System) solution that allows multiple compute instances to access the same file system concurrently?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Block Volume"},{"id":"b","text":"Object Storage"},{"id":"c","text":"File Storage Service"},{"id":"d","text":"Archive Storage"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$OCI File Storage Service (FSS) is a fully managed, elastic, NFS-based file system that can be mounted simultaneously by many compute instances, making it ideal for shared workloads such as content management, analytics, and HPC. Block Volume is a block-level service that can only be attached to one instance at a time in read/write mode (multi-attach in read-only mode is limited). Object Storage uses HTTP/REST, not NFS, and does not provide a mountable file system natively. Archive Storage is a tier within Object Storage designed for long-term, low-cost archival and does not provide NFS access.$patch$, $patch$Storage$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/File/Concepts/filestorageoverview.htm","label":"OCI File Storage Service Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which OCI storage service provides a fully managed, scalable NFS (Network File System) solution that allows multiple compute instances to access the same file system concurrently?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An organization stores large amounts of compliance data in OCI Object Storage that must be retained for several years but is almost never accessed. They want to minimize storage costs as much as possible. Which Object Storage tier should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Standard tier"},{"id":"b","text":"Infrequent Access tier"},{"id":"c","text":"Archive tier"},{"id":"d","text":"Premium tier"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The Archive tier provides the lowest storage cost in OCI Object Storage and is specifically designed for data that is rarely or never accessed, such as long-term compliance records, audit logs, and historical backups. The trade-off is that objects must be restored before they can be read, and there is a minimum retention period of 90 days. The Standard tier is the most expensive because it is optimized for frequent, low-latency access — unsuitable for rarely accessed data when cost minimization is the priority. The Infrequent Access tier offers a mid-range cost but is intended for data accessed occasionally, not data that is almost never accessed. 'Premium tier' is not a valid OCI Object Storage tier.$patch$, $patch$Storage$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Archive/Concepts/archivestorageoverview.htm","label":"OCI Archive Storage Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An organization stores large amounts of compliance data in OCI Object Storage that must be retained for several years but is almost never accessed. They want to minimize storage costs as much as possible. Which Object Storage tier should they use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Oracle Cloud Infrastructure service provides a centralized, fully managed security information and event management (SIEM) capability that ingests logs from OCI services and helps detect threats?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"OCI Vault"},{"id":"b","text":"OCI Cloud Guard"},{"id":"c","text":"OCI Security Zones"},{"id":"d","text":"OCI Bastion"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$OCI Cloud Guard is Oracle's native security posture management service that continuously monitors OCI resources, detects misconfigurations and suspicious activity, and can automatically remediate issues. It acts as a centralized security monitoring hub. OCI Vault is a key and secret management service. Security Zones enforce security policies on compartments but do not perform threat detection. OCI Bastion provides secure, time-limited SSH access to private resources but is not a threat-detection service.$patch$, $patch$Security and Observability$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/cloud-guard/using/part-start.htm","label":"OCI Cloud Guard Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Oracle Cloud Infrastructure service provides a centralized, fully managed security information and event management (SIEM) capability that ingests logs from OCI services and helps detect threats?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer needs to store and manage application secrets, such as database passwords, so they are never stored in plain text within code. Which OCI service is specifically designed for this purpose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"OCI Object Storage"},{"id":"b","text":"OCI Identity and Access Management (IAM)"},{"id":"c","text":"OCI Vault"},{"id":"d","text":"OCI Logging"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$OCI Vault is a managed service for creating and controlling encryption keys and storing secrets such as passwords, certificates, and API keys. Applications can retrieve secrets at runtime via API, eliminating the need to embed credentials in code. OCI Object Storage is a data storage service, not a secrets manager. IAM manages user identities and policies, not application secrets. OCI Logging collects and queries log data.$patch$, $patch$Security and Observability$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/KeyManagement/Tasks/managingsecrets.htm","label":"OCI Vault – Managing Secrets"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer needs to store and manage application secrets, such as database passwords, so they are never stored in plain text within code. Which OCI service is specifically designed for this purpose?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which OCI Observability service would you use to collect, search, and analyze log data emitted by OCI resources such as VCNs, Object Storage buckets, and Compute instances?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"OCI Monitoring"},{"id":"b","text":"OCI Events"},{"id":"c","text":"OCI Logging"},{"id":"d","text":"OCI Notifications"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$OCI Logging is the service designed to ingest, store, and query log data from OCI services (service logs), custom applications (custom logs), and audit activity (audit logs). OCI Monitoring collects numeric metrics such as CPU utilization and emits alarms based on thresholds. OCI Events reacts to state changes in OCI resources and triggers actions; it does not store logs. OCI Notifications sends alerts to subscribers via email, SMS, or HTTPS but does not collect log data.$patch$, $patch$Security and Observability$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Logging/Concepts/loggingoverview.htm","label":"OCI Logging Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which OCI Observability service would you use to collect, search, and analyze log data emitted by OCI resources such as VCNs, Object Storage buckets, and Compute instances?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An OCI administrator wants to receive an email alert whenever CPU utilization on a Compute instance exceeds 85% for more than five minutes. Which combination of OCI services should the administrator use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"OCI Logging and OCI Events"},{"id":"b","text":"OCI Monitoring and OCI Notifications"},{"id":"c","text":"OCI Cloud Guard and OCI Vault"},{"id":"d","text":"OCI Audit and OCI Bastion"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$OCI Monitoring collects metric data (including CPU utilization) from OCI resources and allows you to define alarm rules based on metric thresholds and evaluation windows. When an alarm fires, it publishes to an OCI Notifications topic, which can send messages to subscribers via email, SMS, PagerDuty, Slack, or HTTPS. OCI Logging and Events handle log data and resource state-change triggers, not metric-based threshold alerts. Cloud Guard and Vault address security posture and secret management. OCI Audit records API calls and Bastion provides SSH access — neither handles metric alerting.$patch$, $patch$Security and Observability$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Monitoring/Tasks/managingalarms.htm","label":"OCI Monitoring – Creating Alarms"},{"url":"https://docs.oracle.com/en-us/iaas/Content/Notification/Concepts/notificationoverview.htm","label":"OCI Notifications Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An OCI administrator wants to receive an email alert whenever CPU utilization on a Compute instance exceeds 85% for more than five minutes. Which combination of OCI services should the administrator use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which OCI feature automatically records all API calls made to OCI services — including who made the call, the source IP address, and the time — for compliance and forensic investigation purposes?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"OCI Service Connector Hub"},{"id":"b","text":"OCI Audit"},{"id":"c","text":"OCI Vulnerability Scanning"},{"id":"d","text":"OCI Security Advisor"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$OCI Audit automatically logs every API call to OCI services and stores those audit events, capturing the principal (user or service), source IP, timestamp, request parameters, and response. This data is essential for compliance audits and security forensics. OCI Service Connector Hub moves data between OCI services (e.g., Logging to Object Storage) but does not record API calls itself. OCI Vulnerability Scanning checks Compute instances and container images for known vulnerabilities. OCI Security Advisor provides guided workflows to improve security posture but is not an API call logging service.$patch$, $patch$Security and Observability$patch$,
         2, $json$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Audit/Concepts/auditoverview.htm","label":"OCI Audit Service Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '1Z0-1085-25'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which OCI feature automatically records all API calls made to OCI services — including who made the call, the source IP address, and the time — for compliance and forensic investigation purposes?$patch$);

-- PMLE-P1: 23 questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization wants to build a document processing pipeline that automatically classifies incoming contracts by type and extracts key fields such as party names, effective dates, and payment terms — all without writing custom model training code. The solution must integrate natively with BigQuery for downstream analytics. Which Google Cloud service combination best satisfies these requirements with the least amount of custom ML code?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Train a custom AutoML Text Classification model in Vertex AI, then deploy it behind a Vertex AI Endpoint and write a Cloud Function to parse entity fields using regex before loading results into BigQuery."},{"id":"b","text":"Use Document AI with a specialized processor (e.g., Contract Document AI processor) for entity extraction and classification, then stream the structured output into BigQuery using a Dataflow pipeline."},{"id":"c","text":"Use Cloud Vision API OCR to extract raw text, then fine-tune a BERT model on Vertex AI Workbench using custom training code, and export predictions to BigQuery via a scheduled query."},{"id":"d","text":"Configure a BigQuery ML TRANSFORM pipeline to ingest raw PDF bytes, apply a pre-trained text embedding model, and cluster documents using K-means inside BigQuery."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Document AI provides purpose-built processors — including specialized contract processors — that perform both document classification and entity extraction without requiring custom model training code, fulfilling the low-code requirement. Dataflow offers a managed, serverless integration path directly into BigQuery for downstream analytics. Option A requires custom training code and manual regex parsing, violating the low-code constraint. Option C requires fine-tuning a BERT model, which is high-code and high-effort. Option D misuses BigQuery ML; BQML cannot ingest raw PDF bytes and K-means clustering does not provide field-level extraction.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/document-ai/docs/overview","label":"Document AI overview – Google Cloud"},{"url":"https://cloud.google.com/document-ai/docs/processors-list#specialized_processors","label":"Document AI contract processor"},{"url":"https://cloud.google.com/dataflow/docs/guides/templates/provided-streaming#running-the-pubsub-to-bigquery-template","label":"Dataflow to BigQuery pipeline templates"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization wants to build a document processing pipeline that automatically classifies incoming contracts by type and extracts key fields such as party names, effective dates, and payment terms — all without writing custom model training code. The solution must integrate natively with BigQuery for downstream analytics. Which Google Cloud service combination best satisfies these requirements with the least amount of custom ML code?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A retail company needs to add real-time product recommendations to their e-commerce website within two weeks. The data science team has limited ML engineering resources and wants to avoid building and maintaining a custom collaborative filtering model. Their user event data (views, clicks, purchases) is already being streamed into Google Analytics 4 and exported to BigQuery. Which Google Cloud approach delivers personalized recommendations with the lowest operational overhead and minimal custom ML code?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use Vertex AI Matching Engine to build an approximate nearest-neighbor index from BigQuery user embeddings generated by a custom TensorFlow two-tower model trained on Vertex AI Training."},{"id":"b","text":"Use Recommendations AI (part of Retail API), import the existing user event data and product catalog from BigQuery, train a recommendation model through the console or API, and serve results via the Retail API predict endpoint."},{"id":"c","text":"Deploy a pre-built Apache Spark ALS collaborative filtering job on Dataproc, schedule it nightly with Cloud Composer, and write recommendations to Firestore for low-latency serving."},{"id":"d","text":"Use BigQuery ML to train a matrix factorization model with BQML, export the resulting user and item factor tables to Cloud Bigtable, and build a custom lookup microservice in Cloud Run."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Recommendations AI (Google Cloud Retail API) is a fully managed, low-code solution purpose-built for product recommendation use cases. It accepts user events and product catalog data, handles model training internally, and exposes a predict endpoint — all without requiring custom ML code. It integrates directly with BigQuery data exports and meets the two-week timeline. Option A requires building and training a custom TensorFlow two-tower model, which is high-code and time-intensive. Option C requires managing a Dataproc cluster, writing Spark code, and setting up Cloud Composer — high operational overhead. Option D requires training a BQML model, exporting factor tables, and building a custom serving microservice — several manual engineering steps that increase complexity and time-to-value.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/retail/docs/overview","label":"Recommendations AI overview – Google Cloud Retail API"},{"url":"https://cloud.google.com/retail/docs/import-user-events","label":"Importing user events into Retail API from BigQuery"},{"url":"https://cloud.google.com/retail/docs/get-predictions","label":"Retail API predict method"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A retail company needs to add real-time product recommendations to their e-commerce website within two weeks. The data science team has limited ML engineering resources and wants to avoid building and maintaining a custom collaborative filtering model. Their user event data (views, clicks, purchases) is already being streamed into Google Analytics 4 and exported to BigQuery. Which Google Cloud approach delivers personalized recommendations with the lowest operational overhead and minimal custom ML code?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A financial services firm wants to detect anomalous transactions in near-real-time to flag potential fraud. Their security team has no ML expertise and must configure the solution primarily through the Google Cloud console and configuration files rather than writing training code. Transaction records land in a BigQuery table within seconds of processing. They require explainability outputs for every flagged transaction to satisfy internal audit requirements. Which solution best meets all stated constraints?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use Vertex AI Tabular Workflows with a custom XGBoost training script, enable Vertex Explainable AI, and schedule batch prediction jobs against the BigQuery transaction table every 5 minutes."},{"id":"b","text":"Use Vertex AI AutoML Tabular to train a fraud-detection classification model on historical labeled transaction data, enable feature attributions via Vertex Explainable AI, and deploy the model to a Vertex AI Endpoint invoked by a BigQuery continuous query or scheduled job."},{"id":"c","text":"Use the Cloud Natural Language API sentiment analysis endpoint to score transaction descriptions and threshold on the returned sentiment magnitude as a proxy for anomaly likelihood."},{"id":"d","text":"Use Vertex AI Workbench to author a custom anomaly detection notebook with an Isolation Forest algorithm, containerize the training logic, and deploy via Cloud Run with a direct BigQuery read on each request."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI AutoML Tabular allows teams with no ML coding expertise to train high-quality classification models via the Google Cloud console by simply pointing to a BigQuery dataset of labeled transactions. It natively integrates with Vertex Explainable AI to produce feature attribution scores per prediction, satisfying the audit explainability requirement. The trained model can be deployed to a Vertex AI Endpoint and invoked via a scheduled or streaming mechanism from BigQuery. Option A requires writing a custom XGBoost training script, violating the no-code constraint. Option C misapplies a text sentiment API to tabular financial data — it cannot detect transaction anomalies reliably. Option D requires authoring custom notebook code, containerization, and a custom serving microservice — all high-code activities that exceed the team's stated skills.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/tabular-data/classification-regression/overview","label":"AutoML Tabular training overview – Vertex AI"},{"url":"https://cloud.google.com/vertex-ai/docs/explainable-ai/overview","label":"Vertex Explainable AI overview"},{"url":"https://cloud.google.com/vertex-ai/docs/tabular-data/classification-regression/get-online-predictions","label":"Get online predictions from AutoML Tabular models"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A financial services firm wants to detect anomalous transactions in near-real-time to flag potential fraud. Their security team has no ML expertise and must configure the solution primarily through the Google Cloud console and configuration files rather than writing training code. Transaction records land in a BigQuery table within seconds of processing. They require explainability outputs for every flagged transaction to satisfy internal audit requirements. Which solution best meets all stated constraints?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A media company's content team wants to automatically generate short descriptive captions for thousands of newly uploaded images each day, then store the captions alongside metadata in Firestore for use by their CMS. They have no in-house ML model development capability and need the pipeline operational within one sprint (two weeks). Image files are uploaded to a Cloud Storage bucket as the trigger event. Which architecture satisfies the requirements with the least custom ML development effort?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Fine-tune a vision-language model on Vertex AI using a custom PyTorch training container, deploy it to a Vertex AI Endpoint, and trigger inference via an Eventarc rule on the Cloud Storage bucket that invokes a Cloud Run service calling the endpoint."},{"id":"b","text":"Use the Cloud Vision API (label detection and object localization) to extract structured labels for each uploaded image, then use a Cloud Function triggered by the Cloud Storage finalize event to assemble a descriptive caption string from the labels and write it to Firestore."},{"id":"c","text":"Use Vertex AI Vision (AutoML Image Classification) to label each image, export label predictions to BigQuery, and run a scheduled BigQuery SQL transformation nightly to concatenate labels into captions stored back in Firestore."},{"id":"d","text":"Configure a Vertex AI Pipelines DAG that reads images from Cloud Storage, calls the Cloud Vision API, passes labels to the Vertex AI PaLM text generation API (Gemini) to generate natural-language captions, and writes results to Firestore — triggered by an Eventarc Cloud Storage event."}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$The optimal low-code solution leverages two pre-built Google Cloud AI APIs — Cloud Vision API for structured image understanding and Vertex AI Gemini (PaLM) text generation API for producing fluent natural-language captions — chained together in a Vertex AI Pipeline triggered by an Eventarc event on Cloud Storage object finalization. No custom model training is required; both APIs are consumed as managed services. Results are written directly to Firestore. This satisfies the no-ML-development constraint, the two-week timeline, and the end-to-end automation requirement. Option A requires fine-tuning a custom vision-language model — significant ML engineering effort. Option B uses only label concatenation rather than natural-language caption generation, producing low-quality captions that are not truly descriptive sentences. Option C introduces unnecessary latency via nightly batch BigQuery transformations and still produces label-concatenated rather than fluent captions; AutoML Image Classification also requires a training data labeling phase that exceeds the sprint timeline.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vision/docs/features-list","label":"Cloud Vision API documentation"},{"url":"https://cloud.google.com/vertex-ai/generative-ai/docs/text/text-overview","label":"Vertex AI Gemini API – text generation"},{"url":"https://cloud.google.com/eventarc/docs/run/create-trigger-storage-console","label":"Eventarc triggers for Cloud Storage – Google Cloud"},{"url":"https://cloud.google.com/vertex-ai/docs/pipelines/introduction","label":"Vertex AI Pipelines overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A media company's content team wants to automatically generate short descriptive captions for thousands of newly uploaded images each day, then store the captions alongside metadata in Firestore for use by their CMS. They have no in-house ML model development capability and need the pipeline operational within one sprint (two weeks). Image files are uploaded to a Cloud Storage bucket as the trigger event. Which architecture satisfies the requirements with the least custom ML development effort?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization has a centralized ML platform team and several business-unit data science teams. The business units need to share curated feature datasets with each other while maintaining strict data governance, versioning, and discoverability. Which Google Cloud service is the most appropriate foundation for implementing this shared feature management strategy?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Feature Store, using entity types and features with online and offline serving layers accessible across projects via IAM-controlled resource sharing"},{"id":"b","text":"BigQuery authorized views, where each team creates views over their own tables and grants cross-project SELECT permissions to other teams"},{"id":"c","text":"Cloud Storage buckets with uniform bucket-level access, storing Parquet files and sharing them via signed URLs between teams"},{"id":"d","text":"Dataproc Metastore with a shared Apache Hive catalog, allowing all teams to register and query feature tables using HiveQL"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI Feature Store is purpose-built for ML feature management across teams. It provides versioned, discoverable, and consistently served features for both training (offline) and inference (online), with fine-grained IAM access controls that allow cross-project sharing without duplicating data. BigQuery authorized views (b) can share data but lack ML-specific metadata, feature versioning, point-in-time correctness, and online serving needed by ML workflows. Cloud Storage with signed URLs (c) offers no governance, versioning, or discovery capabilities. Dataproc Metastore (d) is a metadata service for Spark/Hive workloads and is not designed for ML feature lifecycle management or low-latency online feature serving.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/overview","label":"Vertex AI Feature Store Overview"},{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/access-control","label":"Sharing features across projects with Vertex AI Feature Store"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization has a centralized ML platform team and several business-unit data science teams. The business units need to share curated feature datasets with each other while maintaining strict data governance, versioning, and discoverability. Which Google Cloud service is the most appropriate foundation for implementing this shared feature management strategy?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning engineer at a financial services firm needs to track every experiment run by multiple data science teams, compare hyperparameter configurations, and link each registered model artifact back to the exact dataset version and code commit used to produce it. The solution must integrate natively with Vertex AI Pipelines. Which combination of Google Cloud capabilities best satisfies these requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Experiments for run tracking and hyperparameter logging, combined with Vertex ML Metadata to record artifact lineage and dataset/code provenance, all surfaced in Vertex AI Model Registry"},{"id":"b","text":"MLflow Tracking Server deployed on Cloud Run, with model artifacts stored in Cloud Storage and lineage tracked using custom metadata tags on GCS objects"},{"id":"c","text":"BigQuery ML experiment tables to log metrics, Cloud Source Repositories for code versioning, and Cloud Storage for model artifacts with manual naming conventions to link artifacts to experiments"},{"id":"d","text":"Kubeflow Pipelines on GKE with a standalone MinIO artifact store and a self-managed MySQL metadata backend separate from Vertex AI"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI Experiments natively tracks runs, metrics, and hyperparameters across teams; Vertex ML Metadata automatically records artifact lineage (datasets, models, evaluation metrics) and links them to pipeline executions, satisfying the provenance requirement. Vertex AI Model Registry then provides a governed catalog where models are versioned and traceable. This entire stack integrates seamlessly with Vertex AI Pipelines. MLflow on Cloud Run (b) can track experiments but requires significant custom integration work and does not natively integrate with Vertex AI Pipelines lineage. BigQuery ML tables with manual naming (c) lack automatic lineage, making traceability error-prone and operationally fragile. Self-managed Kubeflow on GKE (d) replicates functionality already available in Vertex AI and introduces unnecessary operational overhead while breaking native Vertex AI integration.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/experiments/intro-vertex-ai-experiments","label":"Vertex AI Experiments documentation"},{"url":"https://cloud.google.com/vertex-ai/docs/ml-metadata/introduction","label":"Vertex ML Metadata overview"},{"url":"https://cloud.google.com/vertex-ai/docs/model-registry/introduction","label":"Vertex AI Model Registry"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning engineer at a financial services firm needs to track every experiment run by multiple data science teams, compare hyperparameter configurations, and link each registered model artifact back to the exact dataset version and code commit used to produce it. The solution must integrate natively with Vertex AI Pipelines. Which combination of Google Cloud capabilities best satisfies these requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Two geographically distributed data science teams are collaborating on a sensitive customer churn prediction model. Team A owns raw PII-containing training data in a BigQuery dataset in project-A; Team B must train models in project-B without ever gaining direct access to the underlying PII records. Regulatory requirements mandate that all data access be auditable. Which approach best meets these constraints on Google Cloud?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use BigQuery authorized views in project-A that expose only non-PII derived features; grant Team B's service account access to the authorized views only, and enable BigQuery Data Access audit logs in both projects"},{"id":"b","text":"Export the BigQuery dataset to a Cloud Storage bucket in project-A, apply bucket-level IAM to grant Team B read access, and rely on Cloud Storage access logs for auditability"},{"id":"c","text":"Create a Dataflow pipeline that streams transformed, de-identified records from project-A into a new BigQuery dataset in project-B nightly, then delete the project-B dataset after each training job"},{"id":"d","text":"Use VPC Service Controls to create a shared perimeter containing both projects, then grant Team B's developers direct BigQuery Data Viewer roles on the project-A dataset within the perimeter"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$BigQuery authorized views are the canonical Google Cloud pattern for sharing query results across projects without exposing the underlying tables. By constructing views that select only non-PII derived features, Team A retains full ownership and control of raw data while Team B can train models on the view output. Enabling BigQuery Data Access audit logs in Cloud Audit Logs satisfies the regulatory auditability requirement in a native, tamper-evident way. Exporting to Cloud Storage (b) creates a data copy outside BigQuery governance, exposes raw records, and Storage access logs are less granular than BigQuery audit logs. A nightly Dataflow pipeline (c) still materializes PII data into project-B before deletion, violating the constraint against direct PII access and introducing a window of exposure. VPC Service Controls (d) controls network-level data exfiltration but granting Data Viewer on the raw dataset still gives Team B access to PII records, which is explicitly prohibited.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/bigquery/docs/authorized-views","label":"BigQuery authorized views – share datasets across projects"},{"url":"https://cloud.google.com/bigquery/docs/reference/auditlogs","label":"BigQuery Data Access audit logging"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Two geographically distributed data science teams are collaborating on a sensitive customer churn prediction model. Team A owns raw PII-containing training data in a BigQuery dataset in project-A; Team B must train models in project-B without ever gaining direct access to the underlying PII records. Regulatory requirements mandate that all data access be auditable. Which approach best meets these constraints on Google Cloud?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An organization uses Vertex AI Pipelines to automate model retraining across three teams. After a recent incident, leadership requires that every model promoted to production be traceable to an approved pipeline run, that promotion events be reviewed by a second team before deployment, and that all historical approvals be preserved for compliance audits. Which combination of Google Cloud services and Vertex AI capabilities best addresses these requirements with the least custom development?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Record pipeline run IDs and artifact URIs in Vertex ML Metadata; use Vertex AI Model Registry with model version aliases and labels to capture approval state; enforce a mandatory peer-review step via a Cloud Tasks queue that gates the Vertex AI Endpoint deployment step in the pipeline"},{"id":"b","text":"Store pipeline run logs in Cloud Logging; use a Cloud Storage object naming convention to indicate approval status; have the second team rename the file to 'approved' before a Cloud Function triggers deployment"},{"id":"c","text":"Use Vertex AI Experiments to log pipeline run metadata; deploy all model versions to a staging Vertex AI Endpoint automatically; require the second team to manually call the Vertex AI REST API to swap traffic to the production endpoint, with approvals tracked in a Google Sheet"},{"id":"d","text":"Integrate the Vertex AI pipeline with a Cloud Build trigger; add a manual approval step in the Cloud Build pipeline that emails the second team; record approvals in a Firestore document for audit purposes"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Cloud Build supports first-class manual approval gates that pause execution, notify reviewers, and require explicit human sign-off before proceeding — this directly satisfies the peer-review requirement with minimal custom code. Cloud Build execution history is immutable and stored persistently, satisfying audit retention. Integrating Vertex AI Pipelines with Cloud Build (e.g., triggered via Cloud Build or calling Vertex AI APIs as build steps) is a well-documented pattern. Recording approval decisions in Firestore provides a queryable, durable audit trail. Option (a) is functionally reasonable but Cloud Tasks is a general-purpose queue not designed as a human approval gate, requiring significant custom orchestration to implement review workflows. Option (b) relies on fragile file-naming conventions and a Cloud Function trigger, providing no reliable audit trail or review workflow. Option (c) uses a Google Sheet for approvals, which provides no access control, audit immutability, or integration with automated deployment gating — it is unsuitable for compliance purposes.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/build/docs/securing-builds/gate-builds-on-approval","label":"Cloud Build manual approvals"},{"url":"https://cloud.google.com/vertex-ai/docs/model-registry/introduction","label":"Vertex AI Model Registry – model versioning and aliases"},{"url":"https://cloud.google.com/vertex-ai/docs/ml-metadata/introduction","label":"Vertex ML Metadata – tracking pipeline artifacts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An organization uses Vertex AI Pipelines to automate model retraining across three teams. After a recent incident, leadership requires that every model promoted to production be traceable to an approved pipeline run, that promotion events be reviewed by a second team before deployment, and that all historical approvals be preserved for compliance audits. Which combination of Google Cloud services and Vertex AI capabilities best addresses these requirements with the least custom development?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team has developed a TensorFlow prototype model on a single VM using a 10 GB dataset. You need to scale training to a 5 TB dataset while minimizing code refactoring and training time. Which Google Cloud approach should you use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use tf.distribute.MirroredStrategy with a single high-memory Compute Engine instance and increase the disk size to accommodate the full dataset."},{"id":"b","text":"Refactor the training job to use Vertex AI custom training with tf.distribute.MultiWorkerMirroredStrategy and provision a multi-node cluster on Vertex AI Training."},{"id":"c","text":"Convert the model to scikit-learn and run it on a Dataproc cluster using PySpark ML for distributed training."},{"id":"d","text":"Export the prototype to BigQuery ML and retrain the model directly in BigQuery using the CREATE MODEL statement."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$tf.distribute.MultiWorkerMirroredStrategy enables synchronous data-parallel training across multiple workers, which is the standard approach for scaling TensorFlow workloads to large datasets with minimal code change. Vertex AI Training natively provisions and manages multi-node clusters, reducing infrastructure overhead. Option A is limited to one machine and cannot efficiently handle 5 TB. Option C requires a full framework rewrite. Option D only supports a narrow set of model types and is not equivalent to a general TensorFlow prototype.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/overview","label":"Vertex AI Custom Training Overview"},{"url":"https://www.tensorflow.org/guide/distributed_training#multiworkermirroredstrategy","label":"TensorFlow MultiWorkerMirroredStrategy"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team has developed a TensorFlow prototype model on a single VM using a 10 GB dataset. You need to scale training to a 5 TB dataset while minimizing code refactoring and training time. Which Google Cloud approach should you use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data scientist has trained a PyTorch image classification model in a local Jupyter notebook and wants to migrate it to Vertex AI for scalable, reproducible training with GPU acceleration. The team insists on maintaining experiment tracking. Which combination of steps best achieves this goal?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Package the training code as a Python source distribution, push the container image to Artifact Registry, submit a Vertex AI CustomJob referencing the container, and log metrics to Vertex AI Experiments."},{"id":"b","text":"Upload the Jupyter notebook directly to Vertex AI Workbench and run it as a scheduled notebook job, using print statements to track metrics."},{"id":"c","text":"Deploy the notebook as a Cloud Run service with GPU support and log metrics to Cloud Monitoring custom metrics."},{"id":"d","text":"Use AutoML Vision to retrain the classification model without migrating any custom PyTorch code, and rely on the built-in evaluation metrics."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Packaging training code in a container, storing it in Artifact Registry, and submitting a Vertex AI CustomJob is the recommended pattern for migrating custom framework models (such as PyTorch) to Vertex AI. Vertex AI Experiments provides native experiment tracking including metrics, parameters, and artifact lineage. Option B does not provide reproducible training at scale. Option C misuses Cloud Run, which is not designed for GPU-based ML training jobs. Option D abandons the custom PyTorch model entirely, which does not satisfy the requirement.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/containers-overview","label":"Vertex AI Custom Training with Custom Containers"},{"url":"https://cloud.google.com/vertex-ai/docs/experiments/intro-vertex-ai-experiments","label":"Vertex AI Experiments"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A data scientist has trained a PyTorch image classification model in a local Jupyter notebook and wants to migrate it to Vertex AI for scalable, reproducible training with GPU acceleration. The team insists on maintaining experiment tracking. Which combination of steps best achieves this goal?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You are scaling a recommendation model prototype to production. The training dataset stored in Cloud Storage grows by approximately 500 GB per week. To avoid repeatedly re-training from scratch and reduce compute costs, which training strategy should you implement on Vertex AI?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Full retraining on the complete accumulated dataset every week using a new Vertex AI CustomJob to ensure model consistency."},{"id":"b","text":"Implement warm-start (incremental) training by initializing each new training job from the previously saved model checkpoint stored in Cloud Storage, training only on the newly arrived data."},{"id":"c","text":"Use Vertex AI AutoML Tabular to automatically retrain the model weekly without any manual intervention or checkpoint management."},{"id":"d","text":"Switch the model to BigQuery ML and use the TRANSFORM clause to handle new weekly data without retraining."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Warm-start (incremental) training initializes the model from a previously saved checkpoint and trains on only the new data, significantly reducing compute time and cost as the dataset grows week over week. This is a well-established pattern for large-scale recommendation systems. Option A is expensive because the dataset grows cumulatively. Option C is incorrect because AutoML Tabular does not natively support warm-start checkpointing from a custom recommendation model. Option D is inappropriate because BigQuery ML's TRANSFORM clause is for feature transformation, not incremental retraining of recommendation models.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/checkpoints","label":"Vertex AI Training — Resuming Training from a Checkpoint"},{"url":"https://cloud.google.com/architecture/ml-on-gcp-best-practices#incrementally-train-models","label":"Best Practices for Incrementally Training ML Models"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You are scaling a recommendation model prototype to production. The training dataset stored in Cloud Storage grows by approximately 500 GB per week. To avoid repeatedly re-training from scratch and reduce compute costs, which training strategy should you implement on Vertex AI?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You need to scale hyperparameter tuning for a Keras model from a manual grid search on a local machine to an automated, parallelized process in Google Cloud. The tuning must explore hundreds of trials efficiently. Which Vertex AI capability should you use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Vizier, configured as a standalone black-box optimization service to suggest hyperparameter configurations, while running training jobs manually on separate VMs."},{"id":"b","text":"Vertex AI Hyperparameter Tuning, which uses Bayesian optimization to automatically run parallel training trials and identify optimal hyperparameter values within a single managed service."},{"id":"c","text":"Cloud Composer with a custom DAG that iterates over a predefined grid of hyperparameter values, submitting sequential Vertex AI training jobs for each combination."},{"id":"d","text":"Use Keras Tuner locally with a larger Compute Engine instance to parallelize the grid search across multiple CPU cores."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Hyperparameter Tuning is a fully managed service that uses Bayesian optimization (via Vertex AI Vizier under the hood) to efficiently explore the hyperparameter space across many parallel trials. It is directly integrated with Vertex AI CustomJob, minimizing infrastructure management. Option A is overly manual and does not provide the managed parallelism required. Option C uses sequential jobs via Cloud Composer, which is far less efficient than parallel Bayesian optimization. Option D does not scale beyond a single machine and does not leverage cloud-scale parallelism.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/hyperparameter-tuning-overview","label":"Vertex AI Hyperparameter Tuning Overview"},{"url":"https://cloud.google.com/vertex-ai/docs/vizier/overview","label":"Vertex AI Vizier"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You need to scale hyperparameter tuning for a Keras model from a manual grid search on a local machine to an automated, parallelized process in Google Cloud. The tuning must explore hundreds of trials efficiently. Which Vertex AI capability should you use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A team built a prototype NLP model using Hugging Face Transformers and wants to migrate it to Vertex AI Training. The model requires a custom training environment with specific library versions not available in Google's pre-built containers. What is the correct approach to package and submit this job?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use a Vertex AI pre-built PyTorch container and install additional libraries via a startup script specified in the CustomJob workerPoolSpecs."},{"id":"b","text":"Build a custom Docker image that includes all required library versions, push it to Artifact Registry, and reference it in the Vertex AI CustomJob workerPoolSpecs containerSpec."},{"id":"c","text":"Install the required libraries into a Cloud Storage bucket and configure the Vertex AI training job to mount the bucket at runtime as the Python package source."},{"id":"d","text":"Convert the Hugging Face model to a TensorFlow SavedModel and use a pre-built TensorFlow container that already supports the required dependency versions."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$When the required library versions are not available in Google's pre-built training containers, the recommended approach is to build a custom Docker image containing the exact environment, push it to Artifact Registry (or Container Registry), and reference it in the Vertex AI CustomJob's containerSpec. This ensures full reproducibility and portability. Option A is fragile because installing packages at startup can fail or introduce inconsistencies and increases job startup time. Option C is incorrect because Cloud Storage cannot serve as a Python package installation source at container runtime without additional tooling. Option D requires unnecessary framework conversion and may not support all Hugging Face features.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/containers-overview","label":"Vertex AI Custom Containers for Training"},{"url":"https://cloud.google.com/artifact-registry/docs/docker/store-docker-container-images","label":"Artifact Registry — Docker Repositories"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A team built a prototype NLP model using Hugging Face Transformers and wants to migrate it to Vertex AI Training. The model requires a custom training environment with specific library versions not available in Google's pre-built containers. What is the correct approach to package and submit this job?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team is scaling a prototype ML pipeline to production on Vertex AI. During scale-up testing, the distributed training job on a 16-worker TPU pod slice runs significantly slower than expected. Cloud Monitoring shows high host-to-device data transfer time. What is the most likely root cause and the recommended remediation?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The model architecture is too large for TPUs; the team should switch to GPU-based training with NVIDIA A100s to resolve the bottleneck."},{"id":"b","text":"The input pipeline is CPU-bound and not prefetching data efficiently; the team should optimize the tf.data pipeline using parallelized transformations, caching, and prefetch(tf.data.AUTOTUNE) to keep TPU devices saturated."},{"id":"c","text":"The TPU pod slice is undersized; the team should increase to a larger pod slice to provide more on-chip memory bandwidth."},{"id":"d","text":"Vertex AI does not support distributed training on TPU pod slices; the team should migrate to a Dataproc cluster with Spark ML for distributed computation."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$High host-to-device data transfer time in a distributed TPU training job almost always indicates that the input pipeline (CPU side) cannot feed data fast enough to keep the TPU cores busy, causing the TPU to stall waiting for data. The correct fix is to optimize the tf.data pipeline: use parallel map transformations, cache preprocessed data in memory or on disk, and use prefetch(tf.data.AUTOTUNE) so data preparation overlaps with device computation. Option A is incorrect because switching hardware does not resolve an input pipeline bottleneck. Option C is incorrect because the bottleneck is I/O, not on-chip memory. Option D is factually wrong; Vertex AI fully supports TPU pod slice training.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/train-with-tpus","label":"Vertex AI — Train with TPUs"},{"url":"https://www.tensorflow.org/guide/data_performance","label":"TensorFlow tf.data Performance Guide"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team is scaling a prototype ML pipeline to production on Vertex AI. During scale-up testing, the distributed training job on a 16-worker TPU pod slice runs significantly slower than expected. Cloud Monitoring shows high host-to-device data transfer time. What is the most likely root cause and the recommended remediation?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team has deployed a TensorFlow image-classification model on Vertex AI Prediction using an n1-standard-4 machine. During peak hours, average prediction latency spikes from 120 ms to over 2 seconds and several requests receive HTTP 429 errors. Traffic is highly variable throughout the day. Which combination of actions will BEST resolve the latency and error-rate problems while minimizing cost?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable autoscaling on the Vertex AI endpoint with a minimum of 1 replica and a maximum of 10 replicas, and set the target CPU utilization to 60%."},{"id":"b","text":"Redeploy the model on a single n1-highcpu-96 machine and disable autoscaling to guarantee capacity."},{"id":"c","text":"Switch to a Cloud Run deployment and manually scale replicas before expected traffic spikes using a cron job."},{"id":"d","text":"Move the model to BigQuery ML so that batch predictions absorb the traffic, and cache results in Memorystore."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI Prediction's autoscaling adjusts the number of serving replicas based on real-time traffic, directly addressing both the latency spike (too few replicas) and the HTTP 429 throttling errors (request queue overflow). Setting a minimum of 1 replica avoids cold-start delays during low-traffic periods, while the maximum of 10 replicas handles peak load. Targeting 60% CPU utilization gives enough headroom before a replica becomes saturated. Option B over-provisions a single large machine, wastes money at low traffic, and does not handle bursts beyond that machine's capacity. Option C requires manual intervention and cron-based scaling is reactive only to predicted—not actual—traffic. Option D converts an online serving problem into batch prediction, which fundamentally breaks the low-latency requirement.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/configure-compute#autoscaling","label":"Vertex AI – Configure autoscaling for online prediction"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/deploy-model-api","label":"Vertex AI – Deploy a model to an endpoint"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team has deployed a TensorFlow image-classification model on Vertex AI Prediction using an n1-standard-4 machine. During peak hours, average prediction latency spikes from 120 ms to over 2 seconds and several requests receive HTTP 429 errors. Traffic is highly variable throughout the day. Which combination of actions will BEST resolve the latency and error-rate problems while minimizing cost?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A recommendation engine is served via a Vertex AI online prediction endpoint backed by a custom TensorFlow SavedModel. The model artifact is 4 GB. The ML team reports that whenever a new model version is deployed with zero downtime, the first several hundred requests to the new model version have anomalously high latency. Subsequent requests return to normal latency. What is the MOST LIKELY cause, and which action should you take to fix it?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The TensorFlow XLA JIT compiler requires warm-up time; enable model warm-up by providing a SavedModel WarmupRequests file in the assets.extra directory."},{"id":"b","text":"Vertex AI caches model weights in Cloud Storage and the cache expires on each deployment; increase the Cloud Storage cache TTL."},{"id":"c","text":"The new replica has not yet registered with Cloud Load Balancing; add a longer readiness check interval in the endpoint configuration."},{"id":"d","text":"The 4 GB artifact exceeds Vertex AI's recommended size; convert the model to TFLite to reduce artifact size below 1 GB."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$TensorFlow models—especially those using SavedModel format—experience high first-request latency because the computation graph is not yet JIT-compiled and model weights have not been loaded into GPU/CPU cache. TensorFlow Serving (which underpins Vertex AI Prediction) supports a warm-up mechanism: placing a tf.serving.SavedModelWarmupRequests protobuf file in the assets.extra/tf_serving_warmup_requests path causes the server to replay those requests before marking the model ready for live traffic, effectively pre-compiling the graph and warming caches. Option B is incorrect—Cloud Storage cache TTL is not a configurable model-serving parameter in this context. Option C confuses load-balancer registration with model initialization; the readiness check already gates traffic. Option D misidentifies artifact size as the root cause; large artifacts are fully supported and TFLite targets edge/mobile, not server-side serving.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://www.tensorflow.org/tfx/serving/saved_model_warmup","label":"TensorFlow Serving – SavedModel Warmup"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/warm-up-model","label":"Vertex AI – Model warm-up for online prediction"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A recommendation engine is served via a Vertex AI online prediction endpoint backed by a custom TensorFlow SavedModel. The model artifact is 4 GB. The ML team reports that whenever a new model version is deployed with zero downtime, the first several hundred requests to the new model version have anomalously high latency. Subsequent requests return to normal latency. What is the MOST LIKELY cause, and which action should you take to fix it?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You operate a fraud-detection service that must return predictions within 50 ms (p99) and handle 50,000 requests per second at peak. The model is a 200 MB XGBoost binary. Your current Vertex AI endpoint uses n1-standard-8 CPU-only machines. Load tests show that a single replica saturates at around 8,000 RPS with p99 latency of 45 ms. The model does not use GPU-accelerated operations. Which infrastructure change gives the HIGHEST throughput-per-dollar for this workload?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Attach NVIDIA T4 GPUs to each replica to accelerate XGBoost inference."},{"id":"b","text":"Switch to n1-highcpu-16 machine type and increase the number of autoscaling replicas proportionally to reach 50,000 RPS."},{"id":"c","text":"Keep n1-standard-8 replicas but enable Vertex AI's dedicated endpoint and set minimum replicas to 7 to cover peak load without autoscaling delay."},{"id":"d","text":"Migrate the model to Vertex AI with a custom container running ONNX Runtime, deployed on c2-standard-8 (compute-optimized) machines, and autoscale to meet demand."}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$XGBoost inference is CPU-bound and benefits from high single-core performance and SIMD instruction throughput. Converting the model to ONNX format and running it with ONNX Runtime enables additional graph-level optimizations. C2 machines use Intel Cascade Lake processors with higher clock speeds and better instructions-per-cycle for numerical workloads compared to the general-purpose N1 series, delivering better throughput-per-dollar for this CPU-bound model. Pairing this with autoscaling handles variable load efficiently. Option A adds GPUs that provide no benefit to XGBoost (which does not use CUDA for inference in production serving), adding cost without improving latency. Option B increases CPU count but N1 general-purpose machines are less efficient per dollar than compute-optimized C2 for this use case. Option C sets a high fixed minimum that wastes money during off-peak hours and does not improve per-replica efficiency.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/compute/docs/compute-optimized-machines","label":"Google Cloud – Compute-optimized machine family (C2)"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/use-custom-container","label":"Vertex AI – Use custom containers for prediction"},{"url":"https://onnxruntime.ai/docs/performance/tune-performance/","label":"ONNX Runtime – Performance best practices"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You operate a fraud-detection service that must return predictions within 50 ms (p99) and handle 50,000 requests per second at peak. The model is a 200 MB XGBoost binary. Your current Vertex AI endpoint uses n1-standard-8 CPU-only machines. Load tests show that a single replica saturates at around 8,000 RPS with p99 latency of 45 ms. The model does not use GPU-accelerated operations. Which infrastructure change gives the HIGHEST throughput-per-dollar for this workload?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization serves two distinct ML models from a single Vertex AI dedicated endpoint: a lightweight text-classification model (50 MB) used for 95% of requests, and a heavy transformer model (8 GB) used for 5% of requests. Both models share the same endpoint, and you notice that the transformer model's long inference time is occasionally causing the lightweight model's p99 latency to degrade. What is the BEST architectural change to isolate workloads and maintain SLAs for both models?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Deploy both models to a single shared endpoint but increase the total number of replicas so queuing effects are reduced."},{"id":"b","text":"Deploy each model to its own dedicated Vertex AI endpoint with independent autoscaling configurations appropriate for each model's resource profile and traffic pattern."},{"id":"c","text":"Combine both models into a single ensemble SavedModel so that Vertex AI schedules inference requests together on the same hardware."},{"id":"d","text":"Move the transformer model to a Vertex AI batch prediction job triggered by a Pub/Sub message, and have the client poll for results."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Deploying each model to its own dedicated Vertex AI endpoint provides full workload isolation: separate queues, independent autoscaling, and distinct machine-type configurations. The lightweight model can run on cost-effective CPU replicas with high concurrency, while the transformer can be placed on GPU-equipped machines sized for its memory footprint. This eliminates head-of-line blocking where long transformer inferences delay text-classification requests. Option A reduces queuing statistically but does not eliminate interference, and wastes resources because both machine pools must be sized for the worst-case (transformer) workload. Option C bundling models into an ensemble is architecturally incorrect—they serve different use cases and must be called independently. Option D converts an online serving requirement (transformer still needs to respond to user-facing requests) into asynchronous batch, which breaks the real-time SLA.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/dedicated-endpoints","label":"Vertex AI – Dedicated endpoints overview"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/deploy-model-api#deploy_multiple_models","label":"Vertex AI – Deploy multiple models"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization serves two distinct ML models from a single Vertex AI dedicated endpoint: a lightweight text-classification model (50 MB) used for 95% of requests, and a heavy transformer model (8 GB) used for 5% of requests. Both models share the same endpoint, and you notice that the transformer model's long inference time is occasionally causing the lightweight model's p99 latency to degrade. What is the BEST architectural change to isolate workloads and maintain SLAs for both models?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You need to expose an existing Vertex AI online prediction endpoint to an external mobile application with the lowest possible network latency for globally distributed users. The endpoint currently exists only in us-central1. Retraining or copying model weights to multiple regions is not permitted due to data-residency constraints. Which approach BEST minimizes end-user latency globally while respecting the data-residency requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create a global Cloud Load Balancer with an Anycast IP, and configure it to route all traffic to the single us-central1 Vertex AI endpoint, leveraging Google's premium-tier backbone to reduce WAN latency."},{"id":"b","text":"Deploy Cloud CDN in front of the Vertex AI endpoint to cache prediction responses at Google edge POPs worldwide."},{"id":"c","text":"Replicate the Vertex AI endpoint to all Google Cloud regions and use Traffic Director to route requests to the nearest region."},{"id":"d","text":"Deploy the model to Firebase Hosting, which auto-distributes model files globally via Google's CDN."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$When data residency prevents multi-region model deployment, the best option is to keep the endpoint in the single permitted region and use a Global External Application Load Balancer with Google's Premium Network Tier. Premium Tier routes traffic from the user's nearest Google edge POP through Google's private, low-latency backbone to the us-central1 backend, significantly reducing WAN hops compared to Standard Tier internet routing. This complies with data-residency requirements because inference still executes only in us-central1. Option B (Cloud CDN) is designed for caching static or idempotent HTTP responses; ML prediction responses are dynamic and user-specific and cannot be meaningfully cached. Option C violates the data-residency constraint that prohibits copying model weights to multiple regions. Option D (Firebase Hosting) is a static-content hosting service, not suitable for serving dynamic ML inference.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/network-tiers/docs/overview","label":"Google Cloud – Premium Tier vs Standard Tier networking"},{"url":"https://cloud.google.com/load-balancing/docs/https","label":"Google Cloud – Global external Application Load Balancer overview"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/overview","label":"Vertex AI – Online prediction overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You need to expose an existing Vertex AI online prediction endpoint to an external mobile application with the lowest possible network latency for globally distributed users. The endpoint currently exists only in us-central1. Retraining or copying model weights to multiple regions is not permitted due to data-residency constraints. Which approach BEST minimizes end-user latency globally while respecting the data-residency requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Vertex AI online prediction endpoint serves a PyTorch model using a custom container. During a rolling update to a new model version, you observe that approximately 3% of requests return HTTP 503 errors for about 90 seconds while the new container image is pulling and initializing. The current deployment uses a single replica with no traffic-splitting configuration. Which combination of settings BEST eliminates the 503 errors during future deployments?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Configure a traffic split so 100% of traffic goes to the existing model version; deploy the new version with 0% traffic; validate it; then gradually shift traffic to 100% on the new version before removing the old version."},{"id":"b","text":"Increase the Vertex AI endpoint request timeout from the default to 300 seconds so that in-flight requests wait for the new container to start."},{"id":"c","text":"Enable Cloud Armor on the endpoint to queue and retry requests that receive 503 responses automatically."},{"id":"d","text":"Switch to a canary deployment in Cloud Run and route traffic from Cloud Run to the Vertex AI endpoint."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI endpoints support deploying multiple model versions simultaneously with configurable traffic splits. By deploying the new version at 0% traffic, you allow the container to pull, start, warm up, and pass health checks before it receives any live traffic. You can then validate the new version and shift traffic incrementally (e.g., 10% → 50% → 100%) while the old version continues to serve the remaining traffic. This eliminates the 503 window entirely. Option B increasing the timeout does not prevent 503s—requests are rejected when no healthy replica is available, not held in an extended queue. Option C Cloud Armor is a WAF/DDoS product and does not retry 503 responses from backends on behalf of clients. Option D introduces an unnecessary architectural layer (Cloud Run) and adds latency and complexity without solving the root cause, which is a deployment strategy issue native to Vertex AI.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/traffic-splitting","label":"Vertex AI – Traffic splitting between model versions"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/deploy-model-api#traffic-split","label":"Vertex AI – Deploy a model to an endpoint (blue/green and canary)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Vertex AI online prediction endpoint serves a PyTorch model using a custom container. During a rolling update to a new model version, you observe that approximately 3% of requests return HTTP 503 errors for about 90 seconds while the new container image is pulling and initializing. The current deployment uses a single replica with no traffic-splitting configuration. Which combination of settings BEST eliminates the 503 errors during future deployments?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team needs to serve predictions from a very large 70-billion-parameter language model on Vertex AI. The model requires more GPU memory than any single accelerator can provide. Single A100 80 GB GPUs are insufficient because the model requires approximately 140 GB of GPU VRAM for FP16 weights alone. Which Vertex AI serving strategy BEST addresses this constraint?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Deploy the model using Vertex AI Prediction with a custom container that implements tensor parallelism across multiple A100 GPUs on a single multi-GPU machine (e.g., a2-ultragpu-4g with 4x A100 80 GB GPUs), so the model is sharded across 320 GB of combined GPU memory."},{"id":"b","text":"Quantize the model to INT4 using Google's proprietary quantization SDK before uploading to Vertex AI, then deploy on a single T4 GPU."},{"id":"c","text":"Enable Vertex AI's automatic model sharding feature, which transparently splits any model across GPUs without requiring changes to the serving container."},{"id":"d","text":"Deploy the model to Vertex AI Batch Prediction instead of online prediction, since batch jobs can access more memory per request."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$For models that exceed single-GPU memory, tensor parallelism (also called model parallelism) distributes model weight tensors across multiple GPUs on the same physical host. The a2-ultragpu-4g machine type provides 4x NVIDIA A100 80 GB GPUs (320 GB total VRAM), which can accommodate a 70B FP16 model (~140 GB) with room for KV cache and activations. A custom container using a framework such as NVIDIA FasterTransformer, vLLM, or DeepSpeed-Inference implements the tensor-parallel sharding logic. Option B aggressively quantizing to INT4 on a T4 (16 GB VRAM) would require ~35 GB minimum—still exceeding a single T4—and INT4 quantization introduces non-trivial quality degradation for large language models without thorough validation. Option C is incorrect; Vertex AI Prediction does not offer automatic transparent model sharding—this must be implemented in the serving container. Option D batch prediction changes the serving paradigm to asynchronous and does not solve the memory constraint; batch jobs use the same underlying machine types.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/compute/docs/accelerator-optimized-machines#a2-ultra","label":"Google Cloud – A2 Ultra machine family (multi-GPU)"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/use-custom-container","label":"Vertex AI – Use custom containers for prediction"},{"url":"https://docs.vllm.ai/en/latest/serving/distributed_serving.html","label":"vLLM – Tensor Parallelism for LLM serving"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team needs to serve predictions from a very large 70-billion-parameter language model on Vertex AI. The model requires more GPU memory than any single accelerator can provide. Single A100 80 GB GPUs are insufficient because the model requires approximately 140 GB of GPU VRAM for FP16 weights alone. Which Vertex AI serving strategy BEST addresses this constraint?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team has deployed a binary classification model on Vertex AI that predicts customer churn. After several weeks in production, the model's precision and recall metrics—tracked via Vertex AI Model Monitoring—begin to degrade significantly, even though the input feature distributions appear stable. A data scientist suspects the issue is related to the relationship between features and the label rather than the features themselves. Which type of drift is MOST likely occurring, and which Vertex AI Model Monitoring capability should you configure to detect it?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Feature drift; configure skew detection by comparing the current serving distribution against the training baseline distribution for each input feature."},{"id":"b","text":"Concept drift; configure prediction drift detection to monitor shifts in the model's output score distribution over time as a proxy for label-relationship changes."},{"id":"c","text":"Data skew; configure feature attribution drift detection using Vertex Explainable AI to compare SHAP value distributions between training and serving data."},{"id":"d","text":"Training-serving skew; configure a Cloud Monitoring custom dashboard to plot raw serving request volumes and alert when throughput drops below a defined threshold."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Concept drift occurs when the statistical relationship between input features and the target label changes over time, even when the feature distributions themselves remain stable. This exactly matches the described scenario. Vertex AI Model Monitoring supports prediction drift detection, which tracks shifts in the model's output (prediction score) distribution using Jensen-Shannon divergence. A sustained shift in prediction scores—without a corresponding shift in input feature distributions—is the canonical signal for concept drift. Option A is incorrect because feature (skew/drift) detection monitors input feature distributions and would not surface if features are stable. Option C (feature attribution drift via Explainable AI) is a valid supplementary signal but is not the primary capability designed to detect concept drift; it also requires Explainable AI to be enabled and configured separately. Option D describes infrastructure-level throughput monitoring, which is unrelated to model quality degradation caused by concept drift.$patch$, $patch$Monitoring AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/model-monitoring/overview","label":"Vertex AI Model Monitoring overview – Drift detection"},{"url":"https://cloud.google.com/vertex-ai/docs/model-monitoring/using-model-monitoring#prediction-drift","label":"Vertex AI Model Monitoring – Prediction drift detection"},{"url":"https://cloud.google.com/vertex-ai/docs/explainable-ai/overview","label":"Vertex Explainable AI – Feature attributions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team has deployed a binary classification model on Vertex AI that predicts customer churn. After several weeks in production, the model's precision and recall metrics—tracked via Vertex AI Model Monitoring—begin to degrade significantly, even though the input feature distributions appear stable. A data scientist suspects the issue is related to the relationship between features and the label rather than the features themselves. Which type of drift is MOST likely occurring, and which Vertex AI Model Monitoring capability should you configure to detect it?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A financial services company operates a real-time fraud detection model served via a Vertex AI Endpoint. The MLOps team must implement an alerting strategy that satisfies all of the following requirements: (1) detect when the proportion of high-confidence fraud predictions (score ≥ 0.9) drops by more than 30% relative to the 7-day rolling average, (2) avoid retraining the model based on noisy short-term fluctuations, and (3) integrate alerts with the company's existing PagerDuty incident management system. Which combination of Google Cloud services and configuration choices BEST fulfills all three requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable Vertex AI Model Monitoring prediction drift detection with a Jensen-Shannon divergence threshold; export monitoring alerts natively to PagerDuty using the built-in Vertex AI–PagerDuty connector; set the retraining trigger to fire immediately on every alert."},{"id":"b","text":"Stream prediction requests and responses to BigQuery using Vertex AI Endpoint request-response logging; create a scheduled BigQuery query that computes the 7-day rolling ratio of high-confidence predictions; write results to a Cloud Monitoring custom metric; configure a Cloud Monitoring alerting policy with a 7-day lookback window and a condition that fires only if the threshold is breached for at least 24 consecutive hours; send notifications to PagerDuty via a Cloud Monitoring notification channel webhook."},{"id":"c","text":"Enable Cloud Audit Logs for the Vertex AI Endpoint; create a log-based metric in Cloud Logging that counts audit log entries per minute; configure a Cloud Monitoring alerting policy on that log-based metric with an absolute threshold; route alerts to PagerDuty using a Pub/Sub notification channel and a Cloud Run function."},{"id":"d","text":"Deploy a separate Cloud Run sidecar service that intercepts all prediction traffic, computes a rolling high-confidence ratio in memory, and sends a direct HTTP webhook to PagerDuty when the ratio drops; disable all Cloud Monitoring alerting to reduce cost."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B satisfies all three requirements precisely. (1) Request-response logging to BigQuery captures raw prediction scores, enabling a scheduled query to compute the exact high-confidence ratio (score ≥ 0.9) and compare it against a 7-day rolling average—giving full control over the business-specific threshold. (2) Setting the alerting condition to require the threshold to be breached for at least 24 consecutive hours (using Cloud Monitoring's 'alert duration' or 'condition evaluation window') prevents the team from acting on noisy short-term spikes and avoids premature retraining. (3) Cloud Monitoring supports PagerDuty as a first-class notification channel via webhook integration, satisfying the incident management requirement. Option A is incorrect because Vertex AI Model Monitoring does not have a native PagerDuty connector and its prediction drift metric is a distribution-level divergence score, not a business-defined ratio of high-confidence predictions; additionally, triggering retraining immediately on every alert violates requirement 2. Option C is incorrect because Cloud Audit Logs capture API-level administrative events, not prediction score values, so a log-based metric on audit logs cannot compute a fraud-score ratio. Option D introduces a non-standard, undocumented sidecar architecture that bypasses Google Cloud's observability stack entirely, is operationally fragile, and disabling Cloud Monitoring would break requirement 3.$patch$, $patch$Monitoring AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/online-predictions-logging","label":"Vertex AI – Log and monitor predictions (request-response logging)"},{"url":"https://cloud.google.com/monitoring/alerts/using-alerting-ui","label":"Cloud Monitoring – Create alerting policies"},{"url":"https://cloud.google.com/monitoring/support/notification-options#pagerduty","label":"Cloud Monitoring – PagerDuty notification channel"},{"url":"https://cloud.google.com/bigquery/docs/scheduling-queries","label":"BigQuery – Scheduled queries"},{"url":"https://cloud.google.com/monitoring/custom-metrics/creating-metrics","label":"Cloud Monitoring – Custom metrics overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A financial services company operates a real-time fraud detection model served via a Vertex AI Endpoint. The MLOps team must implement an alerting strategy that satisfies all of the following requirements: (1) detect when the proportion of high-confidence fraud predictions (score ≥ 0.9) drops by more than 30% relative to the 7-day rolling average, (2) avoid retraining the model based on noisy short-term fluctuations, and (3) integrate alerts with the company's existing PagerDuty incident management system. Which combination of Google Cloud services and configuration choices BEST fulfills all three requirements?$patch$);

-- PMLE-P2: 23 questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization wants to build a document classification solution on Google Cloud with minimal custom code. Business analysts—not ML engineers—will own the solution day-to-day. The documents are already stored in Cloud Storage and the team needs an AutoML-backed workflow that integrates with BigQuery for reporting. Which Google Cloud service best satisfies all of these requirements as a low-code solution?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI AutoML Document AI with a custom Flask API deployed on Cloud Run"},{"id":"b","text":"Document AI with a processor trained via the Document AI Workbench and results exported to BigQuery"},{"id":"c","text":"Vertex AI AutoML Text Classification trained through the Vertex AI console, with predictions exported to BigQuery via a no-code Dataflow template"},{"id":"d","text":"A custom TensorFlow text model trained on Vertex AI Training and served via Vertex AI Endpoints"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Vertex AI AutoML Text Classification is a low-code service that allows non-ML experts to train a document classification model through the Google Cloud console without writing model code. Predictions can be exported to BigQuery using no-code Dataflow templates, satisfying the reporting requirement. Option A incorrectly pairs AutoML Document AI (which is for form/document extraction, not classification) with a custom API, introducing unnecessary code. Option B (Document AI Workbench) is designed for structured form parsing rather than general document classification. Option D requires writing and maintaining custom TensorFlow code, violating the low-code requirement.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/text-data/classification/overview","label":"Vertex AI AutoML Text Classification overview"},{"url":"https://cloud.google.com/dataflow/docs/guides/templates/provided/flex-templates-overview","label":"Dataflow no-code templates"},{"url":"https://cloud.google.com/bigquery/docs/bqml-introduction","label":"BigQuery ML and Vertex AI integration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization wants to build a document classification solution on Google Cloud with minimal custom code. Business analysts—not ML engineers—will own the solution day-to-day. The documents are already stored in Cloud Storage and the team needs an AutoML-backed workflow that integrates with BigQuery for reporting. Which Google Cloud service best satisfies all of these requirements as a low-code solution?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A retail company stores structured customer transaction data in BigQuery and wants to predict customer churn without moving data out of BigQuery or writing custom model training code. The data science team wants to iterate quickly by experimenting with multiple ML algorithms and evaluating them inside BigQuery. Which approach best meets these requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Export the BigQuery data to Cloud Storage, train an AutoML Tabular model in Vertex AI, and import predictions back into BigQuery"},{"id":"b","text":"Use BigQuery ML to create and evaluate multiple classification models directly in BigQuery using SQL statements"},{"id":"c","text":"Use Vertex AI Workbench to write a scikit-learn notebook that reads from BigQuery and trains a churn model"},{"id":"d","text":"Configure a Vertex AI Pipeline to orchestrate feature engineering in Dataflow and model training in Vertex AI Training"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$BigQuery ML (BQML) enables data scientists to create, train, evaluate, and serve ML models using standard SQL directly within BigQuery—no data movement, no custom code, and no separate training infrastructure required. Teams can rapidly experiment with logistic regression, boosted trees, deep neural networks, and more using CREATE MODEL statements. Option A requires data export and introduces an operational gap. Option C requires Python/scikit-learn code and a managed notebook, violating the low-code constraint. Option D involves custom pipeline orchestration code and is appropriate for more complex MLOps workflows, not rapid low-code iteration.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/bigquery/docs/bqml-introduction","label":"BigQuery ML overview"},{"url":"https://cloud.google.com/bigquery/docs/bqml-introduction#supported_models_in","label":"BigQuery ML supported models"},{"url":"https://cloud.google.com/bigquery/docs/reference/standard-sql/bigqueryml-syntax-create","label":"CREATE MODEL statement in BigQuery ML"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A retail company stores structured customer transaction data in BigQuery and wants to predict customer churn without moving data out of BigQuery or writing custom model training code. The data science team wants to iterate quickly by experimenting with multiple ML algorithms and evaluating them inside BigQuery. Which approach best meets these requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An e-commerce company wants to add real-time product recommendations to its website. The engineering team has no ML expertise and wants a managed, low-code solution that can ingest user event data from the website, train recommendation models automatically, and serve personalized results via an API—all within Google Cloud. Which service is the most appropriate choice?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Matching Engine with custom embedding generation using a pre-trained TensorFlow Hub model"},{"id":"b","text":"Google Cloud Recommendations AI (Retail API) configured with event ingestion, model training, and a Predict API"},{"id":"c","text":"Vertex AI AutoML Tabular trained on purchase history exported from Cloud Spanner"},{"id":"d","text":"A collaborative filtering model built with Spark MLlib on Dataproc and served through a custom Cloud Run endpoint"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Google Cloud Recommendations AI (part of the Retail API) is purpose-built for e-commerce product recommendations. It provides a fully managed, low-code pipeline: teams ingest user events (page views, add-to-cart, purchases) via the Retail API, Google automatically trains recommendation models, and predictions are served through the Predict REST API. No ML expertise or custom code is needed. Option A (Matching Engine) requires teams to generate their own embeddings with custom code. Option C (AutoML Tabular) is a general tabular classification/regression tool, not optimized for real-time recommendation serving. Option D requires significant ML and engineering expertise—the opposite of a low-code solution.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/retail/docs/overview","label":"Google Cloud Retail API overview"},{"url":"https://cloud.google.com/retail/docs/getting-started","label":"Recommendations AI getting started"},{"url":"https://cloud.google.com/retail/docs/reference/rest/v2/projects.locations.catalogs.placements/predict","label":"Retail API Predict method"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An e-commerce company wants to add real-time product recommendations to its website. The engineering team has no ML expertise and wants a managed, low-code solution that can ingest user event data from the website, train recommendation models automatically, and serve personalized results via an API—all within Google Cloud. Which service is the most appropriate choice?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A healthcare organization wants to extract structured information—such as patient names, medication names, and dosage amounts—from unstructured clinical notes stored as PDFs in Cloud Storage. The team has no ML engineers available and must use a low-code approach. The extracted data must be written to BigQuery for downstream analytics. Which Google Cloud architecture best meets these requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use the Cloud Natural Language API's entity extraction feature, triggered by Cloud Functions, to process PDFs directly and write results to BigQuery"},{"id":"b","text":"Use the Healthcare Natural Language API to extract medical entities from clinical notes, with results written to BigQuery via a Cloud Function trigger on Cloud Storage"},{"id":"c","text":"Deploy a pre-trained BioBERT model on Vertex AI Endpoints and write a custom Python pipeline to call the endpoint and load results into BigQuery"},{"id":"d","text":"Use Vertex AI AutoML Entity Extraction trained on a custom annotated dataset of clinical notes, served via batch predictions written to BigQuery"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The Healthcare Natural Language API is a specialized, pre-trained, low-code Google Cloud service designed specifically to extract medical entities (medications, dosages, patient data, diagnoses) from clinical text—without any model training or ML expertise. Triggering it via a Cloud Function on Cloud Storage events and writing outputs to BigQuery creates a serverless, low-code pipeline. Option A (Cloud Natural Language API) is a general-purpose NLP API not trained on clinical/medical terminology and will underperform on healthcare NER tasks. Option C requires deploying and maintaining a custom model endpoint plus custom pipeline code, violating the low-code requirement. Option D (AutoML Entity Extraction) requires annotated training data and ML expertise to build and manage, making it unsuitable as a quick low-code solution when a purpose-built API already exists.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/healthcare-api/docs/how-tos/nlp","label":"Cloud Healthcare Natural Language API overview"},{"url":"https://cloud.google.com/healthcare-api/docs","label":"Cloud Healthcare API documentation"},{"url":"https://cloud.google.com/healthcare-api/docs/how-tos/nlp#analyzing_medical_text","label":"Exporting Healthcare Natural Language API results to BigQuery"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A healthcare organization wants to extract structured information—such as patient names, medication names, and dosage amounts—from unstructured clinical notes stored as PDFs in Cloud Storage. The team has no ML engineers available and must use a low-code approach. The extracted data must be written to BigQuery for downstream analytics. Which Google Cloud architecture best meets these requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization has multiple data science teams working on separate Vertex AI Pipelines projects. A new governance policy requires that all pipeline artifacts, datasets, and models be centrally discoverable and lineage-tracked across every team's work. Which Google Cloud service should you configure as the centralized metadata and lineage backbone to satisfy this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Feature Store, using shared feature groups visible to all projects"},{"id":"b","text":"Vertex ML Metadata, connected to a shared MetadataStore in a central project that all team pipelines write to"},{"id":"c","text":"Cloud Data Catalog, tagging every artifact with a custom lineage template"},{"id":"d","text":"BigQuery INFORMATION_SCHEMA views, querying job history across projects to reconstruct lineage"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex ML Metadata is the purpose-built service for tracking ML artifacts, executions, and lineage across Vertex AI Pipelines runs. By pointing all team pipelines at a single, centralized MetadataStore in a shared host project, every artifact is automatically recorded and its lineage graph is queryable in one place. Option A (Feature Store) manages serving of feature values, not cross-team artifact lineage. Option C (Data Catalog) provides data discovery and tagging but does not natively capture pipeline execution lineage. Option D (BigQuery INFORMATION_SCHEMA) records SQL job history, not ML pipeline artifact provenance.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/ml-metadata/introduction","label":"Vertex ML Metadata overview"},{"url":"https://cloud.google.com/vertex-ai/docs/pipelines/track-artifacts-metadata","label":"Tracking artifacts and lineage with Vertex AI Pipelines"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization has multiple data science teams working on separate Vertex AI Pipelines projects. A new governance policy requires that all pipeline artifacts, datasets, and models be centrally discoverable and lineage-tracked across every team's work. Which Google Cloud service should you configure as the centralized metadata and lineage backbone to satisfy this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning platform team needs to expose curated, versioned feature transformations so that three downstream model teams can reuse them without independently re-engineering the same logic. The features must be available for both offline training (low-latency bulk reads) and online serving (low-latency single-entity lookups). Which Vertex AI capability best addresses this cross-team feature sharing requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Experiments, sharing experiment configs and metrics across teams via a shared experiment run"},{"id":"b","text":"Vertex AI Feature Store, creating a shared feature store with feature groups and online/offline serving endpoints accessible to all model teams"},{"id":"c","text":"Vertex AI Model Registry, publishing model versions with attached feature schemas so downstream teams can inspect input requirements"},{"id":"d","text":"Cloud Composer DAGs that materialize features into BigQuery, with each model team reading directly from shared BigQuery tables"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Feature Store is specifically designed for centralizing, versioning, and serving reusable features to multiple teams. It provides both an offline store (backed by BigQuery) for training data generation and an online store for low-latency real-time lookups, eliminating duplicated feature engineering across teams. Option A (Experiments) tracks metrics and hyperparameters, not feature values. Option C (Model Registry) stores model artifacts and metadata, not feature transformations. Option D (BigQuery tables via Composer) can work for offline use but offers no managed online serving layer and requires each team to maintain its own ingestion logic rather than sharing a governed store.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/overview","label":"Vertex AI Feature Store overview"},{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/serving-online","label":"Vertex AI Feature Store: online and offline serving"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning platform team needs to expose curated, versioned feature transformations so that three downstream model teams can reuse them without independently re-engineering the same logic. The features must be available for both offline training (low-latency bulk reads) and online serving (low-latency single-entity lookups). Which Vertex AI capability best addresses this cross-team feature sharing requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization enforces a strict model promotion process: a model trained by a research team must be reviewed and approved by an MLOps team before it can be deployed to production. You need to implement this workflow using native Vertex AI capabilities so that the approval state is auditable and the deployment is gated programmatically. Which approach best satisfies these requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Store models in Cloud Storage buckets with distinct prefixes for 'staging' and 'production'; use IAM conditions to restrict who can copy objects between prefixes"},{"id":"b","text":"Register models in Vertex AI Model Registry with custom model labels (e.g., stage=staging, stage=approved); use a Vertex AI Pipeline step that checks the label value and conditionally calls the deploy endpoint only when stage=approved is present"},{"id":"c","text":"Use Vertex AI Experiments to record a 'status' parameter; trigger deployment whenever an experiment run shows status=approved in its logged parameters"},{"id":"d","text":"Enable Vertex AI Model Monitoring on the staging endpoint and promote the model automatically once the monitoring job reports no skew for 24 hours"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Model Registry supports custom metadata labels on model versions, creating a lightweight but auditable approval gate. A pipeline step can programmatically inspect the label, ensuring deployment only proceeds when the MLOps team has explicitly set the approval label. This pattern is natively supported, fully auditable through Cloud Audit Logs on the registry resource, and keeps promotion logic in code. Option A relies on IAM and Cloud Storage, which lacks native ML metadata and requires manual copy operations outside the Model Registry. Option C misuses the Experiments service, which is designed for tracking training metrics, not governing deployment approvals. Option D automates promotion based on monitoring output, not on an explicit human approval gate, violating the review requirement.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/model-registry/introduction","label":"Vertex AI Model Registry overview"},{"url":"https://cloud.google.com/vertex-ai/docs/model-registry/manage-models","label":"Managing model versions in Vertex AI"},{"url":"https://cloud.google.com/vertex-ai/docs/general/audit-logging","label":"Cloud Audit Logs for Vertex AI"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization enforces a strict model promotion process: a model trained by a research team must be reviewed and approved by an MLOps team before it can be deployed to production. You need to implement this workflow using native Vertex AI capabilities so that the approval state is auditable and the deployment is gated programmatically. Which approach best satisfies these requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data engineering team owns a sensitive customer dataset stored in BigQuery and wants to grant a separate ML research team read access to it for training, while ensuring the research team never sees personally identifiable information (PII) columns such as email addresses and phone numbers. The data engineering team wants to manage this access centrally without duplicating the underlying data. Which approach should you recommend?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Export the dataset to Cloud Storage with PII columns removed using a Dataflow job; grant the research team read access to the exported files"},{"id":"b","text":"Create an authorized BigQuery view that excludes PII columns; grant the research team bigquery.dataViewer on the view only, keeping the source table accessible solely to the data engineering team"},{"id":"c","text":"Use BigQuery column-level encryption with a Cloud KMS key managed by the data engineering team; withhold the decryption key from the research team so PII values appear as ciphertext"},{"id":"d","text":"Apply a BigQuery row-level access policy that filters out any row containing non-null PII values, granting the research team access to the filtered result set"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$An authorized BigQuery view is the recommended, zero-copy pattern for granting cross-team access to a subset of columns. The view owner (data engineering) defines exactly which columns are exposed, the source table remains inaccessible to the research team, and no data is duplicated. IAM is granted only on the view, providing a clean governance boundary. Option A duplicates data into Cloud Storage, introducing synchronization overhead and an additional data copy that must be governed separately. Option C (AEAD encryption) would render PII unreadable but still exposes the encrypted ciphertext column, adds key-management complexity, and is not the standard pattern for column-level access restriction. Option D (row-level access policies) filters rows, not columns; it cannot hide specific PII columns while exposing all other columns in a row.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/bigquery/docs/authorized-views","label":"BigQuery authorized views"},{"url":"https://cloud.google.com/bigquery/docs/column-level-security-intro","label":"BigQuery column-level security overview"},{"url":"https://cloud.google.com/bigquery/docs/best-practices-iam","label":"BigQuery best practices: controlling access to datasets"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A data engineering team owns a sensitive customer dataset stored in BigQuery and wants to grant a separate ML research team read access to it for training, while ensuring the research team never sees personally identifiable information (PII) columns such as email addresses and phone numbers. The data engineering team wants to manage this access centrally without duplicating the underlying data. Which approach should you recommend?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your data science team has developed a TensorFlow prototype model trained on a single VM using a small sample dataset. The full production dataset is 50 TB stored in Cloud Storage and the model requires distributed training. You need to scale the training job with minimal code refactoring. Which approach should you use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Rewrite the model using Apache Spark MLlib and run it on a Dataproc cluster."},{"id":"b","text":"Wrap the existing TensorFlow code with tf.distribute.MirroredStrategy and submit the job to Vertex AI Training with a multi-GPU machine type."},{"id":"c","text":"Convert the TensorFlow model to scikit-learn and run it on a Compute Engine instance with 96 vCPUs."},{"id":"d","text":"Export the prototype model to BigQuery ML using the IMPORT MODEL statement for distributed training."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$tf.distribute.MirroredStrategy requires minimal code changes—it wraps the existing model.compile and model.fit calls—and is natively supported by Vertex AI Training, which handles cluster provisioning and data reading from Cloud Storage. Rewriting in Spark MLlib (a) involves substantial refactoring and loses TensorFlow-specific capabilities. Scikit-learn (c) does not scale to 50 TB and lacks native GPU-distributed training. BigQuery ML IMPORT MODEL (d) is for importing pre-trained models for inference, not for distributed training of custom TensorFlow code.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/overview","label":"Vertex AI: Custom training overview"},{"url":"https://www.tensorflow.org/api_docs/python/tf/distribute/MirroredStrategy","label":"TensorFlow: tf.distribute.MirroredStrategy"},{"url":"https://cloud.google.com/vertex-ai/docs/training/distributed-training","label":"Vertex AI: Distributed training"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your data science team has developed a TensorFlow prototype model trained on a single VM using a small sample dataset. The full production dataset is 50 TB stored in Cloud Storage and the model requires distributed training. You need to scale the training job with minimal code refactoring. Which approach should you use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning engineer is converting a Jupyter notebook prototype into a production-grade training pipeline on Vertex AI Pipelines. The notebook uses Pandas DataFrames to perform feature transformations inline before model training. As dataset size grows to hundreds of millions of rows, which refactoring strategy best addresses scalability while preserving pipeline reproducibility?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Increase the memory on the Vertex AI Training custom job machine to accommodate the full Pandas DataFrame in RAM."},{"id":"b","text":"Replace the Pandas transformation logic with Apache Beam transforms executed on Dataflow, and persist the transformed features to Cloud Storage before training."},{"id":"c","text":"Cache the Pandas DataFrame to a local disk attached to the training VM and reload it at training time."},{"id":"d","text":"Use Vertex AI Feature Store online serving to fetch all features row by row at training time."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Apache Beam on Dataflow is a horizontally scalable, serverless data processing engine that handles hundreds of millions of rows without memory constraints. Persisting the output to Cloud Storage decouples transformation from training, enabling reproducibility and auditability. Increasing VM memory (a) has practical limits and is cost-inefficient at scale. Caching to local disk (c) doesn't scale beyond a single machine and creates reproducibility issues. Fetching features row-by-row from the Feature Store online server (d) is designed for low-latency single-record lookups, not bulk batch retrieval, and would be extremely slow and expensive for training data.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/dataflow/docs/overview","label":"Google Cloud: Dataflow overview"},{"url":"https://cloud.google.com/vertex-ai/docs/pipelines/introduction","label":"Vertex AI Pipelines documentation"},{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/batch-serve-features","label":"Vertex AI Feature Store: Batch serving"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning engineer is converting a Jupyter notebook prototype into a production-grade training pipeline on Vertex AI Pipelines. The notebook uses Pandas DataFrames to perform feature transformations inline before model training. As dataset size grows to hundreds of millions of rows, which refactoring strategy best addresses scalability while preserving pipeline reproducibility?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You have a PyTorch model prototype that trains well on a single GPU. You need to scale it to train on a cluster of 8 VMs, each with 4 GPUs (32 GPUs total), using Vertex AI Training. The training data resides in Cloud Storage. What is the recommended configuration to achieve data-parallel distributed training with the least operational overhead?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use a Vertex AI Training custom job with a single chief worker node and manually shard the dataset across 32 separate input files."},{"id":"b","text":"Use a Vertex AI Training custom job configured with a cluster spec of 8 worker replicas, refactor the training code to use PyTorch DistributedDataParallel (DDP) with the 'nccl' backend, and use a pre-built PyTorch deep learning container."},{"id":"c","text":"Package the PyTorch training script as a Dataflow pipeline using the PyTorch on Beam runner to distribute gradient updates."},{"id":"d","text":"Deploy the PyTorch model to a Vertex AI endpoint with 32 replicas and send training data as prediction requests."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Training natively supports multi-node custom jobs via cluster specifications. PyTorch DistributedDataParallel (DDP) with the NCCL backend is the standard approach for GPU data-parallel training in PyTorch. Pre-built deep learning containers include CUDA, NCCL, and PyTorch, minimising setup overhead. A single-chief configuration (a) does not achieve multi-node parallelism. Dataflow (c) is a batch/stream data processing engine, not a framework for GPU-accelerated model training. Sending training data to a Vertex AI endpoint (d) is nonsensical for training—endpoints are for inference.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/distributed-training","label":"Vertex AI: Run distributed training with custom containers"},{"url":"https://pytorch.org/docs/stable/notes/ddp.html","label":"PyTorch: Distributed Data Parallel"},{"url":"https://cloud.google.com/vertex-ai/docs/training/pre-built-containers","label":"Vertex AI: Pre-built containers for training"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You have a PyTorch model prototype that trains well on a single GPU. You need to scale it to train on a cluster of 8 VMs, each with 4 GPUs (32 GPUs total), using Vertex AI Training. The training data resides in Cloud Storage. What is the recommended configuration to achieve data-parallel distributed training with the least operational overhead?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A team is migrating an iterative hyperparameter tuning process from a manual notebook workflow to an automated, scalable solution on Google Cloud. The model is a custom Keras classifier. Training a single trial takes approximately 45 minutes. They need to evaluate 200 hyperparameter combinations efficiently. Which solution minimises total tuning wall-clock time while staying within the Google Cloud ecosystem?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Run all 200 trials sequentially in a single Vertex AI Training custom job using a for-loop inside the training script."},{"id":"b","text":"Use Vertex AI Vizier (hyperparameter tuning) via Vertex AI Training's built-in hyperparameter tuning job, configuring maxTrialCount=200 and parallelTrialCount equal to the desired concurrency, with the objective metric reported via cloudml-hyper-tune."},{"id":"c","text":"Use Cloud Composer to schedule 200 separate DAG tasks, each triggering a Vertex AI Training job, with results written to BigQuery for manual analysis."},{"id":"d","text":"Deploy the Keras model to Vertex AI Experiments and rely on automatic hyperparameter search built into the experiments SDK."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Training's hyperparameter tuning job uses Vertex AI Vizier under the hood to intelligently search the hyperparameter space (Bayesian optimisation by default). Setting parallelTrialCount to a value greater than 1 runs multiple trials concurrently, dramatically reducing wall-clock time. The cloudml-hyper-tune library allows the training script to receive suggested hyperparameter values and report metrics back to the tuning service. Running trials sequentially (a) would take 200 × 45 min = ~150 hours of wall-clock time. Cloud Composer (c) can orchestrate jobs but adds unnecessary orchestration overhead and does not provide intelligent search—it would require manual correlation of results. Vertex AI Experiments (d) is a tracking tool for logging metrics and parameters; it does not automatically run hyperparameter search trials.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/hyperparameter-tuning-overview","label":"Vertex AI: Hyperparameter tuning overview"},{"url":"https://cloud.google.com/vertex-ai/docs/vizier/overview","label":"Vertex AI Vizier: Overview"},{"url":"https://cloud.google.com/vertex-ai/docs/training/run-hyperparameter-tuning-job","label":"Vertex AI: Run a hyperparameter tuning job"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A team is migrating an iterative hyperparameter tuning process from a manual notebook workflow to an automated, scalable solution on Google Cloud. The model is a custom Keras classifier. Training a single trial takes approximately 45 minutes. They need to evaluate 200 hyperparameter combinations efficiently. Which solution minimises total tuning wall-clock time while staying within the Google Cloud ecosystem?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An ML engineer has a working scikit-learn pipeline prototype that performs preprocessing and classification. The pipeline must be containerised and registered in Artifact Registry so it can be versioned and deployed via Vertex AI. The engineer wants to ensure the container image is reproducible and auditable. Which sequence of steps is correct?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"1) Export the trained pipeline with joblib. 2) Write a Dockerfile that copies the joblib artifact and a Flask serving script. 3) Build the image with Cloud Build using a cloudbuild.yaml that pushes to Artifact Registry. 4) Register the image URI in Vertex AI Model Registry using the REST API or gcloud."},{"id":"b","text":"1) Upload the raw .py prototype file directly to a Cloud Storage bucket. 2) Reference the Cloud Storage URI as the model artifact in Vertex AI Model Registry. 3) Skip containerisation because Vertex AI auto-wraps Python files."},{"id":"c","text":"1) Use AutoML Tables to re-train the scikit-learn pipeline logic without containerisation. 2) Deploy the AutoML model to a Vertex AI endpoint."},{"id":"d","text":"1) Save the scikit-learn pipeline as a .pkl file. 2) Upload the .pkl to BigQuery as a BYTES column. 3) Use BigQuery ML IMPORT MODEL to serve it via SQL."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$The correct production workflow is: serialise the trained pipeline (joblib is the recommended serialiser for scikit-learn), package it with a prediction server in a Docker image, use Cloud Build for reproducible image construction, push to Artifact Registry for versioned storage, and register the container URI in Vertex AI Model Registry. This provides full auditability and versioning. Option (b) is incorrect—Vertex AI does not auto-wrap raw .py files; a container or a pre-built container with a model artifact is required. Option (c) completely changes the modelling approach and abandons the existing prototype. Option (d) misuses BigQuery as a binary artifact store and IMPORT MODEL does not support arbitrary scikit-learn pickles as a serving runtime.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/custom-prediction-routines","label":"Vertex AI: Custom prediction routines with scikit-learn"},{"url":"https://cloud.google.com/artifact-registry/docs/overview","label":"Artifact Registry: Overview"},{"url":"https://cloud.google.com/build/docs/building/build-containers","label":"Cloud Build: Building and pushing container images"},{"url":"https://cloud.google.com/vertex-ai/docs/model-registry/introduction","label":"Vertex AI Model Registry"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An ML engineer has a working scikit-learn pipeline prototype that performs preprocessing and classification. The pipeline must be containerised and registered in Artifact Registry so it can be versioned and deployed via Vertex AI. The engineer wants to ensure the container image is reproducible and auditable. Which sequence of steps is correct?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$During the transition from prototype to production, your team discovers that the training pipeline written in Python intermittently produces different model quality metrics across runs despite using the same training data. The model uses dropout layers and random data augmentation. You need to ensure fully reproducible training runs when rerunning the same pipeline revision. Which combination of practices achieves this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Set a fixed random seed in TensorFlow/NumPy/Python random modules, pin all library versions in a requirements.txt or conda environment file, and store the exact dataset version using Vertex AI Managed Datasets with immutable data snapshots."},{"id":"b","text":"Disable dropout layers and all data augmentation permanently so that no stochastic operations remain in the pipeline."},{"id":"c","text":"Run the training pipeline 10 times and use the median metric score as the canonical result, storing all 10 model artifacts."},{"id":"d","text":"Switch from Vertex AI Training to Cloud Run to guarantee deterministic execution environments."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Reproducibility requires controlling all sources of randomness and environmental variation: (1) fixing seeds for all random number generators (Python, NumPy, TensorFlow) eliminates stochastic variation within a run; (2) pinning library versions in requirements.txt or a conda environment guarantees the same code paths across runs; (3) immutable dataset versioning via Vertex AI Managed Datasets ensures the same data is used. Disabling dropout and augmentation (b) degrades model quality and is not a viable production approach—the goal is reproducibility, not elimination of regularisation. Running 10 trials and taking the median (c) does not achieve reproducibility; it just averages over variability. Cloud Run (d) is a serverless container platform for serving applications, not a specialised training environment, and switching to it does not inherently address random seed or library version issues.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://www.tensorflow.org/api_docs/python/tf/random/set_seed","label":"TensorFlow: Random number generation and reproducibility"},{"url":"https://cloud.google.com/vertex-ai/docs/datasets/overview","label":"Vertex AI: Manage datasets"},{"url":"https://cloud.google.com/architecture/ml-on-gcp-best-practices#ensure_reproducibility","label":"Google Cloud: ML reproducibility best practices"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$During the transition from prototype to production, your team discovers that the training pipeline written in Python intermittently produces different model quality metrics across runs despite using the same training data. The model uses dropout layers and random data augmentation. You need to ensure fully reproducible training runs when rerunning the same pipeline revision. Which combination of practices achieves this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team has deployed a TensorFlow image-classification model on Vertex AI Prediction using an n1-standard-4 machine type. During a product launch, traffic spikes to 50× the baseline within 90 seconds, causing HTTP 429 errors before autoscaling can add new nodes. The model artifact itself cannot be changed. Which combination of Vertex AI Prediction configuration changes will BEST mitigate the latency and 429 errors during sudden traffic spikes while minimizing idle cost?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable autoscaling with a minReplicaCount of 0 and a maxReplicaCount of 20, and set the target CPU utilization threshold to 95%."},{"id":"b","text":"Set minReplicaCount to a warm baseline (e.g., 5) that absorbs the initial spike, configure maxReplicaCount to 20, and lower the autoscaling target CPU utilization to 60% so scale-out triggers earlier."},{"id":"c","text":"Switch to a GPU-backed machine type (e.g., n1-standard-4 + 1 x NVIDIA T4) and keep minReplicaCount at 1 with no autoscaling policy change."},{"id":"d","text":"Enable traffic splitting by deploying a second model version with identical artifacts and routing 50% of traffic to each version to distribute load."},{"id":"e","text":"Increase the prediction request timeout to 300 seconds so that queued requests eventually complete instead of returning 429 errors."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct because keeping a non-zero minReplicaCount ensures there are always warm replicas available to handle the initial burst before the autoscaler provisions additional nodes, and a lower CPU utilization target (60%) causes scale-out to trigger earlier, reducing the window of overload. Option A sets minReplicaCount to 0, meaning the endpoint cold-starts from zero and cannot absorb any burst traffic before scaling begins. Option C adds GPU compute but doesn't address the autoscaling policy; a single replica will still be overwhelmed. Option D (traffic splitting with identical artifacts) does not add capacity—it just routes the same overloaded traffic to two endpoints running the same artifact with the same replica count. Option E only extends the timeout window; it does not add capacity and will eventually exhaust the request queue, still resulting in errors.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/configure-compute#autoscaling","label":"Vertex AI – Configure autoscaling for online prediction"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/deploy-model-api","label":"Vertex AI – Deploy a model to an endpoint"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team has deployed a TensorFlow image-classification model on Vertex AI Prediction using an n1-standard-4 machine type. During a product launch, traffic spikes to 50× the baseline within 90 seconds, causing HTTP 429 errors before autoscaling can add new nodes. The model artifact itself cannot be changed. Which combination of Vertex AI Prediction configuration changes will BEST mitigate the latency and 429 errors during sudden traffic spikes while minimizing idle cost?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A retail company serves product-recommendation predictions via a Vertex AI online endpoint. The model returns a JSON payload averaging 4 KB per response. At peak load the endpoint serves 8,000 requests per second (RPS), and the ML engineering team notices that median latency is acceptable but p99 latency is 3× higher than p50. Cloud Monitoring shows that the dedicated serving VMs are at only 35% CPU utilization. What is the MOST likely root cause of the high p99 latency?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The model is bottlenecked on GPU memory bandwidth; switching to a CPU-only machine type will equalize latency percentiles."},{"id":"b","text":"The load balancer is routing all requests to a single replica due to session affinity misconfiguration, causing queue buildup on that replica."},{"id":"c","text":"Network egress bandwidth is saturated; the 4 KB × 8,000 RPS = ~32 MB/s of response data is exceeding the VM's NIC capacity."},{"id":"d","text":"Request queuing at the model server level (e.g., TensorFlow Serving or Triton) is causing tail latency; the serving container's max batch queue depth or worker thread count needs to be tuned."},{"id":"e","text":"Vertex AI Prediction imposes a hard p99 SLA cap of 2× p50, so the 3× ratio indicates a billing tier upgrade is required."}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Option D is correct. When CPU utilization is low but p99 latency is disproportionately high relative to p50, the classic cause is request queuing inside the model server process—not compute saturation. TensorFlow Serving and NVIDIA Triton Inference Server both have configurable worker thread pools and dynamic batching queues. If those are under-configured, requests queue behind each other, producing long tail latency even though aggregate CPU looks healthy. Option A is incorrect because the problem states CPU utilization (not GPU) is at 35%, and switching machine types wouldn't inherently fix queuing. Option B is possible in theory but Vertex AI's internal load balancer uses round-robin by default and does not maintain session affinity unless explicitly configured. Option C is incorrect because 32 MB/s of egress is well within standard GCP VM NIC capacity (which is measured in Gbps). Option E is fabricated; Vertex AI does not have a billing tier that caps latency percentile ratios.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://www.tensorflow.org/tfx/serving/performance","label":"TensorFlow Serving – Performance tuning"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/monitor-online-prediction","label":"Vertex AI – Monitor online predictions"},{"url":"https://docs.nvidia.com/deeplearning/triton-inference-server/user-guide/docs/user_guide/model_configuration.html","label":"NVIDIA Triton Inference Server – Model configuration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A retail company serves product-recommendation predictions via a Vertex AI online endpoint. The model returns a JSON payload averaging 4 KB per response. At peak load the endpoint serves 8,000 requests per second (RPS), and the ML engineering team notices that median latency is acceptable but p99 latency is 3× higher than p50. Cloud Monitoring shows that the dedicated serving VMs are at only 35% CPU utilization. What is the MOST likely root cause of the high p99 latency?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An ML engineer needs to serve a 13-billion-parameter large language model (LLM) for internal batch summarization tasks that run nightly on ~500,000 documents. The team wants to minimize cost while meeting a 6-hour total processing window. The model has already been converted to a SavedModel format. Which Vertex AI serving strategy is MOST cost-effective for this workload?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Deploy the model to a Vertex AI online endpoint with minReplicaCount set to 0 so it scales to zero overnight, then invoke it synchronously from a Cloud Run job."},{"id":"b","text":"Use Vertex AI Batch Prediction with a GPU machine type, specifying the starting replica count and letting the service manage the fleet for the duration of the job."},{"id":"c","text":"Host the model on a single Compute Engine A3 VM with a persistent disk, run inference in a custom Python loop, and shut down the VM after completion."},{"id":"d","text":"Submit the model to Vertex AI Model Registry and trigger a Vertex AI Pipeline that fans out the 500,000 documents to 500 parallel custom training jobs, each processing 1,000 documents."},{"id":"e","text":"Deploy the model on Vertex AI online prediction with a large dedicated GPU cluster and use Pub/Sub to fan out inference requests during the nightly window."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct. Vertex AI Batch Prediction is purpose-built for large-scale, offline inference workloads. It automatically provisions and deprovisions GPU workers, supports large model artifacts stored in Cloud Storage, handles retries, and charges only for the compute time used during the job—making it inherently cost-efficient for nightly batch workloads. Option A is not suitable because online endpoints are optimized for low-latency, real-time requests. Invoking an online endpoint 500,000 times synchronously from Cloud Run would incur high per-request overhead and network costs, and scale-to-zero from a cold state would add cold-start latency. Option C avoids managed services but requires manual orchestration, monitoring, and restart logic; it also cannot parallelize across multiple VMs without additional engineering. Option D misuses custom training jobs for inference, which is not the intended purpose of that resource type and adds unnecessary overhead. Option E keeps the cluster running (idle between requests) and adds unnecessary Pub/Sub complexity for a batch workload.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/batch-predictions","label":"Vertex AI – Batch prediction overview"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/get-batch-predictions","label":"Vertex AI – Get batch predictions for a custom-trained model"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An ML engineer needs to serve a 13-billion-parameter large language model (LLM) for internal batch summarization tasks that run nightly on ~500,000 documents. The team wants to minimize cost while meeting a 6-hour total processing window. The model has already been converted to a SavedModel format. Which Vertex AI serving strategy is MOST cost-effective for this workload?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization runs a fraud-detection model on Vertex AI online prediction. A new regulatory requirement mandates that the model version used for each prediction must be auditable for at least 7 years. Predictions are currently logged to BigQuery via Vertex AI request-response logging. Model versions are registered in Vertex AI Model Registry. Which additional step is REQUIRED to satisfy the auditability requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable VPC Service Controls around the Vertex AI endpoint to prevent unauthorized model swaps."},{"id":"b","text":"Tag each BigQuery prediction log row with the deployed model version ID (model_version_id) and configure the BigQuery dataset with a 7-year table expiration or partition expiry policy."},{"id":"c","text":"Store the model artifact in a Cloud Storage bucket with Bucket Lock (WORM) retention policy set to 7 years."},{"id":"d","text":"Enable Cloud Audit Logs for the Vertex AI API and export them to Cloud Storage with a 7-year retention policy."},{"id":"e","text":"Configure Vertex AI Model Monitoring to capture feature distributions for 7 years and correlate them to the serving endpoint."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct because auditability of which model version produced each prediction requires two things: (1) the prediction log must include the model version identifier so a specific prediction can be traced back to the exact model version, and (2) that log must be retained for the required period. Enriching the BigQuery logs with the model_version_id (available via Vertex AI's prediction logging metadata) and setting appropriate BigQuery data retention policies directly satisfies the regulatory requirement. Option A (VPC Service Controls) is a security boundary control, not an auditability mechanism. Option C protects the model artifact but doesn't link individual predictions to a version. Option D (Cloud Audit Logs) records API control-plane actions (e.g., model deployments and undeployments) but does not capture per-prediction logs tied to responses. Option E (Model Monitoring) tracks data drift statistics, not individual prediction-to-version lineage.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/log-predictions","label":"Vertex AI – Log prediction requests and responses"},{"url":"https://cloud.google.com/vertex-ai/docs/model-registry/introduction","label":"Vertex AI Model Registry – Model versioning"},{"url":"https://cloud.google.com/bigquery/docs/best-practices-storage#use_expiration_settings_to_remove_unneeded_tables_and_partitions","label":"BigQuery – Table data retention and expiration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization runs a fraud-detection model on Vertex AI online prediction. A new regulatory requirement mandates that the model version used for each prediction must be auditable for at least 7 years. Predictions are currently logged to BigQuery via Vertex AI request-response logging. Model versions are registered in Vertex AI Model Registry. Which additional step is REQUIRED to satisfy the auditability requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A media company wants to perform real-time inference on live video stream frames (30 fps, 1080p) for object detection. The model is a custom YOLO variant exported as an ONNX file. Expected concurrent streams: 200. Latency requirement: inference result within 100 ms of frame arrival. Which serving architecture on Google Cloud BEST meets these requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Import the ONNX model into Vertex AI online prediction with a standard CPU machine type and enable request batching with a max-batch-size of 200 to amortize inference cost."},{"id":"b","text":"Deploy the ONNX model on a Vertex AI online endpoint backed by GPU instances (e.g., NVIDIA T4 or A100), use NVIDIA Triton Inference Server as the serving container, enable dynamic batching, and front the endpoint with a regional external Application Load Balancer."},{"id":"c","text":"Convert the ONNX model to TensorFlow Lite and deploy it as a Cloud Run function with 1 GB memory, scaling to a maximum of 200 instances."},{"id":"d","text":"Use Vertex AI Batch Prediction with streaming input from Pub/Sub, setting a maximum latency hint of 100 ms."},{"id":"e","text":"Store the model in Cloud Storage and invoke it via a Dataflow streaming pipeline that calls a custom inference UDF on each frame."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct. Real-time video inference at 30 fps × 200 streams = 6,000 inference requests per second, each with a strict 100 ms deadline. GPU-backed Vertex AI online endpoints with Triton Inference Server natively support ONNX models, provide GPU-accelerated inference, and Triton's dynamic batching groups requests arriving within a configurable window to maximize GPU utilization while still meeting latency SLOs. A regional load balancer distributes stream traffic across healthy replicas. Option A uses CPU only, which is far too slow for 1080p YOLO inference at this throughput. Option C (Cloud Run + TFLite) has cold-start latency and memory constraints that make it unsuitable for sustained high-throughput video inference. Option D (Batch Prediction) is asynchronous and not designed for sub-100 ms latency; there is also no 'maximum latency hint' parameter in Batch Prediction. Option E (Dataflow + UDF) can work for streaming but Dataflow is not optimized for GPU-accelerated inference and introduces additional serialization overhead that risks exceeding the 100 ms budget.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/use-custom-container","label":"Vertex AI – Use custom serving containers"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/use-triton-inference-server","label":"NVIDIA Triton Inference Server on Vertex AI"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/configure-compute#gpu-types","label":"Vertex AI – GPU machine types for online prediction"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A media company wants to perform real-time inference on live video stream frames (30 fps, 1080p) for object detection. The model is a custom YOLO variant exported as an ONNX file. Expected concurrent streams: 200. Latency requirement: inference result within 100 ms of frame arrival. Which serving architecture on Google Cloud BEST meets these requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An ML engineer is deploying two versions of a ranking model to a Vertex AI endpoint. Version A is the current production model; Version B is a newly trained candidate. The business requires that no more than 5% of live traffic be exposed to Version B initially, with the ability to gradually increase the split without redeployment downtime. The endpoint must also maintain a single stable HTTPS URL for client applications. Which Vertex AI feature directly enables this pattern?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create two separate Vertex AI endpoints—one for each model version—and use a Cloud Armor policy to split traffic by IP hash."},{"id":"b","text":"Use Vertex AI traffic splitting by deploying both model versions to the same endpoint with trafficSplit set to {versionA: 95, versionB: 5}, and update the split percentage via the UpdateDeployedModel API without taking the endpoint offline."},{"id":"c","text":"Configure a Vertex AI Feature Store with two feature snapshots—one per model version—and let the online serving layer select the appropriate snapshot."},{"id":"d","text":"Deploy Version B to a separate endpoint and implement a custom canary proxy in Cloud Run that routes 5% of traffic to the new endpoint based on a random number header."},{"id":"e","text":"Use Vertex AI Experiments to create an experiment run that shadows 5% of production traffic to Version B without affecting the response returned to clients."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct. Vertex AI endpoints natively support traffic splitting across multiple deployed model versions on the same endpoint resource. The trafficSplit field accepts a map of deployedModelId to integer percentage (must sum to 100). You can update the split at any time via a PATCH call to the endpoint without redeployment, and the endpoint URL remains constant—exactly the requirements stated. Option A uses two separate endpoints, which breaks the 'single stable URL' requirement and requires client-side routing logic. Option C misuses Feature Store, which manages feature data, not model routing. Option D satisfies the functional goal but requires maintaining a custom proxy service, which adds operational complexity when the native platform feature already exists. Option E describes shadow testing (responses are not returned to clients), which is not a canary release—it doesn't satisfy the business goal of gradually exposing clients to Version B.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/traffic-splitting","label":"Vertex AI – Traffic splitting between model versions"},{"url":"https://cloud.google.com/vertex-ai/docs/reference/rest/v1/projects.locations.endpoints/patch","label":"Vertex AI REST API – projects.locations.endpoints.patch (trafficSplit)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An ML engineer is deploying two versions of a ranking model to a Vertex AI endpoint. Version A is the current production model; Version B is a newly trained candidate. The business requires that no more than 5% of live traffic be exposed to Version B initially, with the ability to gradually increase the split without redeployment downtime. The endpoint must also maintain a single stable HTTPS URL for client applications. Which Vertex AI feature directly enables this pattern?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Vertex AI online prediction endpoint serves a scikit-learn model via a custom container. Under normal load the endpoint returns predictions in ~40 ms. After a rolling update that doubled the model's input feature count, p95 latency jumped to 900 ms. Cloud Monitoring shows that container CPU utilization is at 15% and there are no OOM events. The custom container uses a synchronous Flask server with a single worker process. What is the MOST likely performance bottleneck and the correct remediation?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The model artifact is too large for the instance's local SSD; remediate by mounting a Filestore NFS share to reduce artifact load time per request."},{"id":"b","text":"Python's Global Interpreter Lock (GIL) in the single-worker Flask server is serializing all requests; remediate by switching to a multi-worker WSGI/ASGI server (e.g., Gunicorn with multiple workers or uvicorn) so that CPU cores are fully utilized and requests are handled concurrently."},{"id":"c","text":"The Vertex AI load balancer is applying request coalescing across replicas; remediate by disabling HTTP keep-alive on the endpoint."},{"id":"d","text":"The doubled feature count has triggered scikit-learn's fallback to a pure-Python prediction path; remediate by recompiling scikit-learn with AVX-512 SIMD support."},{"id":"e","text":"The custom container's health check probe is consuming CPU cycles during prediction; remediate by increasing the liveness probe interval to 300 seconds."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct. A single-worker synchronous Flask server handles one request at a time. Doubling the feature count increases per-request CPU time (even slightly), which means that when multiple concurrent requests arrive, they queue behind each other in the single process. The result is high tail latency despite low aggregate CPU utilization—because utilization is measured across all vCPUs but only one is ever busy at a time due to the single-worker architecture. Migrating to Gunicorn with multiple workers (typically 2× vCPU + 1) or an async server eliminates the queue. Option A is incorrect because scikit-learn models are loaded into memory at startup and feature count does not affect per-request disk I/O. Option C is fabricated; Vertex AI does not perform request coalescing, and disabling keep-alive would harm (not help) performance. Option D is incorrect because scikit-learn uses NumPy/Cython-compiled code paths regardless of feature count and does not have an AVX-512 recompilation requirement for correctness. Option E is incorrect because liveness probe CPU overhead is negligible and is not correlated with prediction latency.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/custom-container-requirements","label":"Vertex AI – Custom container requirements for online prediction"},{"url":"https://docs.gunicorn.org/en/stable/design.html#server-model","label":"Gunicorn – Workers and concurrency"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/use-custom-container","label":"Vertex AI – Build a custom container for online predictions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Vertex AI online prediction endpoint serves a scikit-learn model via a custom container. Under normal load the endpoint returns predictions in ~40 ms. After a rolling update that doubled the model's input feature count, p95 latency jumped to 900 ms. Cloud Monitoring shows that container CPU utilization is at 15% and there are no OOM events. The custom container uses a synchronous Flask server with a single worker process. What is the MOST likely performance bottleneck and the correct remediation?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning engineer has deployed a scikit-learn classification model to a Vertex AI Endpoint. Three weeks after deployment, the model's precision and recall metrics begin degrading noticeably. The engineer suspects feature drift but needs to confirm this using Google Cloud-native tooling without writing custom monitoring code. Which Vertex AI feature should the engineer enable and configure to automatically detect skew between the training data distribution and the distribution of features in incoming prediction requests?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Model Monitoring with training-serving skew detection, configured by supplying the training dataset URI and alert thresholds for each input feature"},{"id":"b","text":"Vertex AI Pipelines with a scheduled TFX StatisticsGen component that computes statistics on live traffic logs stored in Cloud Storage"},{"id":"c","text":"Cloud Monitoring custom metrics that ingest prediction request payloads and compare feature value histograms using Dataflow"},{"id":"d","text":"Vertex AI Experiments with automatic artifact lineage tracking to compare feature distributions across experiment runs"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI Model Monitoring supports training-serving skew detection out of the box. By pointing it at the training dataset (BigQuery table, Cloud Storage CSV/JSONL, or a Vertex AI Dataset) and setting per-feature skew thresholds, the service automatically samples live prediction traffic, computes feature statistics, compares them against the training baseline, and raises Cloud Monitoring alerts when drift exceeds configured thresholds — all without custom monitoring code. Option B requires building and scheduling a custom TFX pipeline, which is not 'without custom monitoring code.' Option C requires a custom Dataflow pipeline and manual metric ingestion. Option D (Vertex AI Experiments) tracks experiment artifacts and metrics during training runs, not live production traffic drift.$patch$, $patch$Monitoring AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/model-monitoring/overview","label":"Vertex AI Model Monitoring overview – Google Cloud"},{"url":"https://cloud.google.com/vertex-ai/docs/model-monitoring/model-monitoring-skew-drift","label":"Monitor models for training-serving skew and prediction drift – Google Cloud"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning engineer has deployed a scikit-learn classification model to a Vertex AI Endpoint. Three weeks after deployment, the model's precision and recall metrics begin degrading noticeably. The engineer suspects feature drift but needs to confirm this using Google Cloud-native tooling without writing custom monitoring code. Which Vertex AI feature should the engineer enable and configure to automatically detect skew between the training data distribution and the distribution of features in incoming prediction requests?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An ML operations team manages dozens of Vertex AI Endpoints across multiple business units. They want a centralized observability solution that: (1) captures model-level prediction latency percentiles (p50, p95, p99), (2) automatically pages an on-call engineer when p99 latency exceeds 800 ms for more than five consecutive minutes, and (3) provides a unified dashboard across all endpoints without deploying any additional infrastructure. Which combination of Google Cloud services satisfies all three requirements with the least operational overhead?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable Vertex AI system metrics export to Cloud Monitoring; create a Cloud Monitoring Alerting Policy with a metric-threshold condition on 'aiplatform.googleapis.com/prediction/online/response_latencies' filtered by endpoint; build a Cloud Monitoring dashboard; configure an Alerting Policy notification channel to PagerDuty or a Cloud Monitoring-integrated pager tool"},{"id":"b","text":"Stream prediction request logs from Vertex AI to BigQuery using Pub/Sub; write a scheduled Cloud Function that queries BigQuery for p99 latency and publishes custom metrics to Cloud Monitoring; create Cloud Monitoring alerts on those custom metrics"},{"id":"c","text":"Deploy a Prometheus server on Google Kubernetes Engine, scrape Vertex AI Endpoint metrics via a custom exporter, and use Grafana for dashboards and Alertmanager for paging"},{"id":"d","text":"Use Cloud Logging log-based metrics to extract latency values from Vertex AI prediction logs and create a distribution metric; build a Looker Studio dashboard; set up a log-based alert in Cloud Logging"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI automatically exports built-in system metrics — including 'aiplatform.googleapis.com/prediction/online/response_latencies' as a distribution metric — to Cloud Monitoring at no extra configuration cost. From there, Cloud Monitoring natively supports percentile aggregations (p50, p95, p99) on distribution metrics, threshold-based alerting policies with duration conditions (e.g., 5-minute sustained breach), multi-endpoint dashboards, and notification channels that integrate with PagerDuty, OpsGenie, email, and SMS. This satisfies all three requirements with zero additional infrastructure. Option B introduces unnecessary complexity: a Pub/Sub pipeline, BigQuery queries, and Cloud Functions just to replicate metrics that are already exported natively. Option C requires provisioning and maintaining a GKE cluster, Prometheus, a custom Vertex AI exporter, Grafana, and Alertmanager — significant operational overhead. Option D (log-based metrics) can approximate latency distributions but requires log-based alert configuration in Cloud Logging rather than the richer metric-threshold alerting available in Cloud Monitoring, and Looker Studio dashboards are not part of Cloud Monitoring's unified observability surface.$patch$, $patch$Monitoring AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/monitoring/api/metrics_gcp#gcp-aiplatform","label":"Vertex AI online prediction metrics – Cloud Monitoring metric list"},{"url":"https://cloud.google.com/monitoring/alerts/using-alerting-ui","label":"Create alerting policies for metrics – Cloud Monitoring"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/monitoring-resources","label":"Monitor Vertex AI resources with Cloud Monitoring – Google Cloud"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An ML operations team manages dozens of Vertex AI Endpoints across multiple business units. They want a centralized observability solution that: (1) captures model-level prediction latency percentiles (p50, p95, p99), (2) automatically pages an on-call engineer when p99 latency exceeds 800 ms for more than five consecutive minutes, and (3) provides a unified dashboard across all endpoints without deploying any additional infrastructure. Which combination of Google Cloud services satisfies all three requirements with the least operational overhead?$patch$);

-- PMLE-P3: 22 questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization wants to build a customer churn prediction model with minimal custom code. A data scientist has already prepared and stored the training data as a CSV file in Cloud Storage. The team wants automated feature engineering, hyperparameter tuning, and model selection without writing any training code. Which Google Cloud service should they use, and what is the correct sequence of steps to train and deploy the model?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use Vertex AI AutoML Tabular: create a dataset in Vertex AI by importing the CSV from Cloud Storage, train an AutoML Tabular model by selecting the target column, then deploy the best model to a Vertex AI Endpoint."},{"id":"b","text":"Use BigQuery ML: load the CSV into BigQuery, write a CREATE MODEL statement specifying model_type='dnn_classifier', then export the model to Cloud Storage for serving."},{"id":"c","text":"Use Vertex AI Workbench: open a managed notebook, run a scikit-learn pipeline with GridSearchCV for hyperparameter tuning, and register the best model in the Vertex AI Model Registry."},{"id":"d","text":"Use Dataflow ML: define a Beam pipeline with a TFX component that reads the CSV, applies tf.Transform for feature engineering, trains a TensorFlow model, and writes predictions to BigQuery."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI AutoML Tabular is the purpose-built low-code solution for structured/tabular data. It automates feature engineering, architecture search, hyperparameter tuning, and model selection entirely through the UI or API without any custom training code. The workflow — import data → configure AutoML training run → deploy to Endpoint — satisfies all stated requirements. BigQuery ML (option B) requires writing SQL DDL and does not fully automate feature engineering or model selection to the same degree; it also requires SQL authoring, making it higher-code. Vertex AI Workbench (option C) is a notebook environment that still requires writing scikit-learn pipeline code, which is not low-code. Dataflow ML / TFX (option D) is a high-code, pipeline-engineering approach requiring expertise in Apache Beam and TFX components.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/tabular-data/tabular-workflows/overview","label":"Vertex AI AutoML Tabular overview"},{"url":"https://cloud.google.com/vertex-ai/docs/tabular-data/classification-regression/train-model","label":"Train an AutoML model for tabular data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization wants to build a customer churn prediction model with minimal custom code. A data scientist has already prepared and stored the training data as a CSV file in Cloud Storage. The team wants automated feature engineering, hyperparameter tuning, and model selection without writing any training code. Which Google Cloud service should they use, and what is the correct sequence of steps to train and deploy the model?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A retail company stores its transaction history in BigQuery and wants to generate product recommendations for each customer without moving data out of BigQuery or writing Python/Java model training code. They require the solution to scale automatically with their BigQuery storage and allow SQL-based inference queries. Which approach best satisfies all of these constraints?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Export the BigQuery table to Cloud Storage as Parquet files, train a matrix factorization model using Vertex AI AutoML, import the model back into BigQuery using BigQuery ML's IMPORT MODEL syntax, and run SQL predictions."},{"id":"b","text":"Use BigQuery ML to create a matrix factorization model directly on the transaction data with a CREATE MODEL statement, then run ML.RECOMMEND to generate recommendations — all within BigQuery using SQL."},{"id":"c","text":"Use Vertex AI Feature Store to serve precomputed customer and item embeddings, then deploy a custom nearest-neighbor matching model on Vertex AI Matching Engine."},{"id":"d","text":"Use Dataproc to run a PySpark ALS (Alternating Least Squares) job on the BigQuery data via the BigQuery Spark connector, then write the resulting recommendations back to a BigQuery table."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$BigQuery ML supports matrix factorization models natively (CREATE MODEL ... OPTIONS(model_type='matrix_factorization')), allowing the team to train a recommendation model directly on BigQuery data using SQL — no data movement, no Python/Java code. The ML.RECOMMEND function then produces per-user recommendations entirely in SQL, and the solution scales with BigQuery automatically. Option A is incorrect because Vertex AI AutoML does not offer a matrix factorization/recommendation model type, and the IMPORT MODEL workflow adds unnecessary complexity. Option C requires significant engineering work — Vertex AI Feature Store and Matching Engine are powerful but are not low-code and require Python SDK usage and infrastructure setup. Option D uses Dataproc with PySpark, which involves writing custom code and managing a Spark cluster, violating the no-custom-code and no-data-movement constraints.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/bigquery/docs/matrix-factorization-recommendation","label":"BigQuery ML matrix factorization overview"},{"url":"https://cloud.google.com/bigquery/docs/reference/standard-sql/bigqueryml-syntax-recommend","label":"ML.RECOMMEND function in BigQuery ML"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A retail company stores its transaction history in BigQuery and wants to generate product recommendations for each customer without moving data out of BigQuery or writing Python/Java model training code. They require the solution to scale automatically with their BigQuery storage and allow SQL-based inference queries. Which approach best satisfies all of these constraints?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A manufacturing company wants to detect visual defects on an assembly line using image classification. They have 5,000 labeled images stored in Cloud Storage, but no in-house ML engineers. They need a solution that (1) requires no model architecture design or custom training code, (2) produces a REST endpoint for real-time inference, and (3) allows them to iteratively improve the model by adding new labeled images. A junior developer will manage the entire lifecycle. Which solution is the most appropriate?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use Vertex AI AutoML Image Classification: create a Vertex AI dataset, import and label the images, launch an AutoML training job selecting the 'Best model quality' optimization objective, and deploy the trained model to a Vertex AI Endpoint for online prediction."},{"id":"b","text":"Use Cloud Vision API's AutoML Vision (now Vertex AI) custom model feature within the Google Cloud Console, train using the pre-built EfficientNet backbone by specifying a custom dataset, and expose the model via the Vision API product search endpoint."},{"id":"c","text":"Use Vertex AI Workbench to fine-tune a pre-trained ResNet-50 model from TensorFlow Hub using a Keras training loop, register the model in Vertex AI Model Registry, and deploy it to a Vertex AI Endpoint."},{"id":"d","text":"Use Cloud Run to host a containerized TensorFlow Serving instance, train a MobileNet model locally using the 5,000 images, push the SavedModel artifact to Cloud Storage, and configure Cloud Run to load it on startup."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI AutoML Image Classification is the canonical low-code solution for image classification on Google Cloud. It handles neural architecture search, transfer learning, data augmentation, and hyperparameter optimization internally — the junior developer only needs to supply labeled images and configure the training job through the Console or a minimal API call. Deployment to a Vertex AI Endpoint provides a managed REST endpoint for real-time inference, and retraining with new images is a straightforward re-run of the AutoML training job against the updated dataset. Option B is a plausible distractor but conflates the legacy AutoML Vision product naming and incorrectly routes inference through the Vision API product search endpoint, which is designed for similarity search rather than classification serving. Option C (fine-tuning ResNet-50 in Keras) requires writing and managing a custom training loop — not a low-code approach suitable for a junior developer. Option D requires containerization, local training, and infrastructure management on Cloud Run, which is a high-code DevOps-heavy approach.$patch$, $patch$Architecting low-code AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/image-data/classification/overview","label":"Vertex AI AutoML Image Classification overview"},{"url":"https://cloud.google.com/vertex-ai/docs/image-data/classification/train-model","label":"Train an AutoML model for image classification"},{"url":"https://cloud.google.com/vertex-ai/docs/general/deployment","label":"Deploy a model to an endpoint (Vertex AI)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A manufacturing company wants to detect visual defects on an assembly line using image classification. They have 5,000 labeled images stored in Cloud Storage, but no in-house ML engineers. They need a solution that (1) requires no model architecture design or custom training code, (2) produces a REST endpoint for real-time inference, and (3) allows them to iteratively improve the model by adding new labeled images. A junior developer will manage the entire lifecycle. Which solution is the most appropriate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization has multiple data science teams working on different ML projects, all using Vertex AI. A newly appointed ML platform lead wants to enforce a policy where every dataset artifact and trained model must be traceable back to its originating pipeline run, and this lineage information must be queryable by downstream consumers without granting them direct pipeline access. Which Vertex AI capability should the platform lead leverage to satisfy this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Feature Store, storing all dataset and model metadata as features with serving configs"},{"id":"b","text":"Vertex AI ML Metadata (Vertex ML Metadata) with lineage tracking across artifacts, executions, and contexts"},{"id":"c","text":"Vertex AI Model Registry with custom model labels and IAM-restricted access policies"},{"id":"d","text":"Cloud Data Catalog with tag templates applied to each BigQuery dataset used in training"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex ML Metadata is the purpose-built service for recording and querying artifact lineage in Vertex AI. It stores artifacts (datasets, models, metrics), executions (pipeline steps), and contexts (pipeline runs), and exposes lineage graphs that downstream consumers can query via the Vertex AI API or the Cloud Console without needing access to the underlying pipeline configuration. Feature Store (a) manages structured feature data for serving, not pipeline lineage. Model Registry (c) provides a model catalog and versioning, but does not trace lineage back through datasets and pipeline runs in a queryable graph. Data Catalog (d) applies metadata tags to BigQuery assets but does not capture end-to-end ML pipeline lineage across Vertex resources.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/ml-metadata/introduction","label":"Vertex AI ML Metadata overview"},{"url":"https://cloud.google.com/vertex-ai/docs/pipelines/record-metadata","label":"Vertex AI Pipelines – Recording metadata and artifacts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization has multiple data science teams working on different ML projects, all using Vertex AI. A newly appointed ML platform lead wants to enforce a policy where every dataset artifact and trained model must be traceable back to its originating pipeline run, and this lineage information must be queryable by downstream consumers without granting them direct pipeline access. Which Vertex AI capability should the platform lead leverage to satisfy this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A financial services company has two separate ML teams: the Risk team and the Fraud team. Both teams need to consume a shared set of customer transaction features (e.g., 30-day spend velocity, merchant category ratios) with guaranteed low-latency online serving. Data engineering produces these features daily via batch pipelines. The company wants to avoid duplicating feature computation and ensure both teams always read from the same feature values at serving time. What is the MOST appropriate architecture to achieve this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Store feature values in Cloud Spanner and have each team query it independently with their own service accounts"},{"id":"b","text":"Create a central Vertex AI Feature Store with a shared entity type for customers; data engineering ingests daily batch features, and both teams perform online serving reads from the same feature store"},{"id":"c","text":"Export features to a shared BigQuery table and have each team's model query BigQuery at inference time using the BigQuery ML PREDICT function"},{"id":"d","text":"Use Pub/Sub to stream feature values to each team's dedicated Memorystore Redis cluster, with data engineering publishing updates once per day"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Feature Store is designed precisely for this cross-team feature sharing pattern. A single entity type (e.g., 'customer') holds all transaction features; data engineering writes to it via batch ingestion once per day, and any number of teams can read from it with low-latency online serving reads. This eliminates duplicate feature computation and guarantees serving consistency. Cloud Spanner (a) is a relational database not optimised for ML feature serving patterns and adds operational overhead. BigQuery at inference time (c) introduces high latency (seconds) unsuitable for online fraud or risk scoring. The Pub/Sub + Redis approach (d) could achieve low latency but duplicates infrastructure per team and creates divergence risks between Redis clusters.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/overview","label":"Vertex AI Feature Store overview"},{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/create-featurestore","label":"Sharing features across teams with Vertex AI Feature Store"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A financial services company has two separate ML teams: the Risk team and the Fraud team. Both teams need to consume a shared set of customer transaction features (e.g., 30-day spend velocity, merchant category ratios) with guaranteed low-latency online serving. Data engineering produces these features daily via batch pipelines. The company wants to avoid duplicating feature computation and ensure both teams always read from the same feature values at serving time. What is the MOST appropriate architecture to achieve this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An ML engineer is setting up a collaborative model development workflow on Vertex AI Workbench for a team of five data scientists. The team lead requires that: (1) all notebook environments are reproducible and version-controlled, (2) heavy GPU training jobs must not block interactive exploration on the same instance, and (3) the team must be able to share notebooks without sharing credentials. Which combination of practices BEST satisfies all three requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use a single Vertex AI Workbench User-Managed Notebook instance with a shared service account, store notebooks in a local directory, and run training as subprocess calls within the notebook kernel"},{"id":"b","text":"Use Vertex AI Workbench Managed Notebooks with a Cloud Storage-backed notebook source repository; submit training jobs to Vertex AI Training as custom jobs, and share notebooks via Cloud Storage IAM-controlled buckets"},{"id":"c","text":"Deploy a self-managed JupyterHub on a GKE cluster, mount a shared NFS volume for notebooks, and run distributed training directly on the GKE nodes to keep everything within one cluster"},{"id":"d","text":"Use separate Vertex AI Workbench User-Managed Notebook instances per data scientist, sync notebooks manually via email, and use local GPU quotas for training"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Workbench Managed Notebooks provide managed, reproducible environments with scheduler and executor integrations. Storing notebook sources in Cloud Storage (or a git-backed source such as Cloud Source Repositories) satisfies version control and reproducibility. Submitting training to Vertex AI Training as custom jobs decouples heavy GPU workloads from interactive exploration instances. Sharing notebooks via IAM-controlled Cloud Storage buckets allows teammates to access notebook files without exchanging credentials. Option (a) violates credential isolation by sharing a single service account interactively and blocks the kernel during training. Option (c) adds significant operational overhead and does not leverage managed Vertex AI services. Option (d) has no shared source of truth and relies on manual sync.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/workbench/managed/introduction","label":"Vertex AI Workbench Managed Notebooks overview"},{"url":"https://cloud.google.com/vertex-ai/docs/training/create-custom-job","label":"Submit a training job to Vertex AI Training"},{"url":"https://cloud.google.com/vertex-ai/docs/general/access-control","label":"Control access to Vertex AI resources with IAM"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An ML engineer is setting up a collaborative model development workflow on Vertex AI Workbench for a team of five data scientists. The team lead requires that: (1) all notebook environments are reproducible and version-controlled, (2) heavy GPU training jobs must not block interactive exploration on the same instance, and (3) the team must be able to share notebooks without sharing credentials. Which combination of practices BEST satisfies all three requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A retail company maintains a central Vertex AI Model Registry used by three product teams. The MLOps team wants to implement a governance process where: a model version can only be promoted from the 'staging' alias to the 'production' alias after a designated approver has reviewed evaluation metrics stored alongside the model, and all promotion events must be auditable. Which approach BEST implements this governance workflow using native Google Cloud capabilities?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Write a Cloud Function that runs on a fixed schedule, reads model evaluation metrics from a spreadsheet maintained by the approver, and updates the model alias if a certain cell is marked 'APPROVED'"},{"id":"b","text":"Use Vertex AI Model Registry aliases to tag versions; implement an approval step inside a Vertex AI Pipeline using a manual approval component that pauses execution, records the approval decision as a pipeline run metadata entry, and then calls the Model Registry API to assign the 'production' alias; rely on Cloud Audit Logs to capture all alias-change API calls"},{"id":"c","text":"Require each team to email the MLOps team with evaluation results; the MLOps team manually runs a gcloud CLI command to update the model alias, satisfying auditability through email archives"},{"id":"d","text":"Store evaluation metrics in BigQuery, create a Looker Studio dashboard for approvers, and have approvers send a Pub/Sub message to trigger a Cloud Run service that updates the model alias"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Model Registry supports aliases (such as 'staging' and 'production') that can be programmatically reassigned via the API. Embedding an approval gate inside a Vertex AI Pipeline—using a pause/human-approval component—keeps the entire promotion workflow within the ML system, records the approval decision as ML Metadata, and triggers alias assignment only after approval. Cloud Audit Logs automatically capture every Vertex AI API call (including alias updates), providing a tamper-evident audit trail. Option (a) is fragile, relies on a spreadsheet, and is not auditable in a reliable way. Option (c) is entirely manual and uses email archives rather than system audit logs. Option (d) introduces unnecessary complexity (Pub/Sub + Cloud Run) outside of the Vertex AI ecosystem and does not natively record the approval decision in ML Metadata.$patch$, $patch$Collaborating within and across teams to manage data and models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/model-registry/manage-models","label":"Vertex AI Model Registry – Manage model versions and aliases"},{"url":"https://cloud.google.com/vertex-ai/docs/pipelines/build-pipeline","label":"Vertex AI Pipelines – Create a pipeline with a manual approval step"},{"url":"https://cloud.google.com/vertex-ai/docs/general/audit-logging","label":"Cloud Audit Logs for Vertex AI"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A retail company maintains a central Vertex AI Model Registry used by three product teams. The MLOps team wants to implement a governance process where: a model version can only be promoted from the 'staging' alias to the 'production' alias after a designated approver has reviewed evaluation metrics stored alongside the model, and all promotion events must be auditable. Which approach BEST implements this governance workflow using native Google Cloud capabilities?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data science team has built a TensorFlow prototype model on a local machine using a small sample dataset. They now need to scale training to the full 500 GB dataset stored in Cloud Storage. The team wants to minimize code changes while maximizing training throughput. Which approach should they use to distribute training across multiple accelerators on Vertex AI?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Refactor the model to use tf.data.Dataset with manual sharding logic and submit a custom training job with a single large n1-highmem-96 instance."},{"id":"b","text":"Wrap the model's compile and fit calls inside a tf.distribute.MirroredStrategy scope and submit a Vertex AI custom training job with a multi-GPU machine type."},{"id":"c","text":"Convert the TensorFlow model to ONNX format and run distributed training using Dataflow with the Apache Beam ML transforms."},{"id":"d","text":"Use Vertex AI AutoML Tabular to retrain the model, providing the Cloud Storage dataset path as the training source."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$tf.distribute.MirroredStrategy enables synchronous data-parallel training across multiple GPUs on a single machine with minimal code changes — only the strategy scope wrapping is required. Vertex AI custom training jobs natively support multi-GPU machine types (e.g., a2-highgpu-8g), making this the lowest-friction path from a local prototype to scaled training. Option A ignores distribution across multiple devices. Option C introduces an unnecessary format conversion and Dataflow is not designed for model training. Option D abandons the custom model entirely in favor of AutoML.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/distributed-training","label":"Vertex AI – Distributed training overview"},{"url":"https://www.tensorflow.org/api_docs/python/tf/distribute/MirroredStrategy","label":"TensorFlow – tf.distribute.MirroredStrategy"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A data science team has built a TensorFlow prototype model on a local machine using a small sample dataset. They now need to scale training to the full 500 GB dataset stored in Cloud Storage. The team wants to minimize code changes while maximizing training throughput. Which approach should they use to distribute training across multiple accelerators on Vertex AI?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning engineer is migrating a PyTorch training script from a Jupyter notebook to a production-grade Vertex AI custom training job. The script currently hardcodes hyperparameters and writes checkpoints to the local filesystem. Which combination of changes is most important to make the script production-ready on Vertex AI?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Replace hardcoded hyperparameters with argparse arguments, write checkpoints to the AIP_MODEL_DIR environment variable path in Cloud Storage, and package the script as a Python source distribution."},{"id":"b","text":"Replace hardcoded hyperparameters with environment variables read via os.environ, keep checkpoints on the local disk, and submit the notebook file directly using the Vertex AI Workbench executor."},{"id":"c","text":"Convert the script to a TensorFlow SavedModel format, use Vertex AI Pipelines to schedule the notebook, and store checkpoints in Firestore."},{"id":"d","text":"Wrap the script in a Docker container that copies the final model artifact to BigQuery and use Cloud Composer to trigger training runs."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI custom training jobs inject runtime information (including the Cloud Storage output directory) via environment variables such as AIP_MODEL_DIR. Using argparse to accept hyperparameters makes the job compatible with Vertex AI hyperparameter tuning. Writing checkpoints directly to a Cloud Storage path (via the environment variable) ensures persistence after the ephemeral training container exits. Packaging as a Python source distribution (or pre-built container) is the standard submission mechanism. Option B keeps checkpoints on ephemeral local disk, losing them after the job finishes. Option C incorrectly requires format conversion and uses Firestore unsuitably. Option D introduces unnecessary complexity with BigQuery for model artifacts.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/code-requirements#environment-variables","label":"Vertex AI – Custom training environment variables"},{"url":"https://cloud.google.com/vertex-ai/docs/training/create-python-pre-built-container","label":"Vertex AI – Packaging training application"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning engineer is migrating a PyTorch training script from a Jupyter notebook to a production-grade Vertex AI custom training job. The script currently hardcodes hyperparameters and writes checkpoints to the local filesystem. Which combination of changes is most important to make the script production-ready on Vertex AI?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A team is scaling a scikit-learn prototype to handle a 50 million-row dataset. Training on a single Vertex AI custom job instance runs out of memory. The model must remain scikit-learn compatible for downstream integration. Which strategy best addresses the memory constraint while keeping the scikit-learn interface?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Switch to BigQuery ML and retrain the model using BQML's LOGISTIC_REG option, exporting the result as a scikit-learn pipeline."},{"id":"b","text":"Use Dask-ML with a dask.dataframe to partition the dataset across a Dask cluster on Google Kubernetes Engine, leveraging its scikit-learn-compatible API for incremental fitting."},{"id":"c","text":"Enable Vertex AI's built-in data parallelism flag in the TrainingJob spec and set machineCount to 8 without any code changes."},{"id":"d","text":"Convert the scikit-learn pipeline to a TensorFlow Keras model and use tf.distribute.MultiWorkerMirroredStrategy for distributed training."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Dask-ML provides a scikit-learn-compatible API (including Incremental and Pipeline wrappers) and can partition large datasets across a cluster using Dask DataFrames, directly solving the memory constraint while preserving the team's existing interface. GKE provides a managed environment to run a Dask cluster. Option A changes the training platform entirely to BigQuery ML and cannot export a true scikit-learn model. Option C is incorrect because Vertex AI custom jobs do not have a built-in automatic data parallelism flag for scikit-learn; multi-worker distribution requires explicit code changes. Option D abandons scikit-learn entirely and requires significant refactoring.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://ml.dask.org/incremental.html","label":"Dask-ML – Incremental learning"},{"url":"https://cloud.google.com/vertex-ai/docs/training/overview","label":"Vertex AI – Training on GKE"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A team is scaling a scikit-learn prototype to handle a 50 million-row dataset. Training on a single Vertex AI custom job instance runs out of memory. The model must remain scikit-learn compatible for downstream integration. Which strategy best addresses the memory constraint while keeping the scikit-learn interface?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company's data scientists have developed a TensorFlow 2 model prototype that achieves good validation metrics on 1% of the data. Before full-scale training on Vertex AI, they need to verify that the training job will scale linearly with data volume and that GPU utilization stays above 80%. Which Vertex AI feature should they use to collect these scaling diagnostics during a trial training run?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Vertex AI Experiments with autologging enabled, comparing throughput metrics across runs with increasing dataset fractions."},{"id":"b","text":"Vertex AI Model Monitoring configured with skew detection thresholds on the training data distribution."},{"id":"c","text":"Cloud Profiler attached to the training container to capture CPU flame graphs across data volume checkpoints."},{"id":"d","text":"Vertex AI TensorBoard with the Trace Viewer plugin to inspect input pipeline bottlenecks, alongside Cloud Monitoring GPU utilization metrics for the training VM."}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Vertex AI TensorBoard integrates natively with TensorFlow and provides the Trace Viewer, which visualizes the tf.data input pipeline and helps identify starvation or bottlenecks that would limit GPU utilization. Cloud Monitoring exposes GPU utilization metrics for Compute Engine instances used by Vertex AI training jobs, directly answering whether GPUs are above 80%. Together these tools provide both pipeline throughput and hardware utilization visibility. Option A (Experiments) tracks metric values across runs but does not provide low-level GPU utilization or pipeline trace data. Option B (Model Monitoring) is for post-deployment data drift, not training diagnostics. Option C (Cloud Profiler) targets CPU profiling in application code, not GPU utilization or data pipeline throughput.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/experiments/tensorboard-overview","label":"Vertex AI TensorBoard overview"},{"url":"https://cloud.google.com/monitoring/api/metrics_gcp#gcp-compute","label":"Cloud Monitoring – GPU metrics for Compute Engine"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company's data scientists have developed a TensorFlow 2 model prototype that achieves good validation metrics on 1% of the data. Before full-scale training on Vertex AI, they need to verify that the training job will scale linearly with data volume and that GPU utilization stays above 80%. Which Vertex AI feature should they use to collect these scaling diagnostics during a trial training run?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning team is preparing to scale a prototype recommendation model for production training on Vertex AI. The model will be trained on a 2 TB sparse feature dataset stored in Cloud Storage as TFRecord files. The team observes that GPU utilization fluctuates between 20%–40% during test runs. What is the most likely root cause, and which tf.data optimization should be applied first?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The model graph is too large for the GPU memory; apply tf.data.Dataset.cache() to reduce repeated computation of static graph nodes."},{"id":"b","text":"The input pipeline is CPU-bound and cannot feed data fast enough; apply tf.data.Dataset.prefetch(tf.data.AUTOTUNE) combined with parallel interleave and parallel map to overlap data preprocessing with GPU compute."},{"id":"c","text":"The TFRecord files are too large; split them into smaller shards and use tf.data.Dataset.shard() to restrict each worker to a single shard."},{"id":"d","text":"The GPU driver version is incompatible with TensorFlow; upgrade the base container image to the latest deep learning container before applying any tf.data changes."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Low and fluctuating GPU utilization during training on large datasets is a classic symptom of an input pipeline bottleneck: the GPU waits idle while the CPU reads, decompresses, and preprocesses batches. The recommended remedy is to pipeline data loading with compute using tf.data.Dataset.prefetch(tf.data.AUTOTUNE), use tf.data.TFRecordDataset with num_parallel_reads=tf.data.AUTOTUNE, and apply tf.data.Dataset.map() with num_parallel_calls=tf.data.AUTOTUNE. This overlaps preprocessing with model execution. Option A incorrectly attributes the issue to graph size; cache() is useful for repeated epochs of small datasets but does not solve a throughput bottleneck on 2 TB data. Option C misidentifies shard size as the root cause; sharding is for multi-worker distribution, not single-machine throughput. Option D is a driver/compatibility issue that would typically manifest as errors, not low utilization.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://www.tensorflow.org/guide/data_performance","label":"TensorFlow – tf.data performance guide"},{"url":"https://cloud.google.com/vertex-ai/docs/training/training-best-practices","label":"Vertex AI – Training best practices"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning team is preparing to scale a prototype recommendation model for production training on Vertex AI. The model will be trained on a 2 TB sparse feature dataset stored in Cloud Storage as TFRecord files. The team observes that GPU utilization fluctuates between 20%–40% during test runs. What is the most likely root cause, and which tf.data optimization should be applied first?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An ML engineer is scaling a prototype model to use Vertex AI hyperparameter tuning. The training job uses a custom TensorFlow container. The engineer needs the hyperparameter tuning service to minimize validation loss across 50 trials. After reviewing the job configuration, which requirement is missing that will prevent the tuning service from functioning correctly?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The training container must be converted to a pre-built container rather than a custom container image."},{"id":"b","text":"The training script must report the metric to the Vertex AI hyperparameter tuning service using the hypertune library (or equivalent) by calling report_hyperparameter_tuning_metric() at the end of each epoch or trial."},{"id":"c","text":"All 50 trials must be set to run sequentially (parallelism=1) so the tuning service can use results from previous trials before starting new ones."},{"id":"d","text":"The hyperparameter search space must be defined inside the training script using a config file rather than in the HyperparameterTuningJob API spec."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Hyperparameter Tuning requires the training script to explicitly report the optimization metric back to the service at each trial. This is done using the google-cloud-hypertune library, which calls report_hyperparameter_tuning_metric() with the metric tag and value. Without this call, the tuning service has no signal to guide Bayesian optimization or grid search and trials will fail or produce no useful results. Option A is incorrect: custom containers are fully supported for hyperparameter tuning. Option C is incorrect: parallelism > 1 is allowed and common; sequential trials are not required (though Bayesian optimization benefits from some sequential ordering). Option D is incorrect: the search space is defined in the HyperparameterTuningJob API spec, not inside the training script.$patch$, $patch$Scaling prototypes into ML models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/training/hyperparameter-tuning-overview","label":"Vertex AI – Hyperparameter tuning overview"},{"url":"https://cloud.google.com/vertex-ai/docs/training/hyperparameter-tuning-overview#capture_training_metrics","label":"Vertex AI – Using the hypertune library"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An ML engineer is scaling a prototype model to use Vertex AI hyperparameter tuning. The training job uses a custom TensorFlow container. The engineer needs the hyperparameter tuning service to minimize validation loss across 50 trials. After reviewing the job configuration, which requirement is missing that will prevent the tuning service from functioning correctly?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team has deployed a TensorFlow 2 image classification model on Vertex AI Prediction using an n1-standard-4 machine type. During a promotional event, traffic spikes 10x within minutes, causing HTTP 429 errors. You need a solution that automatically handles sudden traffic bursts with minimal latency impact and no manual intervention. What should you do?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable autoscaling on the Vertex AI Endpoint by setting minReplicaCount to 2 and maxReplicaCount to 20, and configure a traffic-based scaling policy."},{"id":"b","text":"Manually increase the number of deployed model replicas before each known traffic spike by updating the DeployedModel resource."},{"id":"c","text":"Switch from Vertex AI Prediction to Cloud Run and deploy the model as a containerized Flask app with Cloud Run's concurrency settings."},{"id":"d","text":"Use Vertex AI Batch Prediction instead of online prediction to handle the increased load by queuing requests asynchronously."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI Prediction supports autoscaling through the minReplicaCount and maxReplicaCount parameters on a DeployedModel. When traffic increases, the service automatically provisions additional replicas up to maxReplicaCount, handling burst traffic without manual intervention and with low latency. Option B requires manual effort and does not handle unexpected spikes. Option C introduces significant architectural change and complexity without a clear latency benefit. Option D (Batch Prediction) is designed for high-throughput offline inference, not low-latency online serving, so it would not address the HTTP 429 errors during a real-time event.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/configure-compute#autoscaling","label":"Vertex AI – Configure autoscaling for online prediction"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team has deployed a TensorFlow 2 image classification model on Vertex AI Prediction using an n1-standard-4 machine type. During a promotional event, traffic spikes 10x within minutes, causing HTTP 429 errors. You need a solution that automatically handles sudden traffic bursts with minimal latency impact and no manual intervention. What should you do?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You are serving a large 7-billion-parameter generative text model on Vertex AI using a custom container. The model requires 40 GB of GPU memory. You want the most cost-effective GPU configuration that fits the model in a single node and supports Vertex AI online prediction. Which machine and accelerator configuration should you choose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"n1-standard-8 with 4 x NVIDIA T4 GPUs (64 GB total VRAM)."},{"id":"b","text":"a2-highgpu-1g with 1 x NVIDIA A100 40 GB GPU."},{"id":"c","text":"n1-standard-8 with 1 x NVIDIA V100 16 GB GPU."},{"id":"d","text":"a2-highgpu-2g with 2 x NVIDIA A100 40 GB GPUs (80 GB total VRAM)."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The a2-highgpu-1g machine type pairs with a single NVIDIA A100 40 GB GPU, which exactly meets the 40 GB VRAM requirement and is the most cost-effective single-node option because it avoids paying for a second A100. Option A (4 x T4) provides 64 GB total VRAM but T4 cards do not support NVLink, so tensor-parallel inference across multiple T4s adds coordination overhead and higher cost. Option C (1 x V100 16 GB) is insufficient—16 GB < 40 GB. Option D (2 x A100 = 80 GB) exceeds requirements and is more expensive than Option B.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/configure-compute#gpu-compatibility-chart","label":"Vertex AI – GPU availability for online prediction"},{"url":"https://cloud.google.com/compute/docs/gpus#a2-vms","label":"Google Cloud – A2 machine family"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You are serving a large 7-billion-parameter generative text model on Vertex AI using a custom container. The model requires 40 GB of GPU memory. You want the most cost-effective GPU configuration that fits the model in a single node and supports Vertex AI online prediction. Which machine and accelerator configuration should you choose?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A retail company runs an online prediction service on Vertex AI. The model artifact is stored in Cloud Storage. After a scheduled monthly retraining pipeline completes, you need the updated model to receive 100% of production traffic only after it passes an evaluation threshold (AUC-ROC ≥ 0.92). If it fails, the previous model version must continue serving. Which serving strategy best meets these requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Deploy both model versions to the same Vertex AI Endpoint and use traffic splitting to route 0% traffic to the new model until evaluation passes, then shift to 100%."},{"id":"b","text":"Delete the existing Vertex AI Endpoint and create a new one with the updated model after evaluation passes."},{"id":"c","text":"Deploy the new model to a separate Vertex AI Endpoint behind a Cloud Load Balancer and use URL routing to switch traffic."},{"id":"d","text":"Use Vertex AI Batch Prediction to evaluate the new model and, if it passes, overwrite the existing deployed model artifact in place."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Vertex AI Endpoints support traffic splitting across multiple deployed model versions, allowing you to allocate 0% to the new model while evaluation runs. If the AUC-ROC threshold is met, you update the split to 100% for the new model and 0% for the old one—without downtime. The old model remains deployed and can immediately resume serving if the new model fails. Option B introduces downtime during endpoint deletion and recreation. Option C adds unnecessary infrastructure complexity. Option D (overwriting artifacts in place) bypasses safe deployment practices and does not preserve the fallback model.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/traffic-splitting","label":"Vertex AI – Traffic splitting between model versions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A retail company runs an online prediction service on Vertex AI. The model artifact is stored in Cloud Storage. After a scheduled monthly retraining pipeline completes, you need the updated model to receive 100% of production traffic only after it passes an evaluation threshold (AUC-ROC ≥ 0.92). If it fails, the previous model version must continue serving. Which serving strategy best meets these requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your online prediction service processes user clickstream data in real time. The model's median latency is 120 ms but the p99 latency is 2,400 ms—far exceeding the SLA of 500 ms. Profiling reveals the bottleneck is Python-based feature preprocessing running inside the prediction container. You want to reduce p99 latency to under 500 ms with the least refactoring effort. What should you do?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Move the feature preprocessing logic into a Dataflow streaming pipeline that writes transformed features to a Feature Store online serving endpoint, and update the model container to read from Feature Store at prediction time."},{"id":"b","text":"Rewrite the preprocessing code in C++ and compile it as a shared library loaded by the prediction container."},{"id":"c","text":"Use Vertex AI Feature Store to precompute and cache entity features so the prediction container retrieves already-transformed values with single-digit millisecond lookups instead of recomputing them per request."},{"id":"d","text":"Increase the number of CPU cores on the prediction node to reduce per-request preprocessing time through parallelism."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Vertex AI Feature Store's online serving layer is an optimized, low-latency key-value store that returns precomputed feature values in single-digit milliseconds. By offloading expensive preprocessing to an offline or streaming ingestion job and storing results in Feature Store, the prediction container only needs a fast lookup—eliminating the preprocessing bottleneck. This requires minimal refactoring of the model container. Option A also uses Feature Store but routes through Dataflow at prediction time, adding streaming latency rather than removing it. Option B requires significant engineering effort and is not the least-refactoring path. Option D (more CPUs) may reduce median latency but does not address tail-latency spikes caused by preprocessing complexity.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/featurestore/overview","label":"Vertex AI Feature Store – Overview and online serving"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your online prediction service processes user clickstream data in real time. The model's median latency is 120 ms but the p99 latency is 2,400 ms—far exceeding the SLA of 500 ms. Profiling reveals the bottleneck is Python-based feature preprocessing running inside the prediction container. You want to reduce p99 latency to under 500 ms with the least refactoring effort. What should you do?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You need to serve a scikit-learn regression model with a custom Python prediction routine that runs pre- and post-processing logic not supported by the built-in scikit-learn container. The solution must use Vertex AI online prediction, support model versioning, and avoid managing container image builds in CI/CD pipelines. Which approach should you use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Build a custom Docker image that includes the scikit-learn model and preprocessing logic, push it to Artifact Registry, and deploy it as a custom container on a Vertex AI Endpoint."},{"id":"b","text":"Use Vertex AI Custom Prediction Routines (CPR) to define a Predictor class with preprocess() and postprocess() methods, then let Vertex AI build and manage the container image automatically."},{"id":"c","text":"Deploy the model on Cloud Run using a Flask wrapper and invoke it via HTTP from a Vertex AI pipeline."},{"id":"d","text":"Export the preprocessing logic as a separate Cloud Function and chain it with the Vertex AI built-in scikit-learn container using Pub/Sub."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Vertex AI Custom Prediction Routines (CPR) allow ML engineers to define a Python Predictor class with preprocess(), predict(), and postprocess() methods. Vertex AI automatically packages this code into a container image and manages the image lifecycle, removing the need to write or maintain Dockerfiles in CI/CD pipelines. This satisfies all stated requirements: custom logic, online prediction, model versioning via Model Registry, and no manual container builds. Option A works but requires manual Dockerfile management—violating the 'avoid managing container image builds' constraint. Option C moves the model outside Vertex AI's managed serving layer, losing versioning benefits. Option D introduces event-driven fan-out complexity and adds latency for a synchronous prediction use case.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/custom-prediction-routines","label":"Vertex AI – Custom prediction routines"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You need to serve a scikit-learn regression model with a custom Python prediction routine that runs pre- and post-processing logic not supported by the built-in scikit-learn container. The solution must use Vertex AI online prediction, support model versioning, and avoid managing container image builds in CI/CD pipelines. Which approach should you use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your company wants to expose a Vertex AI online prediction endpoint to external third-party partners over the internet while ensuring that only authenticated partner systems with a valid service account can invoke the endpoint. Internal Vertex AI pipelines must also be able to call the endpoint without additional configuration. Which access control setup satisfies both requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Make the Vertex AI Endpoint public and implement an API key check inside the prediction container's preprocessing logic."},{"id":"b","text":"Grant partner service accounts the roles/aiplatform.user IAM role on the Vertex AI Endpoint resource, require partners to obtain short-lived OAuth 2.0 tokens via Workload Identity Federation, and use VPC Service Controls to restrict access from unauthorized networks."},{"id":"c","text":"Place the Vertex AI Endpoint behind an internal HTTP(S) Load Balancer and provide partners with a VPN tunnel to the VPC."},{"id":"d","text":"Use a Cloud Armor security policy attached to an external HTTP(S) Load Balancer to whitelist partner IP ranges, forwarding requests to the Vertex AI Endpoint."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Granting roles/aiplatform.user to partner service accounts enforces IAM-based authentication at the Google API layer, ensuring only authorized principals can call the endpoint. Workload Identity Federation allows external service accounts to impersonate Google service accounts and obtain short-lived OAuth 2.0 tokens without long-lived key files—meeting the 'valid service account' requirement securely. VPC Service Controls add a perimeter defense to prevent data exfiltration and unauthorized network access. Internal Vertex AI pipelines already authenticate using the project's default service account and are unaffected. Option A is insecure (API keys in custom code are not as robust as IAM). Option C requires VPN provisioning and limits scalability for many partners. Option D uses IP-allowlisting which is weaker than identity-based authentication and does not satisfy 'valid service account' requirement.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/general/access-control","label":"Vertex AI – Access control for prediction endpoints"},{"url":"https://cloud.google.com/iam/docs/workload-identity-federation","label":"Google Cloud – Workload Identity Federation"},{"url":"https://cloud.google.com/vpc-service-controls/docs/overview","label":"VPC Service Controls overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your company wants to expose a Vertex AI online prediction endpoint to external third-party partners over the internet while ensuring that only authenticated partner systems with a valid service account can invoke the endpoint. Internal Vertex AI pipelines must also be able to call the endpoint without additional configuration. Which access control setup satisfies both requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You have a real-time fraud detection model deployed on Vertex AI online prediction. The average request rate is 500 RPS but spikes to 4,000 RPS during weekday mornings. Each prediction takes ~80 ms of compute. You notice that during spikes, many requests are queued and latency climbs to over 3 seconds. Your team wants to absorb the spike gracefully, keep p95 latency under 300 ms, and minimize idle infrastructure cost during off-peak hours. Which combination of configurations best addresses these goals?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Set minReplicaCount=8 and maxReplicaCount=8 (fixed fleet) to ensure capacity is always available; use a large machine type to handle concurrency."},{"id":"b","text":"Set minReplicaCount=1 and maxReplicaCount=16 with a target CPU utilization of 60%, and enable request-based autoscaling metrics to scale out quickly before queuing builds."},{"id":"c","text":"Set minReplicaCount=2 and maxReplicaCount=16, configure scale-out based on the requestsPerSecondPerReplica metric targeting ~250 RPS per replica, and set a cooldown period of 30 seconds to allow fast scale-in after spikes."},{"id":"d","text":"Offload peak traffic to Vertex AI Batch Prediction and return results via a Pub/Sub notification to the calling application."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Setting minReplicaCount=2 ensures at least two replicas are always warm, handling the baseline 500 RPS (250 RPS each) with no cold-start latency. maxReplicaCount=16 provides headroom for 4,000 RPS (250 RPS × 16 = 4,000). Scaling on requestsPerSecondPerReplica is the most direct metric for this use case—it triggers scale-out before CPU saturation causes queuing, keeping p95 latency under 300 ms. A 30-second cooldown is aggressive enough to reduce idle replicas quickly after the morning spike, minimizing cost. Option A (fixed fleet of 8) wastes money during off-peak hours when 2 replicas suffice. Option B uses CPU utilization which lags behind request rate changes, allowing queues to build before scaling responds. Option D (batch prediction) introduces asynchronous latency unsuitable for real-time fraud detection.$patch$, $patch$Serving and scaling models$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/configure-compute#autoscaling-metrics","label":"Vertex AI – Autoscaling metrics for online prediction"},{"url":"https://cloud.google.com/vertex-ai/docs/predictions/online-prediction-performance","label":"Vertex AI – Online prediction performance and scaling best practices"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You have a real-time fraud detection model deployed on Vertex AI online prediction. The average request rate is 500 RPS but spikes to 4,000 RPS during weekday mornings. Each prediction takes ~80 ms of compute. You notice that during spikes, many requests are queued and latency climbs to over 3 seconds. Your team wants to absorb the spike gracefully, keep p95 latency under 300 ms, and minimize idle infrastructure cost during off-peak hours. Which combination of configurations best addresses these goals?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your team has deployed a binary classification model on Vertex AI Endpoints to predict customer churn. After several weeks in production, the model's precision and recall metrics, tracked via Vertex AI Model Monitoring, have degraded significantly even though the serving infrastructure shows no anomalies. A data scientist suspects the root cause is a shift in the statistical distribution of the 'account_tenure_days' and 'monthly_spend_usd' input features. Which Vertex AI Model Monitoring alert type should be configured to directly detect this condition, and what is the underlying statistical method it uses by default?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Prediction drift monitoring using the Jensen-Shannon divergence to compare the distribution of model output scores between the training baseline and recent prediction requests."},{"id":"b","text":"Feature attribution drift monitoring using Shapley values to measure changes in the relative contribution of each feature to the model's predictions over time."},{"id":"c","text":"Feature skew detection using the L-infinity norm to compare the statistical distribution of input features at serving time against the training data baseline stored in BigQuery or Cloud Storage."},{"id":"d","text":"Custom metric monitoring using Cloud Monitoring and a user-defined Prometheus scrape target to track the mean and standard deviation of incoming feature values against hard-coded thresholds."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Vertex AI Model Monitoring offers two primary alerting categories: training-serving skew detection and prediction drift detection. Training-serving skew detection is specifically designed to identify when the statistical distribution of input features received at serving time diverges from the distribution of those same features in the training dataset—precisely the scenario described. By default, it uses the L-infinity norm (Chebyshev distance) as the distance metric to measure distributional divergence for numerical features. Option (a) is incorrect because prediction drift monitors the model's output distribution, not the input feature distribution, and uses Jensen-Shannon divergence. Option (b) is incorrect because feature attribution drift (using Shapley/SHAP values) measures changes in feature importance/contribution, not raw feature distribution shift—it also requires Explainable AI to be enabled and is a separate monitoring signal. Option (d) is a valid general-purpose approach but is not the purpose-built Vertex AI Model Monitoring capability for this task; it would require significant custom engineering rather than the native monitoring configuration.$patch$, $patch$Monitoring AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/model-monitoring/overview","label":"Vertex AI Model Monitoring overview – Training-serving skew detection"},{"url":"https://cloud.google.com/vertex-ai/docs/model-monitoring/using-model-monitoring","label":"Vertex AI Model Monitoring – Skew and drift detection thresholds"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your team has deployed a binary classification model on Vertex AI Endpoints to predict customer churn. After several weeks in production, the model's precision and recall metrics, tracked via Vertex AI Model Monitoring, have degraded significantly even though the serving infrastructure shows no anomalies. A data scientist suspects the root cause is a shift in the statistical distribution of the 'account_tenure_days' and 'monthly_spend_usd' input features. Which Vertex AI Model Monitoring alert type should be configured to directly detect this condition, and what is the underlying statistical method it uses by default?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A machine learning platform team manages over 40 models deployed across Vertex AI Endpoints in a production environment. They need to build a centralized observability strategy that (1) captures fine-grained, per-request prediction latency percentiles (p50, p95, p99) broken down by endpoint and model version, (2) triggers automated PagerDuty alerts when p99 latency exceeds a defined SLO threshold for more than five minutes, and (3) stores these time-series metrics for 13 months to satisfy an internal audit requirement. Which combination of Google Cloud services and configuration steps correctly fulfills ALL three requirements with the least operational overhead?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Enable Vertex AI request-response logging to BigQuery, write a scheduled Dataflow job to compute latency percentiles, push results as custom metrics to Cloud Monitoring, create a Cloud Monitoring alerting policy with a PagerDuty notification channel, and configure a BigQuery table partition expiry of 395 days."},{"id":"b","text":"Use the built-in Vertex AI Endpoint system metrics surfaced in Cloud Monitoring (google.cloud.aiplatform/endpoint/request_latencies), create a Cloud Monitoring dashboard with percentile aggregation, define an alerting policy targeting the p99 latency metric with a 5-minute duration condition and a PagerDuty notification channel, and set a Cloud Monitoring custom metric retention policy to 13 months using a Metrics Scope configuration."},{"id":"c","text":"Instrument each deployed model container with an OpenTelemetry SDK sidecar to emit latency histograms, ingest spans into Cloud Trace, build a Looker Studio dashboard to visualize p99 from Cloud Trace, configure a log-based alert in Cloud Logging for latency threshold breaches routed to PagerDuty, and retain trace data using a Cloud Logging sink to Cloud Storage with a 13-month retention bucket lifecycle rule."},{"id":"d","text":"Use the built-in Vertex AI Endpoint system metrics in Cloud Monitoring (google.cloud.aiplatform/endpoint/request_latencies), define a Cloud Monitoring alerting policy with a p99 percentile aligner, a 5-minute duration condition window, and a PagerDuty notification channel, and export the metric time-series data to a Cloud Monitoring linked BigQuery dataset to satisfy the 13-month retention requirement beyond Cloud Monitoring's default 24-month user-defined metric retention window."}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Option (d) is correct and fulfills all three requirements with minimal operational overhead. Vertex AI Endpoints automatically emit the system metric 'google.cloud.aiplatform/endpoint/request_latencies' to Cloud Monitoring, which natively supports PERCENTILE aggregation aligners (ALIGN_PERCENTILE_99, etc.) broken down by 'endpoint_id' and 'deployed_model_id' labels—satisfying requirement (1) without custom instrumentation. A Cloud Monitoring alerting policy can be configured with a p99 percentile aligner, a condition duration of 5 minutes, and a PagerDuty notification channel via an existing integration—satisfying requirement (2). For requirement (3), while Cloud Monitoring retains built-in metrics for up to 24 months, the team can use Cloud Monitoring's BigQuery metric export (linked datasets) to persist time-series data in BigQuery for exactly 13 months under a defined table expiry policy, providing audit-grade retention with no pipeline engineering. Option (a) is incorrect because routing through Dataflow adds significant engineering overhead and latency to metric availability, violating the 'least operational overhead' constraint. Option (b) is incorrect because it incorrectly states that a 'Metrics Scope configuration' can set retention to 13 months for system metrics—system metric retention is fixed by Google and cannot be extended via Metrics Scope; a BigQuery export is the correct mechanism. Option (c) is incorrect because Cloud Trace is designed for distributed tracing, not time-series metric aggregation; computing percentiles from trace spans for 40+ models would require substantial custom processing and incurs high operational overhead.$patch$, $patch$Monitoring AI solutions$patch$,
         4, $json$[{"url":"https://cloud.google.com/vertex-ai/docs/predictions/online-prediction-metrics","label":"Vertex AI – Monitor model performance with Cloud Monitoring system metrics"},{"url":"https://cloud.google.com/monitoring/alerts/concepts-indepth","label":"Cloud Monitoring – Alerting on percentile metrics"},{"url":"https://cloud.google.com/monitoring/docs/export/linked-datasets","label":"Cloud Monitoring – Export metrics to BigQuery (linked datasets)"},{"url":"https://cloud.google.com/monitoring/support/notification-options#pagerduty","label":"Cloud Monitoring – PagerDuty notification channel integration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'PMLE-P3'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A machine learning platform team manages over 40 models deployed across Vertex AI Endpoints in a production environment. They need to build a centralized observability strategy that (1) captures fine-grained, per-request prediction latency percentiles (p50, p95, p99) broken down by endpoint and model version, (2) triggers automated PagerDuty alerts when p99 latency exceeds a defined SLO threshold for more than five minutes, and (3) stores these time-series metrics for 13 months to satisfy an internal audit requirement. Which combination of Google Cloud services and configuration steps correctly fulfills ALL three requirements with the least operational overhead?$patch$);

-- MD-102-P2: 16 questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization is deploying Windows 11 to 500 new devices using Windows Autopilot. You need to ensure that during the Out-of-Box Experience (OOBE), devices are automatically joined to Azure AD and enrolled in Microsoft Intune without any user interaction for the initial setup phase. Which Autopilot deployment mode should you configure?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"User-driven mode with Azure AD join"},{"id":"b","text":"Self-deploying mode"},{"id":"c","text":"Pre-provisioning (White Glove) mode"},{"id":"d","text":"User-driven mode with Hybrid Azure AD join"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Self-deploying mode is designed for scenarios where no user interaction is required during OOBE. The device authenticates to Azure AD and enrolls in Intune automatically using the device's TPM 2.0 identity, making it ideal for kiosks, digital signage, or shared devices. User-driven modes (options A and D) require the user to authenticate during OOBE. Pre-provisioning (White Glove) mode still requires a technician or user interaction to complete the provisioning process.$patch$, $patch$Deploy Windows client$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/autopilot/self-deploying","label":"Windows Autopilot self-deploying mode"},{"url":"https://learn.microsoft.com/en-us/autopilot/windows-autopilot","label":"Overview of Windows Autopilot"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization is deploying Windows 11 to 500 new devices using Windows Autopilot. You need to ensure that during the Out-of-Box Experience (OOBE), devices are automatically joined to Azure AD and enrolled in Microsoft Intune without any user interaction for the initial setup phase. Which Autopilot deployment mode should you configure?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company is using Microsoft Deployment Toolkit (MDT) integrated with Windows Deployment Services (WDS) to deploy Windows 11 across its on-premises environment. A technician notices that PXE-booted clients are receiving a 32-bit Windows PE environment, but the target machines are all 64-bit. Which action should the administrator take to resolve this issue?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Modify the MDT task sequence to include a 64-bit WinPE boot image and update the WDS boot image entry to reference it"},{"id":"b","text":"Reinstall WDS and select the x64 architecture option during setup"},{"id":"c","text":"Change the deployment share platform setting from x86 to x64 in MDT and regenerate the deployment share"},{"id":"d","text":"Edit the DHCP scope options to add Option 67 pointing to the x64 bootmgr.efi file"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$The correct resolution is to create or import a 64-bit WinPE boot image into WDS and update the boot image entry so that PXE clients receive the x64 environment. MDT task sequences define the deployment workflow, but the WinPE boot image served by WDS must match the target architecture. Simply reinstalling WDS (option B) or changing DHCP options (option D) alone does not address the boot image architecture mismatch. Regenerating only the MDT deployment share (option C) without updating the WDS boot image reference will not resolve the PXE delivery issue.$patch$, $patch$Deploy Windows client$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/configmgr/mdt/use-the-mdt","label":"Use the Microsoft Deployment Toolkit (MDT)"},{"url":"https://learn.microsoft.com/en-us/windows-server/networking/technologies/wds/wds-overview","label":"Windows Deployment Services overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company is using Microsoft Deployment Toolkit (MDT) integrated with Windows Deployment Services (WDS) to deploy Windows 11 across its on-premises environment. A technician notices that PXE-booted clients are receiving a 32-bit Windows PE environment, but the target machines are all 64-bit. Which action should the administrator take to resolve this issue?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You are planning an in-place upgrade from Windows 10 to Windows 11 for 300 corporate laptops using Microsoft Configuration Manager (MECM). Before initiating the upgrade task sequence, you want to validate that all devices meet the Windows 11 hardware requirements. Which built-in Configuration Manager feature should you use to assess device readiness before deploying the upgrade?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Endpoint analytics in the Microsoft Intune admin center"},{"id":"b","text":"Desktop Analytics integration with Configuration Manager"},{"id":"c","text":"Configuration Manager hardware inventory with a custom MOF extension"},{"id":"d","text":"Microsoft Defender for Endpoint's device health reports"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Desktop Analytics integrates directly with Configuration Manager and provides Windows upgrade readiness assessments, compatibility insights for apps and drivers, and pilot group recommendations based on hardware and software inventory. This is the purpose-built Microsoft solution for evaluating devices before an OS upgrade deployment. Endpoint analytics (option A) focuses on device performance and user experience metrics rather than upgrade compatibility. Custom hardware inventory MOF extensions (option C) can collect data but require significant manual effort and lack built-in upgrade readiness intelligence. Microsoft Defender for Endpoint health reports (option D) are focused on security posture, not OS upgrade readiness.$patch$, $patch$Deploy Windows client$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/configmgr/desktop-analytics/overview","label":"What is Desktop Analytics?"},{"url":"https://learn.microsoft.com/en-us/mem/configmgr/osd/deploy-use/upgrade-windows-to-the-latest-version","label":"Upgrade Windows devices with Configuration Manager"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You are planning an in-place upgrade from Windows 10 to Windows 11 for 300 corporate laptops using Microsoft Configuration Manager (MECM). Before initiating the upgrade task sequence, you want to validate that all devices meet the Windows 11 hardware requirements. Which built-in Configuration Manager feature should you use to assess device readiness before deploying the upgrade?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization wants to use Windows Autopilot pre-provisioning (White Glove) to speed up device deployment for remote employees. After the technician completes the technician flow in the provisioning facility, the device is shipped to the end user. When the end user powers on the device and completes the user flow, the Enrollment Status Page (ESP) fails and rolls back. What is the MOST likely cause of this failure?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The device was not registered in Windows Autopilot before being shipped"},{"id":"b","text":"A required app or policy assigned to the user did not install successfully within the ESP timeout period"},{"id":"c","text":"The Autopilot deployment profile was configured for Self-deploying mode instead of pre-provisioning"},{"id":"d","text":"The device TPM was cleared during shipping, invalidating the Autopilot registration"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$During the user phase of Autopilot pre-provisioning, the Enrollment Status Page (ESP) tracks the installation of user-targeted apps and the application of user-targeted policies. If a required application fails to install or times out before the ESP threshold is reached, the ESP will report failure and may roll back the device. This is the most common cause of ESP failure during the user flow. Option A is incorrect because the device was already successfully registered and provisioned by the technician. Option C is incorrect as the wrong profile mode would have caused failure during the technician flow, not the user flow. Option D is unlikely because TPM-based Autopilot registration is tied to the hardware hash, not the TPM state post-provisioning.$patch$, $patch$Deploy Windows client$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/autopilot/pre-provision","label":"Windows Autopilot pre-provisioning"},{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/windows-enrollment-status","label":"Enrollment Status Page"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization wants to use Windows Autopilot pre-provisioning (White Glove) to speed up device deployment for remote employees. After the technician completes the technician flow in the provisioning facility, the device is shipped to the end user. When the end user powers on the device and completes the user flow, the Enrollment Status Page (ESP) fails and rolls back. What is the MOST likely cause of this failure?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An enterprise administrator needs to deploy a Windows 11 image to devices that do not have internet access during provisioning. The administrator decides to use an Autopilot offline scenario combined with a provisioning package created with Windows Configuration Designer. Which tool and method should be used to capture the Autopilot device configuration offline and embed it into the provisioning package?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Export the Autopilot deployment profile as a JSON file from the Intune admin center and import it into Windows Configuration Designer"},{"id":"b","text":"Use the Get-WindowsAutoPilotInfo PowerShell script to generate a hardware hash CSV and apply it via a provisioning package"},{"id":"c","text":"Download the Autopilot configuration profile directly from Windows Configuration Designer using a service account with Intune read permissions"},{"id":"d","text":"Create a custom OMA-URI policy in Intune and export it as a .ppkg file using the Intune Export tool"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$For offline Autopilot scenarios, administrators can export the Autopilot deployment profile as a JSON file from the Microsoft Intune admin center (Devices > Enrollment > Windows Autopilot > Deployment Profiles > Export profile). This JSON file is then imported into Windows Configuration Designer when building a provisioning package (.ppkg), allowing devices without internet access to receive the Autopilot configuration during OOBE via the package. Option B is incorrect because Get-WindowsAutoPilotInfo captures hardware hashes for device registration, not for embedding profile configuration into a provisioning package. Option C is incorrect because Windows Configuration Designer does not natively connect to Intune to download profiles at authoring time. Option D is incorrect because Intune does not provide a native export-to-ppkg tool for OMA-URI policies.$patch$, $patch$Deploy Windows client$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/autopilot/profiles","label":"Autopilot deployment profile export (offline scenario)"},{"url":"https://learn.microsoft.com/en-us/windows/configuration/provisioning-packages/provisioning-install-icd","label":"Windows Configuration Designer overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An enterprise administrator needs to deploy a Windows 11 image to devices that do not have internet access during provisioning. The administrator decides to use an Autopilot offline scenario combined with a provisioning package created with Windows Configuration Designer. Which tool and method should be used to capture the Autopilot device configuration offline and embed it into the provisioning package?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization uses Microsoft Entra ID (formerly Azure Active Directory) and Intune. You need to ensure that only compliant devices can access Microsoft 365 resources. Which combination of features should you configure to enforce this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Microsoft Entra Conditional Access policy with a device compliance requirement, combined with an Intune compliance policy"},{"id":"b","text":"Microsoft Entra Privileged Identity Management (PIM) with an Intune device configuration profile"},{"id":"c","text":"Microsoft Entra Multi-Factor Authentication (MFA) with an Intune app protection policy"},{"id":"d","text":"Microsoft Entra Identity Protection with a Microsoft Defender for Endpoint integration policy"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$To restrict Microsoft 365 resource access to compliant devices, you must create an Intune compliance policy that defines the rules a device must meet (e.g., encryption, OS version) and then reference that compliance state in a Microsoft Entra Conditional Access policy using the 'Require device to be marked as compliant' grant control. PIM (option B) manages privileged role elevation and is unrelated to device compliance enforcement. MFA with app protection policies (option C) protects app-layer data but does not gate access based on device compliance state. Defender for Endpoint integration (option D) provides risk signals but is not the primary mechanism for enforcing device compliance as an access control gate on its own.$patch$, $patch$Manage identity and compliance$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/howto-conditional-access-policy-compliant-device","label":"Microsoft Learn – Require compliant or hybrid Azure AD joined device with Conditional Access"},{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/device-compliance-get-started","label":"Microsoft Learn – Device compliance policies in Microsoft Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization uses Microsoft Entra ID (formerly Azure Active Directory) and Intune. You need to ensure that only compliant devices can access Microsoft 365 resources. Which combination of features should you configure to enforce this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator needs to configure Windows Hello for Business (WHfB) for a hybrid Microsoft Entra joined environment. The organization wants to use the cloud Kerberos trust deployment model. Which prerequisite must be met before deploying WHfB with cloud Kerberos trust?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Active Directory must be running at the Windows Server 2016 functional level"},{"id":"b","text":"Microsoft Entra Kerberos must be enabled in the on-premises Active Directory domain"},{"id":"c","text":"A Public Key Infrastructure (PKI) must be deployed on-premises to issue user certificates"},{"id":"d","text":"Active Directory Federation Services (AD FS) must be deployed in the environment"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Cloud Kerberos trust is a WHfB hybrid deployment model that uses Microsoft Entra Kerberos — a partial Kerberos server object created in on-premises Active Directory — to issue Kerberos ticket-granting tickets (TGTs) to users. Enabling Microsoft Entra Kerberos in the on-premises AD domain is therefore a mandatory prerequisite. Option A is incorrect because cloud Kerberos trust requires only Windows Server 2008 R2 or later domain functional level, not 2016. Option C is incorrect because cloud Kerberos trust is specifically designed to eliminate the PKI requirement present in the key trust and certificate trust models. Option D is incorrect because AD FS is not required for cloud Kerberos trust; the model works natively with Microsoft Entra ID.$patch$, $patch$Manage identity and compliance$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/windows/security/identity-protection/hello-for-business/deploy/hybrid-cloud-kerberos-trust","label":"Microsoft Learn – Windows Hello for Business cloud Kerberos trust deployment"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/howto-authentication-passwordless-security-key-on-premises","label":"Microsoft Learn – Microsoft Entra Kerberos and passwordless sign-in"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator needs to configure Windows Hello for Business (WHfB) for a hybrid Microsoft Entra joined environment. The organization wants to use the cloud Kerberos trust deployment model. Which prerequisite must be met before deploying WHfB with cloud Kerberos trust?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Contoso uses Microsoft Intune to manage Windows 11 devices. A new regulatory requirement mandates that all managed devices must enforce BitLocker Drive Encryption with a 256-bit AES cipher, and recovery keys must be automatically backed up to Microsoft Entra ID. Which Intune policy type should the administrator use to enforce these BitLocker settings?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"An Intune device compliance policy targeting Windows 11 devices"},{"id":"b","text":"An Intune endpoint security Disk Encryption policy targeting Windows 11 devices"},{"id":"c","text":"An Intune app protection policy for Windows targeting managed devices"},{"id":"d","text":"A Microsoft Entra Conditional Access policy with an encryption grant control"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Intune Endpoint Security Disk Encryption policies are specifically designed to configure and enforce BitLocker settings (cipher strength, startup PIN, recovery key escrow to Entra ID, etc.) on Windows devices. This is the correct policy type for remediating BitLocker configuration. A device compliance policy (option A) can check whether BitLocker is enabled and mark non-compliant devices, but it does not push or enforce BitLocker cipher configuration settings — it is a reporting/gating mechanism, not a configuration mechanism. App protection policies (option C) apply to app-layer data protection and are unrelated to drive encryption. Conditional Access policies (option D) grant or block access based on signals; they cannot directly configure BitLocker settings on a device.$patch$, $patch$Manage identity and compliance$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/encrypt-devices","label":"Microsoft Learn – Manage BitLocker policy for Windows devices with Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/endpoint-security-disk-encryption-policy","label":"Microsoft Learn – Endpoint security Disk Encryption policy in Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Contoso uses Microsoft Intune to manage Windows 11 devices. A new regulatory requirement mandates that all managed devices must enforce BitLocker Drive Encryption with a 256-bit AES cipher, and recovery keys must be automatically backed up to Microsoft Entra ID. Which Intune policy type should the administrator use to enforce these BitLocker settings?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An organization has deployed Microsoft Intune and Microsoft Entra ID. A user reports that their personally owned Android device was enrolled under the 'Android Enterprise – Personally Owned with Work Profile' enrollment type. The user is concerned that the IT department can see and wipe their personal photos and data. Which statement accurately describes the scope of IT control under this enrollment type?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"IT administrators have full control of the entire device, including personal apps, photos, and the ability to issue a full device wipe"},{"id":"b","text":"IT administrators can only manage, view, and selectively wipe data within the work profile; personal data and apps remain private and outside IT control"},{"id":"c","text":"IT administrators can view all installed personal apps and their data, but cannot perform any wipe actions"},{"id":"d","text":"IT administrators can push policies to the entire device and can perform a full wipe, but cannot view personal app data"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Android Enterprise Personally Owned with Work Profile creates a hardware-enforced container (work profile) on the device. Intune and IT administrators can only manage, deploy apps to, and selectively wipe the work profile — they have no visibility into or control over personal apps, personal photos, call logs, or other personal data outside the work profile. A selective wipe removes only the work profile and its associated data, not personal content. Option A is incorrect because full device management (including personal data access and full wipe) applies to corporate-owned fully managed enrollment, not personally owned work profile. Option C is incorrect because IT can perform a selective wipe of the work profile. Option D is incorrect because policies are scoped to the work profile only, and a full device wipe is not available under this enrollment type for personally owned devices.$patch$, $patch$Manage identity and compliance$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/enrollment/android-work-profile-enroll","label":"Microsoft Learn – Android Enterprise personally owned devices with work profile – Intune enrollment"},{"url":"https://learn.microsoft.com/en-us/mem/intune/remote-actions/devices-wipe","label":"Microsoft Learn – Remove devices by using wipe, retire, or manually unenrolling the device"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An organization has deployed Microsoft Intune and Microsoft Entra ID. A user reports that their personally owned Android device was enrolled under the 'Android Enterprise – Personally Owned with Work Profile' enrollment type. The user is concerned that the IT department can see and wipe their personal photos and data. Which statement accurately describes the scope of IT control under this enrollment type?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Fabrikam needs to implement role-based access control (RBAC) in Microsoft Intune so that the helpdesk team can reset passcodes and remotely lock devices, but cannot modify device configuration profiles or compliance policies. Which built-in Intune RBAC role best satisfies this requirement with the principle of least privilege?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Intune Role Administrator"},{"id":"b","text":"Help Desk Operator"},{"id":"c","text":"Read Only Operator"},{"id":"d","text":"Policy and Profile Manager"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The built-in Help Desk Operator role in Intune is specifically designed for helpdesk scenarios. It grants permissions to perform remote actions such as remote lock, passcode reset, retire, and sync, while explicitly excluding permissions to create or modify device configuration profiles or compliance policies. This directly satisfies the principle of least privilege for the described scenario. Intune Role Administrator (option A) grants the ability to create and assign Intune RBAC roles — far beyond what a helpdesk team needs and inappropriate for this use case. Read Only Operator (option C) provides no ability to perform remote actions, only to view data. Policy and Profile Manager (option D) grants permissions to create and manage device configuration profiles and compliance policies — exactly the permissions Fabrikam wants to exclude from the helpdesk team.$patch$, $patch$Manage identity and compliance$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/role-based-access-control","label":"Microsoft Learn – Role-based access control (RBAC) with Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/fundamentals/role-based-access-control#built-in-roles","label":"Microsoft Learn – Built-in role permissions for Microsoft Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Fabrikam needs to implement role-based access control (RBAC) in Microsoft Intune so that the helpdesk team can reset passcodes and remotely lock devices, but cannot modify device configuration profiles or compliance policies. Which built-in Intune RBAC role best satisfies this requirement with the principle of least privilege?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company's security team wants to enforce that all Windows 11 devices managed by Intune must have a minimum OS version of 10.0.22621 (Windows 11 22H2). Devices that do not meet this requirement should be blocked from accessing company email via Microsoft 365. What is the correct sequence of steps to enforce this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create an Intune device configuration profile specifying the minimum OS version, then create a Conditional Access policy that requires the device to be marked as compliant"},{"id":"b","text":"Create an Intune device compliance policy specifying the minimum OS version of 10.0.22621, assign it to the target group, then create a Conditional Access policy requiring device compliance and targeting Microsoft 365 (Exchange Online)"},{"id":"c","text":"Create an Intune device compliance policy specifying the minimum OS version, then create a Microsoft Entra Identity Protection user risk policy to block access for non-compliant users"},{"id":"d","text":"Configure a Windows Update for Business ring policy in Intune enforcing the minimum OS version, then create a Conditional Access policy that blocks legacy authentication"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The correct approach is a two-step process: (1) Create an Intune device compliance policy for Windows 10/11 that sets the minimum OS version to 10.0.22621; assign this policy to the relevant device or user group — devices not meeting the requirement are marked 'Not Compliant'. (2) Create a Microsoft Entra Conditional Access policy that targets Microsoft 365 / Exchange Online as the cloud app and uses the grant control 'Require device to be marked as compliant', which blocks access from non-compliant devices. Option A is incorrect because device configuration profiles configure device settings but do not generate a compliance state that Conditional Access can consume for an OS version check. Option C is incorrect because Identity Protection risk policies respond to sign-in and user risk signals, not device compliance state. Option D is incorrect because Windows Update for Business rings manage update deployment timing but do not generate a compliance signal for Conditional Access, and blocking legacy authentication is unrelated to the OS version requirement.$patch$, $patch$Manage identity and compliance$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/create-compliance-policy","label":"Microsoft Learn – Create a compliance policy in Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/howto-conditional-access-policy-compliant-device","label":"Microsoft Learn – Conditional Access – Require compliant device"},{"url":"https://learn.microsoft.com/en-us/mem/intune/protect/compliance-policy-create-windows","label":"Microsoft Learn – Windows compliance settings in Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company's security team wants to enforce that all Windows 11 devices managed by Intune must have a minimum OS version of 10.0.22621 (Windows 11 22H2). Devices that do not meet this requirement should be blocked from accessing company email via Microsoft 365. What is the correct sequence of steps to enforce this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You are an Endpoint Administrator responsible for deploying Microsoft 365 Apps for enterprise to 500 Windows 11 devices managed through Microsoft Intune. You need to ensure that users cannot install additional Office add-ins from the Office Store while still allowing IT-approved add-ins. Which configuration method should you use to enforce this restriction?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create an Intune device configuration profile using the Settings Catalog and enable the 'Block Web Add-ins' policy under Microsoft Office 2016 > Security Settings."},{"id":"b","text":"Create an Intune App Configuration policy targeting Microsoft 365 Apps and set the 'Allow the Office Store' key to 'Disabled'."},{"id":"c","text":"Deploy an Intune App Protection policy that blocks data transfer to unmanaged apps, which will implicitly prevent add-in installations."},{"id":"d","text":"Use the Office Deployment Tool (ODT) with a custom configuration XML that includes the ExcludeApp element for the Store."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$To block users from installing Office add-ins from the Office Store, you should use the Intune Settings Catalog to configure Office administrative template policies. The 'Block Web Add-ins' policy (and the related 'Don't allow Web Add-ins to start' policies) under Microsoft Office 2016 > Security Settings controls access to the Office Store for add-ins on managed devices. App Configuration policies (option B) are used for managed app behavior settings and do not expose this Office Store add-in control. App Protection policies (option C) govern data-loss prevention scenarios and do not restrict add-in installations. The ODT ExcludeApp element (option D) is used during installation to exclude specific Office applications, not to restrict Store access post-deployment.$patch$, $patch$Manage applications$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/apps-add-office365","label":"Microsoft Learn – Add Microsoft 365 Apps to Windows 10/11 devices using Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/configuration/settings-catalog","label":"Microsoft Learn – Use the Settings Catalog to configure settings on Windows and macOS devices"},{"url":"https://learn.microsoft.com/en-us/office/dev/add-ins/overview/office-add-ins","label":"Microsoft Learn – Office add-ins platform overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You are an Endpoint Administrator responsible for deploying Microsoft 365 Apps for enterprise to 500 Windows 11 devices managed through Microsoft Intune. You need to ensure that users cannot install additional Office add-ins from the Office Store while still allowing IT-approved add-ins. Which configuration method should you use to enforce this restriction?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company uses Microsoft Intune to manage Android Enterprise personally owned devices with a work profile. The security team requires that the corporate email app only allows copy/paste operations within the managed work profile and prevents users from pasting work data into personal apps. Which Intune feature should be configured to meet this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Configure an Android Enterprise Device Compliance policy to block clipboard sharing."},{"id":"b","text":"Create an Intune App Protection policy (APP) for Android targeting the corporate email app and set 'Restrict cut, copy, and paste between other apps' to 'Policy managed apps'."},{"id":"c","text":"Create an Android Enterprise Device Configuration profile and disable the system clipboard feature in device restrictions."},{"id":"d","text":"Assign the corporate email app as a Required app in the Android Enterprise work profile and enable Managed Home Screen."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Intune App Protection Policies (APP) are the correct mechanism to control cut, copy, and paste behavior at the app level on Android devices. Setting 'Restrict cut, copy, and paste between other apps' to 'Policy managed apps' ensures that clipboard content from the managed email app can only be pasted into other apps that are also governed by an App Protection policy, thereby preventing data leakage into personal apps. Device Compliance policies (option A) only assess device state for conditional access and cannot enforce clipboard behavior. Device Configuration profiles with device restrictions (option C) restrict the entire system clipboard, which is overly broad and applies to both profiles. Assigning an app as Required (option D) controls deployment, not data movement restrictions.$patch$, $patch$Manage applications$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/app-protection-policy","label":"Microsoft Learn – App protection policies overview"},{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/app-protection-policy-settings-android","label":"Microsoft Learn – Android app protection policy settings in Microsoft Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company uses Microsoft Intune to manage Android Enterprise personally owned devices with a work profile. The security team requires that the corporate email app only allows copy/paste operations within the managed work profile and prevents users from pasting work data into personal apps. Which Intune feature should be configured to meet this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$You need to deploy a mandatory line-of-business (LOB) Win32 application to all Windows 11 Intune-managed devices. After packaging the application as a .intunewin file and uploading it to Intune, you notice that approximately 30% of devices report the installation as 'Failed'. You check the Intune Management Extension (IME) log on an affected device and find error code 0x80070643. What is the MOST likely cause of this error and the appropriate remediation?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The .intunewin package exceeds the 8 GB file size limit. Repackage the application splitting it into smaller packages."},{"id":"b","text":"The installation command line is incorrect or the installer itself returned a fatal error (MSI error 1603). Verify the install command, ensure all prerequisites are met, and test the installer locally with the same parameters."},{"id":"c","text":"The device does not have an Intune Management Extension (IME) installed. Assign a PowerShell script to trigger IME installation."},{"id":"d","text":"The application is assigned as Available instead of Required. Change the assignment to Required to force installation."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Error code 0x80070643 maps to ERROR_INSTALL_FAILURE, which corresponds to MSI error 1603 — a fatal error during installation. This is one of the most common Win32 app deployment errors in Intune and typically indicates that the installer's command-line parameters are wrong, a prerequisite (such as a runtime or dependency) is missing, or the installer itself encounters a condition it cannot handle (e.g., a conflicting version or insufficient permissions). The correct remediation is to review the install command in Intune, reproduce the installation locally using the exact same command in a SYSTEM context, and check for prerequisite gaps. The 8 GB limit (option A) would surface as an upload error, not a deployment failure. IME is automatically installed when a Win32 app is targeted (option C). Changing assignment type (option D) does not resolve an installation error code.$patch$, $patch$Manage applications$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/apps-win32-app-management","label":"Microsoft Learn – Win32 app management in Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/apps-win32-troubleshoot","label":"Microsoft Learn – Troubleshoot Win32 app installations with Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$You need to deploy a mandatory line-of-business (LOB) Win32 application to all Windows 11 Intune-managed devices. After packaging the application as a .intunewin file and uploading it to Intune, you notice that approximately 30% of devices report the installation as 'Failed'. You check the Intune Management Extension (IME) log on an affected device and find error code 0x80070643. What is the MOST likely cause of this error and the appropriate remediation?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Your organization wants to ensure that users can only launch approved managed apps on their iOS/iPadOS devices enrolled in Intune via the Device Enrollment Program (DEP). Specifically, you want to prevent a managed app from opening links in an unmanaged browser. Which Intune App Protection Policy setting should you configure?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Set 'Send org data to other apps' to 'None' to block all outbound data transfer including hyperlinks."},{"id":"b","text":"Set 'Restrict web content transfer with other apps' to 'Microsoft Edge' or 'Managed browsers' so that all links from managed apps open only in a policy-managed browser."},{"id":"c","text":"Enable 'Require managed browser' under the iOS Device Compliance policy to force Safari into managed mode."},{"id":"d","text":"Configure a Conditional Access policy requiring an approved client app, which will block unmanaged browsers from opening organizational links."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The App Protection Policy setting 'Restrict web content transfer with other apps' (sometimes labeled 'Restrict web content transfer with other browsers') controls which browser can open hyperlinks clicked within a managed app. Setting it to 'Microsoft Edge' or 'Managed browsers' ensures links are redirected to Microsoft Edge (configured with an Intune App Configuration policy) or another Intune-managed browser, preventing them from opening in unmanaged browsers such as Safari or Chrome without APP. Setting 'Send org data to other apps' to 'None' (option A) is overly restrictive and blocks all outbound data sharing, not just browser links, which would break legitimate workflows. Device Compliance policies (option C) do not have a 'Require managed browser' setting that puts Safari in a managed mode. Conditional Access (option D) controls access to cloud resources, not the behavior of hyperlinks within an already-opened app.$patch$, $patch$Manage applications$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/app-protection-policy-settings-ios","label":"Microsoft Learn – iOS/iPadOS app protection policy settings in Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/manage-microsoft-edge","label":"Microsoft Learn – Manage web access using Microsoft Edge with Microsoft Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Your organization wants to ensure that users can only launch approved managed apps on their iOS/iPadOS devices enrolled in Intune via the Device Enrollment Program (DEP). Specifically, you want to prevent a managed app from opening links in an unmanaged browser. Which Intune App Protection Policy setting should you configure?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An organization is deploying a Microsoft Store app to Intune-managed Windows 11 devices using the new Microsoft Store app type available in Intune (powered by WinGet). A subset of devices in one assignment group are not receiving the app. Upon investigation, you confirm those devices are enrolled in Intune and Azure AD joined. What is the MOST likely reason the app is not being delivered to those specific devices?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The new Microsoft Store app type requires devices to be co-managed with Configuration Manager. The affected devices are Intune-only managed and therefore unsupported."},{"id":"b","text":"The Intune Management Extension (IME) is not installed on the affected devices because no PowerShell scripts or Win32 apps have been assigned to them, and the Microsoft Store app type requires IME to function."},{"id":"c","text":"The affected devices do not meet the minimum OS requirement. The new Microsoft Store app type in Intune (WinGet-based) requires Windows 11 version 22H2 or later, and those devices may be running an earlier build."},{"id":"d","text":"The app assignment is scoped to a user group, but the affected devices have no licensed and active user session, so the user-context installation cannot complete; switching to a device group assignment or ensuring a user is signed in would resolve this for required deployments."}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Microsoft Store apps deployed via Intune using the WinGet-based store integration install in user context by default when assigned to user groups. If the targeted devices have no active or licensed user logged on at the time of policy evaluation, or if the assignment is scoped to users who are not associated with those machines, the installation cannot proceed in user context. Switching the assignment to a device group (or ensuring the correct users are associated with the devices and have active sessions) resolves the issue for Required deployments. Co-management with Configuration Manager (option A) is not a requirement for the new Microsoft Store app type in Intune. IME (option B) is used for Win32 and PowerShell deployments, not for the WinGet/Store app type. While OS version matters, the new Microsoft Store experience is broadly available on Windows 10 20H2+ and Windows 11 (option C), making a version mismatch less likely than an assignment scoping issue in this scenario.$patch$, $patch$Manage applications$patch$,
         3, $json$[{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/store-apps-microsoft","label":"Microsoft Learn – Add Microsoft Store apps to Microsoft Intune"},{"url":"https://learn.microsoft.com/en-us/mem/intune/apps/apps-deploy","label":"Microsoft Learn – Assign apps to groups with Microsoft Intune"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'MD-102-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An organization is deploying a Microsoft Store app to Intune-managed Windows 11 devices using the new Microsoft Store app type available in Intune (powered by WinGet). A subset of devices in one assignment group are not receiving the app. Upon investigation, you confirm those devices are enrolled in Intune and Azure AD joined. What is the MOST likely reason the app is not being delivered to those specific devices?$patch$);

-- SAP-C02: 15 questions
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A large enterprise has 120 AWS accounts organized across multiple business units using AWS Organizations. The central security team mandates that no account within the organization may disable AWS CloudTrail logging, and that all CloudTrail logs must be delivered to a centralized S3 bucket in the dedicated security account. Individual business unit administrators have full administrator access within their own accounts. Which combination of actions will BEST enforce this requirement with the LEAST operational overhead?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Deploy an AWS Config rule in every member account that checks for active CloudTrail trails and triggers an AWS Lambda function to re-enable CloudTrail if it is disabled. Store logs in each account's own S3 bucket and replicate them to the central security bucket using S3 Cross-Region Replication."},{"id":"b","text":"Create a Service Control Policy (SCP) at the AWS Organizations root level that denies the cloudtrail:DeleteTrail, cloudtrail:StopLogging, and cloudtrail:UpdateTrail actions for all principals. Use AWS CloudFormation StackSets with SERVICE_MANAGED deployment to deploy an organization-wide CloudTrail trail that delivers logs to the centralized S3 bucket in the security account."},{"id":"c","text":"Use AWS Control Tower to enroll all 120 accounts, apply the 'Disallow Changes to CloudTrail' guardrail, and configure a new landing zone with a centralized logging account. Migrate the existing accounts into Control Tower organizational units manually one at a time."},{"id":"d","text":"Deploy an IAM permission boundary on every IAM role in each member account that prevents cloudtrail:DeleteTrail and cloudtrail:StopLogging. Configure an organization-level CloudTrail trail from the management account and deliver logs to the security account S3 bucket."},{"id":"e","text":"Create a dedicated security OU and move all accounts into it. Apply an SCP to that OU denying cloudtrail:StopLogging only. Enable CloudTrail in each account independently and configure each account's trail to write to the central S3 bucket using bucket policy cross-account access."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct because it combines two AWS-native mechanisms purpose-built for this problem at organizational scale. An SCP applied at the root level enforces a preventive guardrail that no member account principal—regardless of their permissions, including administrators—can override; it denies the specific CloudTrail mutating actions across all 120 accounts without any per-account work. CloudFormation StackSets with SERVICE_MANAGED deployment (delegated to Organizations) automatically deploys and maintains the CloudTrail stack in every existing and future member account with no manual per-account action required. An organization-level trail created in the management account natively supports delivering events from all member accounts to a single S3 bucket. Option A is detective (not preventive) and adds Lambda/replication complexity. Option C (Control Tower) is a valid long-term approach but enrolling 120 existing accounts manually is high operational overhead and not the least-overhead option. Option D uses IAM permission boundaries, which are applied per role and would require touching every role in every account—extremely high overhead and incomplete coverage for new roles. Option E only denies StopLogging but not DeleteTrail or UpdateTrail, leaving gaps in enforcement, and requires per-account manual configuration.$patch$, $patch$Design Solutions for Organizational Complexity$patch$,
         4, $json$[{"url":"https://docs.aws.amazon.com/organizations/latest/userguide/orgs_manage_policies_scps.html","label":"AWS Organizations – Service Control Policies"},{"url":"https://docs.aws.amazon.com/awscloudtrail/latest/userguide/creating-trail-organization.html","label":"Creating a Trail for an Organization (CloudTrail)"},{"url":"https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/stacksets-orgs-manage-stackset.html","label":"CloudFormation StackSets – SERVICE_MANAGED Deployments"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'SAP-C02'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A large enterprise has 120 AWS accounts organized across multiple business units using AWS Organizations. The central security team mandates that no account within the organization may disable AWS CloudTrail logging, and that all CloudTrail logs must be delivered to a centralized S3 bucket in the dedicated security account. Individual business unit administrators have full administrator access within their own accounts. Which combination of actions will BEST enforce this requirement with the LEAST operational overhead?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A global financial services company runs workloads in AWS accounts belonging to three separate AWS Organizations: one for its retail banking division, one for its investment banking division, and one for its corporate IT division. Regulatory requirements mandate strict network isolation between divisions, yet a new internal application requires private connectivity from the corporate IT VPC (CIDR 10.100.0.0/16) to specific microservices hosted in the retail banking VPC (CIDR 10.200.0.0/16) and the investment banking VPC (CIDR 10.200.0.0/16) — note that both destination VPCs share the same CIDR block. All traffic must remain on the AWS private network, and the solution must scale to hundreds of microservices over time. Which solution meets these requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create VPC peering connections between the corporate IT VPC and each of the division VPCs. Add routes in each routing table to direct traffic to the appropriate peered VPC. Use security groups to restrict access to specific microservice ports."},{"id":"b","text":"Deploy an AWS Transit Gateway in each organization and configure inter-region peering between them. Attach all VPCs to their respective Transit Gateways and create static routes. Use Transit Gateway route tables to segment traffic between divisions."},{"id":"c","text":"Expose each microservice in the retail and investment banking VPCs as an AWS PrivateLink endpoint service (backed by a Network Load Balancer). Create VPC endpoint interface connections from the corporate IT VPC to each endpoint service. Apply endpoint policies to restrict access per service. Use AWS Resource Access Manager to share the endpoint services across Organizations boundaries."},{"id":"d","text":"Set up AWS Direct Connect hosted connections between each organization's on-premises network and route inter-division traffic through the on-premises data center. Use a Transit VIF for each connection and BGP routing to ensure traffic stays private."},{"id":"e","text":"Merge all three AWS Organizations into a single organization using the Organizations InviteAccountToOrganization API. Attach all VPCs to a single Transit Gateway and use Transit Gateway route tables to isolate divisional traffic."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Option C is correct for several reasons specific to this architecture: (1) Both destination VPCs share an overlapping CIDR (10.200.0.0/16), which makes VPC peering (Option A) and Transit Gateway routing (Option B) impossible because both require non-overlapping CIDRs—routing would be ambiguous. AWS PrivateLink is the only AWS-native connectivity model that works across overlapping CIDRs because consumers connect to a logical service endpoint rather than routing at the IP layer. (2) PrivateLink keeps all traffic on the AWS backbone—no internet exposure. (3) Endpoint services can be shared across account and organization boundaries using AWS RAM, satisfying the cross-organization requirement. (4) Each microservice can be independently versioned as its own endpoint service, which scales well to hundreds of services. Option A and B fail due to CIDR overlap. Option D routes traffic off-network through on-premises, violating the private AWS network requirement. Option E merging Organizations is an irreversible, legally and operatorially complex action that would violate the regulatory isolation mandate and is not a valid network connectivity solution.$patch$, $patch$Design Solutions for Organizational Complexity$patch$,
         4, $json$[{"url":"https://docs.aws.amazon.com/vpc/latest/privatelink/privatelink-share-your-services.html","label":"AWS PrivateLink – Share Your Services Across Accounts"},{"url":"https://docs.aws.amazon.com/ram/latest/userguide/shareable.html","label":"AWS Resource Access Manager – Shareable Resource Types"},{"url":"https://docs.aws.amazon.com/vpc/latest/peering/vpc-peering-basics.html#vpc-peering-limitations","label":"VPC Peering – Limitations (Overlapping CIDRs)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'SAP-C02'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A global financial services company runs workloads in AWS accounts belonging to three separate AWS Organizations: one for its retail banking division, one for its investment banking division, and one for its corporate IT division. Regulatory requirements mandate strict network isolation between divisions, yet a new internal application requires private connectivity from the corporate IT VPC (CIDR 10.100.0.0/16) to specific microservices hosted in the retail banking VPC (CIDR 10.200.0.0/16) and the investment banking VPC (CIDR 10.200.0.0/16) — note that both destination VPCs share the same CIDR block. All traffic must remain on the AWS private network, and the solution must scale to hundreds of microservices over time. Which solution meets these requirements?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An enterprise architect is designing a multi-account strategy for a company that is acquiring several smaller businesses over the next two years. Each acquisition will bring its own existing AWS accounts with independently managed IAM Identity Center (formerly AWS SSO) configurations, varied tagging schemas, and separate billing arrangements. The acquiring company uses AWS Organizations with all features enabled and has a centralized cloud governance team. The governance team needs to enforce cost allocation tagging policies immediately upon account onboarding, ensure that permission sets provisioned to acquired accounts follow corporate standards, and receive a consolidated cost view across all accounts within 24 hours of an account joining the organization. Which approach BEST satisfies all three requirements?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"For each acquisition, invite the existing AWS accounts into the master organization. Manually apply tag policies to each new account after invitation. Reconfigure IAM Identity Center in each account to point to the corporate IdP. Wait for the next AWS Cost Explorer data refresh cycle for consolidated billing visibility."},{"id":"b","text":"Use AWS Organizations tag policies attached at the root to enforce required cost allocation tags; non-compliant resources are automatically reported via AWS Config. Centralize identity management by configuring IAM Identity Center at the organization level with corporate IdP delegated administration, and pre-create permission set assignments that are applied automatically when new accounts are registered. Leverage consolidated billing in Organizations so new member accounts appear in Cost Explorer within 24 hours of joining."},{"id":"c","text":"Deploy an AWS Control Tower landing zone and enroll every acquired account into Control Tower. Use Control Tower's Account Factory to enforce tags at account creation. Accept that accounts created outside Account Factory require a manual enrollment process that may take several days, delaying consolidated billing and permission set assignments."},{"id":"d","text":"Use AWS Service Catalog to provision new accounts with standardized configurations including tagging and IAM roles. Implement cross-account IAM role assumption from the management account to manage permissions in member accounts. Set up a separate AWS Cost and Usage Report (CUR) for each acquisition and aggregate using Amazon Athena queries."},{"id":"e","text":"Apply an SCP at the root that denies resource creation unless required tags are present. Require each acquisition to independently configure their IAM Identity Center and federate it with the corporate IdP. Use AWS Organizations consolidated billing but acknowledge that Cost Explorer data for new accounts may take 48–72 hours to appear."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Option B is correct because it directly and comprehensively addresses all three requirements with the lowest latency and operational overhead: (1) Tag enforcement — AWS Organizations tag policies attached at the root level propagate automatically to all member accounts, including newly joined accounts, immediately upon joining. AWS Config with the required-tags managed rule provides continuous compliance reporting without per-account setup. (2) IAM Identity Center at the organization level with a delegated administrator allows pre-created permission sets to be assigned to accounts automatically; when a new account joins, the governance team can push standardized permission set assignments within minutes. The corporate IdP integration is configured once centrally. (3) Consolidated billing in AWS Organizations causes new member accounts to appear in Cost Explorer data typically within 24 hours—satisfying the billing visibility SLA. Option A is manual and slow, violating the 24-hour billing requirement and the immediate tagging mandate. Option C (Control Tower) is valid for greenfield but enrolling existing accounts with pre-existing configurations is a multi-day process and does not meet the 24-hour window. Option D uses Service Catalog for account provisioning (not for tagging enforcement on pre-existing accounts) and CUR+Athena adds unnecessary complexity when consolidated billing already provides the view. Option E's SCP approach to tag enforcement is overly restrictive (blocks all resource creation rather than reporting), and independently configured per-account IAM Identity Center does not meet corporate standards centralization.$patch$, $patch$Design Solutions for Organizational Complexity$patch$,
         4, $json$[{"url":"https://docs.aws.amazon.com/organizations/latest/userguide/orgs_manage_policies_tag-policies.html","label":"AWS Organizations – Tag Policies"},{"url":"https://docs.aws.amazon.com/singlesignon/latest/userguide/manage-your-accounts.html","label":"IAM Identity Center – Multi-Account Permissions with AWS Organizations"},{"url":"https://docs.aws.amazon.com/awsaccountbilling/latest/aboutv2/consolidated-billing.html","label":"AWS Organizations – Consolidated Billing and Cost Explorer"},{"url":"https://docs.aws.amazon.com/singlesignon/latest/userguide/delegated-admin.html","label":"IAM Identity Center – Delegated Administration"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'SAP-C02'
