INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which data serialization format is characterized by indentation-based hierarchy and is the native format used to write Ansible playbooks?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"JSON"},{"id":"b","text":"XML"},{"id":"c","text":"YAML"},{"id":"d","text":"CSV"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states that YAML is indentation-sensitive and is used in Ansible playbooks. JSON uses key-value pairs with curly braces and square brackets and is associated with REST APIs. XML uses opening and closing tags and is associated with NETCONF. CSV (comma-separated values) is not a structured data serialization format used in network automation contexts and is not mentioned in the source material.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://docs.ansible.com/ansible/latest/reference_appendices/YAMLSyntax.html","label":"Ansible Documentation – YAML Syntax"},{"url":"https://developer.cisco.com/learning/tracks/devnet-associate/network-programmability-basics/02-network-programmability/step/1","label":"Cisco DevNet – Data Formats for Network Programmability"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
