INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A company needs to establish a site-to-site VPN between two branch offices. The requirement specifies that the original IP headers of packets must be fully encrypted and new IP headers added for transit across the internet. Which IPsec mode satisfies this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Transport mode, because it encrypts the data payload while preserving the original IP header"},{"id":"b","text":"Tunnel mode, because it encrypts the entire original packet including the IP header and encapsulates it in a new IP header"},{"id":"c","text":"Transport mode, because gateways use it to build gateway-to-gateway tunnels"},{"id":"d","text":"GRE-only encapsulation, because it natively encrypts headers end-to-end"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$IPsec tunnel mode encapsulates the entire original IP packet (header + payload) and encrypts it, then prepends a new IP header for routing across the public network. This is the standard mode for site-to-site VPNs between gateways. The source material states: 'tunnel (gateway-gateway, original IP encrypted).' Transport mode (options A and C) preserves the original IP header in cleartext and is used for host-to-host communications, making it unsuitable when header confidentiality between sites is required. GRE alone (option D) provides no encryption whatsoever.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/security-vpn/ipsec-negotiation-ike-protocols/115936-understanding-ike-ipsec-concepts.html","label":"Cisco – IPsec Modes: Transport and Tunnel"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A company needs to establish a site-to-site VPN between two branch offices. The requirement specifies that the original IP headers of packets must be fully encrypted and new IP headers added for transit across the internet. Which IPsec mode satisfies this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An enterprise wireless network must support the highest level of modern security, replacing the Pre-Shared Key (PSK) exchange method with a more secure mutual authentication handshake. Which wireless security standard and key-exchange mechanism should be implemented?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"WPA2-Personal using a complex PSK of at least 20 characters"},{"id":"b","text":"WPA using TKIP for backward compatibility with legacy clients"},{"id":"c","text":"WPA3 using Simultaneous Authentication of Equals (SAE)"},{"id":"d","text":"WEP with a 256-bit key for enhanced encryption strength"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$WPA3 introduces Simultaneous Authentication of Equals (SAE), a password-authenticated key exchange that replaces the vulnerable PSK four-way handshake used in WPA2-Personal. SAE provides forward secrecy and resistance to offline dictionary attacks. The source material states: 'WPA3 (SAE - Simultaneous Authentication of Equals, replaces PSK).' WPA2-Personal (option A) still uses PSK and is susceptible to offline brute-force attacks. WPA with TKIP (option B) is listed as 'obsolete/insecure.' WEP (option D) is fundamentally broken regardless of key length and is also identified in the source as obsolete/insecure.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/products/collateral/wireless/nb-06-wi-fi-protected-access-3-wp-cte-en.html","label":"Cisco – WPA3 Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An enterprise wireless network must support the highest level of modern security, replacing the Pre-Shared Key (PSK) exchange method with a more secure mutual authentication handshake. Which wireless security standard and key-exchange mechanism should be implemented?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer wants to retrieve the current running configuration from a Cisco IOS-XE device using NETCONF. Which TCP port and transport protocol does NETCONF use by default?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Port 443 over TLS"},{"id":"b","text":"Port 830 over SSH"},{"id":"c","text":"Port 80 over HTTP"},{"id":"d","text":"Port 22 over SSH"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$According to RFC 6241 and the source material, NETCONF operates over SSH on TCP port 830. This distinguishes it from standard SSH management (port 22) and from RESTCONF, which uses HTTP(S). Option (a) is incorrect because port 443/TLS is used by RESTCONF/HTTPS, not NETCONF. Option (c) is incorrect as plain HTTP is not used by NETCONF. Option (d) is incorrect because although NETCONF runs over SSH, the designated port is 830, not 22.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://www.rfc-editor.org/rfc/rfc6241","label":"RFC 6241 – Network Configuration Protocol (NETCONF)"},{"url":"https://www.cisco.com/c/en/us/td/docs/ios-xml/ios/prog/configuration/1612/b_1612_programmability_cg/netconf_yang.html","label":"Cisco IOS XE Programmability Configuration Guide – NETCONF"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer wants to retrieve the current running configuration from a Cisco IOS-XE device using NETCONF. Which TCP port and transport protocol does NETCONF use by default?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer is automating Cisco device configuration using Ansible. Which statement BEST describes how Ansible communicates with network devices compared to Puppet or Chef?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Ansible requires a persistent agent installed on each managed network device."},{"id":"b","text":"Ansible uses a centralized controller that pushes compiled catalogs to device agents."},{"id":"c","text":"Ansible is agentless and communicates with devices using SSH or APIs without requiring software installed on the target."},{"id":"d","text":"Ansible uses gRPC streams to collect model-driven telemetry from devices."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'Ansible: agentless, YAML playbooks, modules (ios_config, ios_facts)' while 'Puppet/Chef: agent-based.' This means Ansible does not require any software pre-installed on the managed device and instead connects over SSH or APIs. Option (a) is incorrect because that describes agent-based tools like Puppet/Chef. Option (b) describes the Puppet catalog compilation/push model. Option (d) describes gNMI/gRPC model-driven telemetry, which is unrelated to Ansible's communication model.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://docs.ansible.com/ansible/latest/network/index.html","label":"Ansible Network Automation Documentation"},{"url":"https://developer.cisco.com/network-automation/detail/ansible/","label":"Cisco DevNet – Network Automation with Ansible"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer is automating Cisco device configuration using Ansible. Which statement BEST describes how Ansible communicates with network devices compared to Puppet or Chef?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An automation script sends an HTTP request to the Cisco DNA Center Northbound REST API and receives a status code of 401. What does this response indicate?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The request was successful and the resource was created."},{"id":"b","text":"The server encountered an internal error processing the request."},{"id":"c","text":"The client is not authorized — valid credentials were not supplied."},{"id":"d","text":"The requested resource was not found on the server."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material lists HTTP status code 401 under '4xx (client error: 400 Bad Request, 401 Unauthorized, 403 Forbidden, 404 Not Found).' A 401 Unauthorized response means the request lacks valid authentication credentials. Option (a) describes a 2xx success response (e.g., 201 Created). Option (b) describes a 5xx server-side error such as 500. Option (d) describes a 404 Not Found response.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://developer.cisco.com/docs/dna-center/authentication/","label":"Cisco DNA Center API Reference – Authentication"},{"url":"https://developer.mozilla.org/en-US/docs/Web/HTTP/Status/401","label":"MDN Web Docs – HTTP Status 401 Unauthorized"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An automation script sends an HTTP request to the Cisco DNA Center Northbound REST API and receives a status code of 401. What does this response indicate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network architect is comparing traditional networking with Software-Defined Networking (SDN). Which statement accurately differentiates the two approaches in terms of the control plane?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Traditional networking uses a centralized controller, while SDN uses a distributed control plane on each device."},{"id":"b","text":"Traditional networking uses a distributed control plane on each device, while SDN centralizes the control plane in a controller."},{"id":"c","text":"Both traditional networking and SDN use a centralized control plane, but SDN also adds a distributed data plane."},{"id":"d","text":"SDN eliminates the data plane entirely by moving all packet forwarding logic into the controller."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The source material explicitly states: 'Traditional: distributed control plane (each device runs routing). SDN: centralized control plane (controller programs data plane).' Option (a) has the two descriptions reversed. Option (c) is incorrect because traditional networking has a distributed, not centralized, control plane. Option (d) is incorrect because SDN retains the data plane on devices; only the control plane is centralized.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/solutions/software-defined-networking/overview.html","label":"Cisco – Software-Defined Networking Overview"},{"url":"https://www.ciscopress.com/store/ccna-200-301-official-cert-guide-library-9780138212827","label":"Cisco CCNA 200-301 Official Cert Guide – SDN"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network architect is comparing traditional networking with Software-Defined Networking (SDN). Which statement accurately differentiates the two approaches in terms of the control plane?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Python developer needs to send a REST API call to modify a specific field of an existing resource on a Cisco DNA Center controller without replacing the entire resource. Which HTTP method should the developer use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"GET"},{"id":"b","text":"POST"},{"id":"c","text":"PUT"},{"id":"d","text":"PATCH"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$The source material defines HTTP methods as: 'GET (read), POST (create), PUT (replace), PATCH (modify), DELETE (remove).' Because the requirement is to modify a specific field without replacing the entire resource, PATCH is the correct method. GET is read-only. POST creates a new resource. PUT replaces the entire resource, which would overwrite fields not included in the request body.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://developer.cisco.com/docs/dna-center/","label":"Cisco DNA Center Developer Guide – REST API Methods"},{"url":"https://www.rfc-editor.org/rfc/rfc5789","label":"RFC 5789 – PATCH Method for HTTP"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
