INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which southbound protocol does Cisco DNA Center (Catalyst Center) use to communicate with and program managed network devices?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"REST over HTTPS on port 443"},{"id":"b","text":"SNMP v2c traps"},{"id":"c","text":"NETCONF/YANG"},{"id":"d","text":"Telnet over port 23"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The source material states: 'Southbound NETCONF/YANG to devices' when describing Cisco DNA Center. NETCONF combined with YANG data models is how DNA Center programs the data plane on managed devices. REST over HTTPS is used for DNA Center's Northbound API (consumed by external automation scripts), not the southbound interface to devices. SNMP v2c is a legacy monitoring protocol not used for southbound programmability in DNA Center. Telnet is unencrypted and deprecated in modern network management.$patch$, $patch$Automation and Programmability$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/products/collateral/cloud-systems-management/dna-center/nb-06-dna-center-aag-cte-en.html","label":"Cisco DNA Center – Design and Architecture Guide"},{"url":"https://developer.cisco.com/docs/dna-center/","label":"Cisco DevNet – DNA Center Southbound Interfaces"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which southbound protocol does Cisco DNA Center (Catalyst Center) use to communicate with and program managed network devices?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer is analyzing a packet capture and notices that a frame's destination MAC address is FF:FF:FF:FF:FF:FF. Which statement BEST describes the behavior of switches on the local network segment when they receive this frame?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The switch drops the frame because broadcast MAC addresses are not forwarded by managed switches."},{"id":"b","text":"The switch forwards the frame out all ports within the same VLAN except the port on which it was received."},{"id":"c","text":"The switch forwards the frame only to the port associated with the default gateway MAC address."},{"id":"d","text":"The switch sends the frame to the CPU for processing and does not forward it to any other port."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A destination MAC address of FF:FF:FF:FF:FF:FF is the Layer 2 broadcast address. When a switch receives a frame destined for this address, it floods the frame out every port that belongs to the same VLAN as the ingress port, excluding the ingress port itself — this is known as a broadcast flood. Option (a) is incorrect because switches do forward broadcasts within the same VLAN; they only block them at VLAN boundaries or router interfaces. Option (c) is incorrect because the switch does not make forwarding decisions based on the default gateway MAC for broadcast frames — it floods them. Option (d) is incorrect; while the switch CPU may also process certain broadcasts (e.g., for STP or ARP), the frame is still forwarded out all other ports in the VLAN.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-6/configuration_guide/lyr2/b_176_lyr2_9300_cg/overview_of_layer_2_lan_switching.html","label":"Cisco — LAN Switching Overview: Broadcast, Multicast, and Unicast"},{"url":"https://www.ciscopress.com/store/ccna-200-301-official-cert-guide-volume-1-9780135792735","label":"Cisco CCNA 200-301 Official Cert Guide, Volume 1 — Chapter 2: Fundamentals of Ethernet LANs"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer is analyzing a packet capture and notices that a frame's destination MAC address is FF:FF:FF:FF:FF:FF. Which statement BEST describes the behavior of switches on the local network segment when they receive this frame?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following MOST accurately describes the key difference between TCP and UDP at the Transport layer of the OSI model?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"TCP operates at Layer 3 and provides logical addressing, while UDP operates at Layer 4 and provides best-effort delivery."},{"id":"b","text":"TCP provides connection-oriented, reliable delivery with sequencing and acknowledgments, while UDP provides connectionless, best-effort delivery with lower overhead."},{"id":"c","text":"TCP is used exclusively for voice and video streaming because it guarantees low latency, while UDP is used for file transfers because it guarantees delivery."},{"id":"d","text":"TCP and UDP both provide reliable delivery, but TCP uses a two-way handshake while UDP uses a three-way handshake to establish sessions."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$TCP (Transmission Control Protocol) is a connection-oriented protocol that uses a three-way handshake (SYN, SYN-ACK, ACK) to establish sessions, and provides reliability through sequencing, acknowledgments, and retransmission of lost segments. UDP (User Datagram Protocol) is connectionless and provides best-effort delivery without acknowledgments or sequencing, resulting in lower overhead and latency — making it preferable for real-time applications like VoIP, video streaming, and DNS queries. Option (a) is incorrect because both TCP and UDP operate at Layer 4 (Transport layer), not Layer 3. Option (c) reverses the typical use cases: UDP is preferred for voice and video due to its lower latency, while TCP is used for reliable file transfers. Option (d) is incorrect because it attributes reliability to both protocols and incorrectly assigns the handshake types — TCP uses the three-way handshake; UDP has no handshake at all.$patch$, $patch$Network Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/internetworking/technology/handbook/Intro-to-Internet.html","label":"Cisco — Internetworking Technology Handbook: Transport Layer Protocols"},{"url":"https://www.rfc-editor.org/rfc/rfc793","label":"RFC 793 — Transmission Control Protocol (TCP)"},{"url":"https://www.rfc-editor.org/rfc/rfc768","label":"RFC 768 — User Datagram Protocol (UDP)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which of the following MOST accurately describes the key difference between TCP and UDP at the Transport layer of the OSI model?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network administrator is configuring a Cisco Catalyst switch and needs to ensure that only one VLAN's traffic is carried untagged across a trunk link to an IP phone, while multiple other VLANs are carried tagged. Which trunk port configuration element is responsible for carrying untagged traffic on a trunk link?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Allowed VLAN list"},{"id":"b","text":"Native VLAN"},{"id":"c","text":"Voice VLAN"},{"id":"d","text":"Management VLAN"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The native VLAN is the VLAN whose traffic is sent and received untagged on an IEEE 802.1Q trunk link. All other VLANs on the trunk carry 802.1Q tags to identify their membership. The allowed VLAN list controls which VLANs are permitted to traverse the trunk but does not determine tagging behavior. The voice VLAN is a feature used on access ports to separate IP phone traffic using CDP/LLDP negotiation. The management VLAN is an administrative concept used for in-band device management and is not a trunking mechanism.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/vlan/b_179_vlan_9300_cg/configuring_vlan.html","label":"Cisco - Configuring VLANs and Trunking (802.1Q Native VLAN)"},{"url":"https://learningnetwork.cisco.com/s/article/ccna-200-301-exam-topics","label":"Cisco CCNA 200-301 Official Cert Guide - VLAN Trunking"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network administrator is configuring a Cisco Catalyst switch and needs to ensure that only one VLAN's traffic is carried untagged across a trunk link to an IP phone, while multiple other VLANs are carried tagged. Which trunk port configuration element is responsible for carrying untagged traffic on a trunk link?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network engineer observes that a switch port connecting to a user workstation is transitioning through Listening and Learning states before reaching the Forwarding state, causing a 30-second delay during device boot. The port is in a non-redundant segment and will never connect to another switch. Which spanning tree feature should the engineer enable on this port to allow it to transition directly to the Forwarding state immediately?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"PortFast"},{"id":"b","text":"BPDU Guard"},{"id":"c","text":"Root Guard"},{"id":"d","text":"UplinkFast"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$PortFast is a Cisco Spanning Tree Protocol (STP) feature that causes a switch port configured as an access port to bypass the normal STP Listening and Learning states and transition directly to the Forwarding state. It is designed for ports connected to end devices (workstations, printers, servers) that will never participate in the STP topology. BPDU Guard is a complementary feature that disables a PortFast-enabled port if a BPDU is received, but it does not itself speed up the port transition. Root Guard prevents a port from becoming the root port and is used on ports toward downstream switches. UplinkFast is an older feature designed to speed up convergence on uplink ports after an uplink failure, not for end-device ports.$patch$, $patch$Network Access$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst9300/software/release/17-9/configuration_guide/stp/b_179_stp_9300_cg/configuring_optional_spanning_tree_features.html","label":"Cisco - Configuring Optional Spanning-Tree Features (PortFast)"},{"url":"https://learningnetwork.cisco.com/s/article/ccna-200-301-exam-topics","label":"Cisco CCNA 200-301 Exam Topics"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network engineer observes that a switch port connecting to a user workstation is transitioning through Listening and Learning states before reaching the Forwarding state, causing a 30-second delay during device boot. The port is in a non-redundant segment and will never connect to another switch. Which spanning tree feature should the engineer enable on this port to allow it to transition directly to the Forwarding state immediately?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network administrator needs to configure a Cisco router so that internal hosts using private IP addresses can access the Internet through a single public IP address assigned to the router's outside interface. The ISP has provided only one routable IP address. Which NAT configuration type should the administrator implement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Static NAT, mapping each internal private IP to a unique public IP address on a one-to-one basis"},{"id":"b","text":"Dynamic NAT, using a pool of multiple public IP addresses assigned by the ISP"},{"id":"c","text":"PAT (Port Address Translation), also known as NAT overload, mapping multiple internal addresses to a single public IP using unique source port numbers"},{"id":"d","text":"Policy-based NAT, translating addresses only when traffic matches a specific ACL and a crypto map"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$PAT (Port Address Translation), commonly called NAT overload, allows multiple internal hosts using private IP addresses to share a single public IP address by differentiating their sessions using unique source port numbers. This is the correct solution when only one public IP address is available. Static NAT (option a) requires a unique public IP for every internal host, which is impossible with a single address. Dynamic NAT (option b) requires a pool of public addresses, which contradicts the single-address constraint. Policy-based NAT with crypto maps (option d) is associated with VPN tunnel traffic translation, not standard Internet access overloading.$patch$, $patch$IP Services$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/support/docs/ip/network-address-translation-nat/26704-nat-faq-00.html","label":"Cisco - Configuring Network Address Translation: Getting Started"},{"url":"https://www.cisco.com/c/en/us/support/docs/ip/network-address-translation-nat/6209-5.html","label":"Cisco - NAT Order of Operations"},{"url":"https://learningnetwork.cisco.com/s/ccna-exam-topics","label":"Cisco Learning Network - CCNA 200-301 Exam Topics"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network administrator needs to configure a Cisco router so that internal hosts using private IP addresses can access the Internet through a single public IP address assigned to the router's outside interface. The ISP has provided only one routable IP address. Which NAT configuration type should the administrator implement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A network administrator wants to prevent unauthorized devices from connecting to a switch port by allowing only a single specific MAC address and automatically disabling the port if a violation occurs. Which port security configuration achieves this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Set the maximum MAC addresses to 1, statically configure the allowed MAC address, and set the violation mode to shutdown."},{"id":"b","text":"Set the maximum MAC addresses to 1, statically configure the allowed MAC address, and set the violation mode to protect."},{"id":"c","text":"Set the maximum MAC addresses to 1, statically configure the allowed MAC address, and set the violation mode to restrict."},{"id":"d","text":"Enable sticky MAC learning with the maximum MAC addresses set to 1 and the violation mode set to protect."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$The 'shutdown' violation mode is the only mode that automatically places the port into an err-disabled state when an unauthorized MAC address is detected, effectively disabling the port as required. 'Protect' mode silently drops frames from unknown MAC addresses but keeps the port up and does not log the violation. 'Restrict' mode also keeps the port up but drops offending frames and increments the violation counter with a syslog message — neither shuts the port down. Sticky MAC learning (option d) dynamically learns and saves MAC addresses but uses 'protect' mode here, which still does not disable the port on a violation. Therefore, only option A — maximum 1, static MAC, violation shutdown — satisfies the requirement of disabling the port on a violation.$patch$, $patch$Security Fundamentals$patch$,
         3, $json$[{"url":"https://www.cisco.com/c/en/us/td/docs/switches/lan/catalyst_ios/software/release/15-2_7_e/security_configuration_guide/b_152_7e_secsw_cg/b_152_7e_secsw_cg_chapter_01001.html","label":"Cisco IOS Security Configuration Guide: Configuring Port Security"},{"url":"https://www.ciscopress.com/articles/article.asp?p=3089357","label":"Cisco CCNA 200-301 Official Cert Guide — Port Security Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = '200-301-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A network administrator wants to prevent unauthorized devices from connecting to a switch port by allowing only a single specific MAC address and automatically disabling the port if a violation occurs. Which port security configuration achieves this?$patch$);

